'use client';

import dynamic from 'next/dynamic';
import { useEffect, useState, useMemo, useCallback } from 'react';
import { HeartPulse, ShieldCheck, AlertCircle, ChevronDown, ChevronUp, Stethoscope, Search } from 'lucide-react';

// Dynamically import MapComponent to prevent SSR "window is not defined" issues
const MapComponent = dynamic(() => import('@/components/MapComponent'), {
    ssr: false,
    loading: () => (
        <div className="flex items-center justify-center w-full h-full">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-white"></div>
        </div>
    )
});

/* ── Types ──────────────────────────────────────────────────────── */
type Disease = { disease_id: number; disease_name: string; description: string | null };
type DiseaseDetail = { disease_id: number; symptoms: string[]; precautions: string[] };
type Merged = Disease & { details: DiseaseDetail | null };

type SymptomCategory = { category: string; icon: string; items: string[] };
type PrecautionCategory = { category: string; icon: string; items: string[] };

type EnhancedInfo = {
    disease_name: string;
    severity_level: "low" | "moderate" | "high" | "critical";
    brief_summary: string;
    symptom_categories: SymptomCategory[];
    precaution_categories: PrecautionCategory[];
    when_to_seek_help: string;
};

/* ── Fetch Helper ────────────────────────────────────────────────── */
async function enhanceDisease(disease: Merged): Promise<EnhancedInfo | null> {
    try {
        const res = await fetch("/api/groq/enhance-disease", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                disease_name: disease.disease_name,
                symptoms: disease.details?.symptoms ?? [],
                precautions: disease.details?.precautions ?? [],
            }),
        });
        if (!res.ok) return null;
        return await res.json() as EnhancedInfo;
    } catch {
        return null;
    }
}

/* ── Sub-components for Enhanced UI ─────────────────────────────── */

import { Sparkles, Loader2, Hospital, Info, TriangleAlert } from "lucide-react";

type SeverityLevel = "low" | "moderate" | "high" | "critical";
const severityConfig: Record<SeverityLevel, { label: string; text: string; bg: string; border: string }> = {
    low: { label: "Low Risk", text: "#34d399", bg: "rgba(16,185,129,0.15)", border: "rgba(16,185,129,0.3)" },
    moderate: { label: "Moderate Risk", text: "#fbbf24", bg: "rgba(245,158,11,0.15)", border: "rgba(245,158,11,0.3)" },
    high: { label: "High Risk", text: "#f87171", bg: "rgba(239,68,68,0.15)", border: "rgba(239,68,68,0.3)" },
    critical: { label: "Critical", text: "#ef4444", bg: "rgba(220,38,38,0.25)", border: "rgba(220,38,38,0.4)" },
};

function SeverityBadge({ level }: { level: SeverityLevel }) {
    const cfg = severityConfig[level] ?? severityConfig.low;
    return (
        <span
            className="inline-flex items-center gap-1.5 rounded-full border px-2.5 py-0.5 text-[11px] font-bold capitalize shadow-sm"
            style={{ background: cfg.bg, borderColor: cfg.border, color: cfg.text }}
        >
            <span className="h-1.5 w-1.5 rounded-full shrink-0 shadow-sm" style={{ background: cfg.text, boxShadow: `0 0 4px ${cfg.text}` }} />
            {cfg.label}
        </span>
    );
}

function EnhancedDiseasePanel({ enhanced }: { enhanced: EnhancedInfo }) {
    return (
        <div className="space-y-5 animate-fade-in">
            {/* Summary banner */}
            {enhanced.brief_summary && (
                <div className="flex items-start gap-3 rounded-xl border border-white/10 px-4 py-3" style={{ background: 'rgba(255,255,255,0.05)' }}>
                    <Info className="h-4 w-4 shrink-0 mt-0.5 text-blue-300" />
                    <p className="text-sm leading-relaxed text-white/80">
                        {enhanced.brief_summary}
                    </p>
                </div>
            )}

            {/* Symptoms */}
            {enhanced.symptom_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <AlertCircle className="h-4 w-4 text-red-300 shrink-0" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Symptoms</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.symptom_categories.map((cat) => (
                            <div key={cat.category} className="rounded-xl border border-red-400/20 p-3.5" style={{ background: "rgba(239,68,68,0.08)" }}>
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5 text-red-300">
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ul className="space-y-1.5">
                                    {cat.items.map((item) => (
                                        <li key={item} className="flex items-start gap-2 text-xs text-white/80">
                                            <span className="mt-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0 shadow-sm" />
                                            {item}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Divider */}
            {enhanced.symptom_categories.length > 0 && enhanced.precaution_categories.length > 0 && (
                <div className="border-t border-white/10" />
            )}

            {/* Precautions */}
            {enhanced.precaution_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <ShieldCheck className="h-4 w-4 text-emerald-300 shrink-0" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Precautions</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.precaution_categories.map((cat, ci) => (
                            <div key={cat.category} className="rounded-xl border border-emerald-400/20 p-3.5" style={{ background: "rgba(16,185,129,0.08)" }}>
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5 text-emerald-300">
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ol className="space-y-1.5">
                                    {cat.items.map((item, ii) => (
                                        <li key={item} className="flex items-start gap-2 text-xs text-white/80">
                                            <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold text-emerald-200 border border-emerald-400/40 shadow-sm" style={{ background: "rgba(16,185,129,0.25)" }}>
                                                {ii + 1}
                                            </span>
                                            {item}
                                        </li>
                                    ))}
                                </ol>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* When to seek help */}
            {enhanced.when_to_seek_help && (
                <div className="flex items-start gap-3 rounded-xl border border-red-500/30 px-4 py-3.5" style={{ background: "rgba(239,68,68,0.1)" }}>
                    <Hospital className="h-4 w-4 shrink-0 mt-0.5 text-red-400" />
                    <div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-red-300 mb-1">
                            When to seek medical help
                        </p>
                        <p className="text-sm leading-relaxed text-white/80">
                            {enhanced.when_to_seek_help}
                        </p>
                    </div>
                </div>
            )}
        </div>
    );
}

/* ── Fallback Panel ─────────────────────────────────────────────── */

function PlainDiseasePanel({ details }: { details: DiseaseDetail }) {
    return (
        <div className="space-y-4">
            {details.symptoms.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <AlertCircle className="h-3.5 w-3.5 text-red-300" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Symptoms</p>
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                        {details.symptoms.map(s => (
                            <span key={s} className="inline-flex items-center rounded-full border border-red-300/30 px-2.5 py-0.5 text-xs font-medium text-red-200" style={{ background: 'rgba(239,68,68,0.15)' }}>
                                <span className="mr-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0" />
                                {s}
                            </span>
                        ))}
                    </div>
                </div>
            )}
            {details.symptoms.length > 0 && details.precautions.length > 0 && (
                <div className="border-t border-white/10" />
            )}
            {details.precautions.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <ShieldCheck className="h-3.5 w-3.5 text-emerald-300" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Precautions</p>
                    </div>
                    <ol className="space-y-2">
                        {details.precautions.map((p, i) => (
                            <li key={p} className="flex items-start gap-2 text-sm text-white/80">
                                <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-5 w-5 rounded-full text-[10px] font-bold text-emerald-200 border border-emerald-400/40" style={{ background: 'rgba(16,185,129,0.20)' }}>
                                    {i + 1}
                                </span>
                                {p}
                            </li>
                        ))}
                    </ol>
                </div>
            )}
        </div>
    );
}

/* ── Disease card ───────────────────────────────────────────────── */
function DiseaseGuideCard({ disease }: { disease: Merged }) {
    const [enhanced, setEnhanced] = useState<EnhancedInfo | null>(null);
    const [enhancing, setEnhancing] = useState(false);
    const [enhanceFailed, setEnhanceFailed] = useState(false);

    const hasDetails = disease.details && (disease.details.symptoms.length > 0 || disease.details.precautions.length > 0);

    useEffect(() => {
        if (hasDetails && !enhanced && !enhancing && !enhanceFailed) {
            setEnhancing(true);
            enhanceDisease(disease)
                .then((result) => {
                    if (result) setEnhanced(result);
                    else setEnhanceFailed(true);
                })
                .catch(() => setEnhanceFailed(true))
                .finally(() => setEnhancing(false));
        }
    }, [hasDetails, enhanced, enhancing, enhanceFailed, disease]);

    return (
        <div className="rounded-2xl border border-white/20 overflow-hidden backdrop-blur-sm flex flex-col h-[380px]" style={{ background: 'rgba(255,255,255,0.08)' }}>
            {/* Header (Sticky) */}
            <div className="w-full flex items-center justify-between gap-3 px-5 py-4 shrink-0 bg-black/10 border-b border-white/10">
                <div className="flex items-center gap-3 min-w-0">
                    <div className="shrink-0 w-9 h-9 rounded-xl flex items-center justify-center" style={{ background: 'rgba(255,255,255,0.15)' }}>
                        <HeartPulse className="h-4 w-4 text-white" />
                    </div>
                    <div className="min-w-0">
                        <p className="text-sm font-bold text-white truncate">{disease.disease_name}</p>
                        {disease.description && (
                            <p className="text-xs text-white/60 truncate">{disease.description}</p>
                        )}
                    </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                    {enhanced?.severity_level && <SeverityBadge level={enhanced.severity_level} />}
                    {!hasDetails && (
                        <span className="hidden sm:inline text-[10px] font-semibold px-2.5 py-0.5 rounded-full border border-white/20 text-white/50">
                            No details yet
                        </span>
                    )}
                </div>
            </div>

            {/* Scrollable Content */}
            <div className="px-5 pb-5 pt-4 flex-1 overflow-y-auto min-h-0 custom-scrollbar">
                {!hasDetails ? (
                    <div className="flex flex-col items-center justify-center h-full py-6 text-center text-white/50">
                        <Stethoscope className="h-5 w-5 mb-2 opacity-50" />
                        <p className="text-sm">No details added by health officers yet.</p>
                    </div>
                ) : enhancing ? (
                    <div className="flex flex-col items-center justify-center h-full py-8 gap-3">
                        <div className="flex items-center gap-2.5 rounded-xl border border-white/10 px-5 py-3" style={{ background: 'rgba(255,255,255,0.05)' }}>
                            <Loader2 className="h-4 w-4 animate-spin text-white" />
                            <span className="text-sm font-medium text-white/80">Analyzing with AI...</span>
                            <Sparkles className="h-4 w-4 text-violet-400" />
                        </div>
                    </div>
                ) : enhanced ? (
                    <div>
                        <div className="flex items-center gap-1.5 mb-4 text-[10px] font-semibold uppercase tracking-widest text-white/50">
                            <Sparkles className="h-3 w-3 text-violet-400" />
                            AI-organized by Groq (Redis Cached)
                        </div>
                        <EnhancedDiseasePanel enhanced={enhanced} />
                    </div>
                ) : (
                    <div>
                        {enhanceFailed && (
                            <div className="flex items-center gap-2 mb-3 text-xs rounded-lg border border-amber-400/30 px-3 py-2 text-amber-300" style={{ background: "rgba(245,158,11,0.15)" }}>
                                <TriangleAlert className="h-3.5 w-3.5 shrink-0" />
                                AI enhancement unavailable — showing raw data
                            </div>
                        )}
                        <PlainDiseasePanel details={disease.details!} />
                    </div>
                )}
            </div>
        </div>
    );
}

/* ── Main page ──────────────────────────────────────────────────── */
export default function MapPage() {
    const [diseases, setDiseases] = useState<Disease[]>([]);
    const [details, setDetails] = useState<DiseaseDetail[]>([]);
    const [loadingGuide, setLoadingGuide] = useState(true);

    useEffect(() => {
        // Fetch details first (critical — from MongoDB directly)
        // Fetch diseases separately (supplementary — from Python backend)
        Promise.all([
            fetch('/api/public/disease-details')
                .then(r => r.json())
                .then((d: unknown) => Array.isArray(d) ? d as DiseaseDetail[] : [])
                .catch(() => [] as DiseaseDetail[]),
            fetch('/api/public/diseases')
                .then(r => r.json())
                .then((d: unknown) => {
                    if (Array.isArray(d)) return d as Disease[];
                    const obj = d as { diseases?: Disease[] };
                    return obj?.diseases ?? [];
                })
                .catch(() => [] as Disease[]),
        ]).then(([ddList, dList]) => {
            setDetails(ddList);
            setDiseases(dList);
        }).finally(() => setLoadingGuide(false));
    }, []);

    // Build from union of all known IDs — details-driven so they always show
    const merged = useMemo<Merged[]>(() => {
        const detailMap = new Map(details.map(d => [d.disease_id, d]));
        const diseaseMap = new Map(diseases.map(d => [d.disease_id, d]));
        const allIds = new Set([...details.map(d => d.disease_id), ...diseases.map(d => d.disease_id)]);
        return Array.from(allIds).map(id => ({
            disease_id: id,
            disease_name: diseaseMap.get(id)?.disease_name ?? `Disease #${id}`,
            description: diseaseMap.get(id)?.description ?? null,
            details: detailMap.get(id) ?? null,
        })).sort((a, b) => {
            if (a.details && !b.details) return -1;
            if (!a.details && b.details) return 1;
            return a.disease_name.localeCompare(b.disease_name);
        });
    }, [diseases, details]);

    return (
        <main className="min-h-screen flex flex-col relative text-white">
            {/* Fixed background */}
            <div className="fixed inset-0 bg-gradient-to-br from-[#1E3A8A] via-[#1e40af] to-[#0EA5A4] overflow-hidden -z-10">
                <div className="absolute inset-0 opacity-10">
                    <div className="absolute top-10 left-10 w-72 h-72 bg-white rounded-full blur-3xl"></div>
                    <div className="absolute bottom-10 right-10 w-96 h-96 bg-white rounded-full blur-3xl"></div>
                </div>
            </div>

            {/* Page header */}
            <div className="w-full max-w-7xl mx-auto px-4 pt-28 pb-4 relative z-10">
                <h1 className="text-3xl font-bold mb-2 tracking-tight text-white drop-shadow-md">Sri Lanka Disease Risk Map</h1>
                <p className="text-white/80 text-lg font-medium drop-shadow-sm max-w-2xl">
                    View real-time disease risk levels across all districts of Sri Lanka.
                </p>
            </div>

            {/* Map container */}
            <div className="w-full max-w-7xl mx-auto px-4 pb-8 flex-1 relative z-10">
                <div className="w-full rounded-2xl overflow-hidden glass-panel p-0 h-[70vh] min-h-[500px] border border-white/20 shadow-2xl">
                    <MapComponent />
                </div>
            </div>

            {/* ── Disease Prevention Guide ──────────────────── */}
            <div className="w-full max-w-7xl mx-auto px-4 pb-16 relative z-10">
                <div className="rounded-2xl border border-white/20 p-6 sm:p-8" style={{ background: 'rgba(255,255,255,0.06)', backdropFilter: 'blur(20px)' }}>
                    {/* Section header */}
                    <div className="flex flex-wrap items-start justify-between gap-4 mb-6">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{ background: 'rgba(255,255,255,0.15)' }}>
                                <ShieldCheck className="h-5 w-5 text-white" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-white">Disease Prevention Guide</h2>
                                <p className="text-sm text-white/60">Symptoms &amp; precautions — updated by health officers</p>
                            </div>
                        </div>
                    </div>

                    {/* Loading */}
                    {loadingGuide && (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                            {Array.from({ length: 4 }).map((_, i) => (
                                <div key={i} className="h-[380px] rounded-2xl border border-white/15 animate-pulse" style={{ background: 'rgba(255,255,255,0.08)', animationDelay: `${i * 50}ms` }} />
                            ))}
                        </div>
                    )}

                    {/* Disease cards */}
                    {!loadingGuide && merged.length > 0 && (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                            {merged.map(d => <DiseaseGuideCard key={d.disease_id} disease={d} />)}
                        </div>
                    )}

                    {/* Empty state */}
                    {!loadingGuide && merged.length === 0 && (
                        <div className="flex flex-col items-center py-10 text-center text-white/50">
                            <Stethoscope className="h-8 w-8 mb-3 opacity-50" />
                            <p className="text-sm font-medium">No disease information available yet.</p>
                        </div>
                    )}
                </div>
            </div>
        </main>
    );
}

'use client';

import dynamic from 'next/dynamic';
import { useEffect, useState, useMemo } from 'react';
import { HeartPulse, ShieldCheck, AlertCircle, Stethoscope } from 'lucide-react';

// Dynamically import MapComponent to prevent SSR "window is not defined" issues
const MapComponent = dynamic(() => import('@/components/MapComponent'), {
    ssr: false,
    loading: () => (
        <div className="flex items-center justify-center w-full h-full">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-white"></div>
        </div>
    )
});

/* ── Types ──────────────────────────────────────────────────────── */
type Disease = { disease_id: number; disease_name: string; description: string | null };
type DiseaseDetail = { disease_id: number; symptoms: string[]; precautions: string[] };
type Merged = Disease & { details: DiseaseDetail | null };

type SymptomCategory = { category: string; icon: string; items: string[] };
type PrecautionCategory = { category: string; icon: string; items: string[] };

type EnhancedInfo = {
    disease_name: string;
    severity_level: "low" | "moderate" | "high" | "critical";
    brief_summary: string;
    symptom_categories: SymptomCategory[];
    precaution_categories: PrecautionCategory[];
    when_to_seek_help: string;
};

/* ── Fetch Helper ────────────────────────────────────────────────── */
async function enhanceDisease(disease: Merged): Promise<EnhancedInfo | null> {
    try {
        const res = await fetch("/api/groq/enhance-disease", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                disease_name: disease.disease_name,
                symptoms: disease.details?.symptoms ?? [],
                precautions: disease.details?.precautions ?? [],
            }),
        });
        if (!res.ok) return null;
        return await res.json() as EnhancedInfo;
    } catch {
        return null;
    }
}

/* ── Sub-components for Enhanced UI ─────────────────────────────── */

import { Sparkles, Loader2, Hospital, Info, TriangleAlert } from "lucide-react";

type SeverityLevel = "low" | "moderate" | "high" | "critical";
const severityConfig: Record<SeverityLevel, { label: string; text: string; bg: string; border: string }> = {
    low: { label: "Low Risk", text: "#34d399", bg: "rgba(16,185,129,0.15)", border: "rgba(16,185,129,0.3)" },
    moderate: { label: "Moderate Risk", text: "#fbbf24", bg: "rgba(245,158,11,0.15)", border: "rgba(245,158,11,0.3)" },
    high: { label: "High Risk", text: "#f87171", bg: "rgba(239,68,68,0.15)", border: "rgba(239,68,68,0.3)" },
    critical: { label: "Critical", text: "#ef4444", bg: "rgba(220,38,38,0.25)", border: "rgba(220,38,38,0.4)" },
};

function SeverityBadge({ level }: { level: SeverityLevel }) {
    const cfg = severityConfig[level] ?? severityConfig.low;
    return (
        <span
            className="inline-flex items-center gap-1.5 rounded-full border px-2.5 py-0.5 text-[11px] font-bold capitalize shadow-sm"
            style={{ background: cfg.bg, borderColor: cfg.border, color: cfg.text }}
        >
            <span className="h-1.5 w-1.5 rounded-full shrink-0 shadow-sm" style={{ background: cfg.text, boxShadow: `0 0 4px ${cfg.text}` }} />
            {cfg.label}
        </span>
    );
}

function EnhancedDiseasePanel({ enhanced }: { enhanced: EnhancedInfo }) {
    return (
        <div className="space-y-5 animate-fade-in">
            {/* Summary banner */}
            {enhanced.brief_summary && (
                <div className="flex items-start gap-3 rounded-xl border border-white/10 px-4 py-3" style={{ background: 'rgba(255,255,255,0.05)' }}>
                    <Info className="h-4 w-4 shrink-0 mt-0.5 text-blue-300" />
                    <p className="text-sm leading-relaxed text-white/80">
                        {enhanced.brief_summary}
                    </p>
                </div>
            )}

            {/* Symptoms */}
            {enhanced.symptom_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <AlertCircle className="h-4 w-4 text-red-300 shrink-0" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Symptoms</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.symptom_categories.map((cat) => (
                            <div key={cat.category} className="rounded-xl border border-red-400/20 p-3.5" style={{ background: "rgba(239,68,68,0.08)" }}>
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5 text-red-300">
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ul className="space-y-1.5">
                                    {cat.items.map((item) => (
                                        <li key={item} className="flex items-start gap-2 text-xs text-white/80">
                                            <span className="mt-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0 shadow-sm" />
                                            {item}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Divider */}
            {enhanced.symptom_categories.length > 0 && enhanced.precaution_categories.length > 0 && (
                <div className="border-t border-white/10" />
            )}

            {/* Precautions */}
            {enhanced.precaution_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <ShieldCheck className="h-4 w-4 text-emerald-300 shrink-0" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Precautions</p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.precaution_categories.map((cat) => (
                            <div key={cat.category} className="rounded-xl border border-emerald-400/20 p-3.5" style={{ background: "rgba(16,185,129,0.08)" }}>
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5 text-emerald-300">
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ol className="space-y-1.5">
                                    {cat.items.map((item, ii) => (
                                        <li key={item} className="flex items-start gap-2 text-xs text-white/80">
                                            <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold text-emerald-200 border border-emerald-400/40 shadow-sm" style={{ background: "rgba(16,185,129,0.25)" }}>
                                                {ii + 1}
                                            </span>
                                            {item}
                                        </li>
                                    ))}
                                </ol>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* When to seek help */}
            {enhanced.when_to_seek_help && (
                <div className="flex items-start gap-3 rounded-xl border border-red-500/30 px-4 py-3.5" style={{ background: "rgba(239,68,68,0.1)" }}>
                    <Hospital className="h-4 w-4 shrink-0 mt-0.5 text-red-400" />
                    <div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-red-300 mb-1">
                            When to seek medical help
                        </p>
                        <p className="text-sm leading-relaxed text-white/80">
                            {enhanced.when_to_seek_help}
                        </p>
                    </div>
                </div>
            )}
        </div>
    );
}

/* ── Fallback Panel ─────────────────────────────────────────────── */

function PlainDiseasePanel({ details }: { details: DiseaseDetail }) {
    return (
        <div className="space-y-4">
            {details.symptoms.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <AlertCircle className="h-3.5 w-3.5 text-red-300" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Symptoms</p>
                    </div>
                    <div className="flex flex-wrap gap-1.5">
                        {details.symptoms.map(s => (
                            <span key={s} className="inline-flex items-center rounded-full border border-red-300/30 px-2.5 py-0.5 text-xs font-medium text-red-200" style={{ background: 'rgba(239,68,68,0.15)' }}>
                                <span className="mr-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0" />
                                {s}
                            </span>
                        ))}
                    </div>
                </div>
            )}
            {details.symptoms.length > 0 && details.precautions.length > 0 && (
                <div className="border-t border-white/10" />
            )}
            {details.precautions.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <ShieldCheck className="h-3.5 w-3.5 text-emerald-300" />
                        <p className="text-[10px] font-bold uppercase tracking-widest text-white/60">Precautions</p>
                    </div>
                    <ol className="space-y-2">
                        {details.precautions.map((p, i) => (
                            <li key={p} className="flex items-start gap-2 text-sm text-white/80">
                                <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-5 w-5 rounded-full text-[10px] font-bold text-emerald-200 border border-emerald-400/40" style={{ background: 'rgba(16,185,129,0.20)' }}>
                                    {i + 1}
                                </span>
                                {p}
                            </li>
                        ))}
                    </ol>
                </div>
            )}
        </div>
    );
}

/* ── Disease card ───────────────────────────────────────────────── */
function DiseaseGuideCard({ disease }: { disease: Merged }) {
    const [enhanced, setEnhanced] = useState<EnhancedInfo | null>(null);
    const hasDetails = disease.details && (disease.details.symptoms.length > 0 || disease.details.precautions.length > 0);
    const [enhancing, setEnhancing] = useState(Boolean(hasDetails));
    const [enhanceFailed, setEnhanceFailed] = useState(false);

    useEffect(() => {
        if (!hasDetails || !enhancing || enhanced || enhanceFailed) return;

        enhanceDisease(disease)
            .then((result) => {
                if (result) setEnhanced(result);
                else setEnhanceFailed(true);
            })
            .catch(() => setEnhanceFailed(true))
            .finally(() => setEnhancing(false));
    }, [hasDetails, enhancing, enhanced, enhanceFailed, disease]);

    return (
        <div className="rounded-2xl border border-white/20 overflow-hidden backdrop-blur-sm flex flex-col h-[380px]" style={{ background: 'rgba(255,255,255,0.08)' }}>
            {/* Header (Sticky) */}
            <div className="w-full flex items-center justify-between gap-3 px-5 py-4 shrink-0 bg-black/10 border-b border-white/10">
                <div className="flex items-center gap-3 min-w-0">
                    <div className="shrink-0 w-9 h-9 rounded-xl flex items-center justify-center" style={{ background: 'rgba(255,255,255,0.15)' }}>
                        <HeartPulse className="h-4 w-4 text-white" />
                    </div>
                    <div className="min-w-0">
                        <p className="text-sm font-bold text-white truncate">{disease.disease_name}</p>
                        {disease.description && (
                            <p className="text-xs text-white/60 truncate">{disease.description}</p>
                        )}
                    </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                    {enhanced?.severity_level && <SeverityBadge level={enhanced.severity_level} />}
                    {!hasDetails && (
                        <span className="hidden sm:inline text-[10px] font-semibold px-2.5 py-0.5 rounded-full border border-white/20 text-white/50">
                            No details yet
                        </span>
                    )}
                </div>
            </div>

            {/* Scrollable Content */}
            <div className="px-5 pb-5 pt-4 flex-1 overflow-y-auto min-h-0 custom-scrollbar">
                {!hasDetails ? (
                    <div className="flex flex-col items-center justify-center h-full py-6 text-center text-white/50">
                        <Stethoscope className="h-5 w-5 mb-2 opacity-50" />
                        <p className="text-sm">No details added by health officers yet.</p>
                    </div>
                ) : enhancing ? (
                    <div className="flex flex-col items-center justify-center h-full py-8 gap-3">
                        <div className="flex items-center gap-2.5 rounded-xl border border-white/10 px-5 py-3" style={{ background: 'rgba(255,255,255,0.05)' }}>
                            <Loader2 className="h-4 w-4 animate-spin text-white" />
                            <span className="text-sm font-medium text-white/80">Analyzing with AI...</span>
                            <Sparkles className="h-4 w-4 text-violet-400" />
                        </div>
                    </div>
                ) : enhanced ? (
                    <div>
                        <div className="flex items-center gap-1.5 mb-4 text-[10px] font-semibold uppercase tracking-widest text-white/50">
                            <Sparkles className="h-3 w-3 text-violet-400" />
                            AI-organized by Groq (Redis Cached)
                        </div>
                        <EnhancedDiseasePanel enhanced={enhanced} />
                    </div>
                ) : (
                    <div>
                        {enhanceFailed && (
                            <div className="flex items-center gap-2 mb-3 text-xs rounded-lg border border-amber-400/30 px-3 py-2 text-amber-300" style={{ background: "rgba(245,158,11,0.15)" }}>
                                <TriangleAlert className="h-3.5 w-3.5 shrink-0" />
                                AI enhancement unavailable — showing raw data
                            </div>
                        )}
                        <PlainDiseasePanel details={disease.details!} />
                    </div>
                )}
            </div>
        </div>
    );
}

/* ── Main page ──────────────────────────────────────────────────── */
export default function MapPage() {
    const [diseases, setDiseases] = useState<Disease[]>([]);
    const [details, setDetails] = useState<DiseaseDetail[]>([]);
    const [loadingGuide, setLoadingGuide] = useState(true);

    useEffect(() => {
        // Fetch details first (critical — from MongoDB directly)
        // Fetch diseases separately (supplementary — from Python backend)
        Promise.all([
            fetch('/api/public/disease-details')
                .then(r => r.json())
                .then((d: unknown) => Array.isArray(d) ? d as DiseaseDetail[] : [])
                .catch(() => [] as DiseaseDetail[]),
            fetch('/api/public/diseases')
                .then(r => r.json())
                .then((d: unknown) => {
                    if (Array.isArray(d)) return d as Disease[];
                    const obj = d as { diseases?: Disease[] };
                    return obj?.diseases ?? [];
                })
                .catch(() => [] as Disease[]),
        ]).then(([ddList, dList]) => {
            setDetails(ddList);
            setDiseases(dList);
        }).finally(() => setLoadingGuide(false));
    }, []);

    // Build from union of all known IDs — details-driven so they always show
    const merged = useMemo<Merged[]>(() => {
        const detailMap = new Map(details.map(d => [d.disease_id, d]));
        const diseaseMap = new Map(diseases.map(d => [d.disease_id, d]));
        const allIds = new Set([...details.map(d => d.disease_id), ...diseases.map(d => d.disease_id)]);
        return Array.from(allIds).map(id => ({
            disease_id: id,
            disease_name: diseaseMap.get(id)?.disease_name ?? `Disease #${id}`,
            description: diseaseMap.get(id)?.description ?? null,
            details: detailMap.get(id) ?? null,
        })).sort((a, b) => {
            if (a.details && !b.details) return -1;
            if (!a.details && b.details) return 1;
            return a.disease_name.localeCompare(b.disease_name);
        });
    }, [diseases, details]);

    return (
        <main className="min-h-screen flex flex-col relative text-white">
            {/* Fixed background */}
            <div className="fixed inset-0 bg-gradient-to-br from-[#1E3A8A] via-[#1e40af] to-[#0EA5A4] overflow-hidden -z-10">
                <div className="absolute inset-0 opacity-10">
                    <div className="absolute top-10 left-10 w-72 h-72 bg-white rounded-full blur-3xl"></div>
                    <div className="absolute bottom-10 right-10 w-96 h-96 bg-white rounded-full blur-3xl"></div>
                </div>
            </div>

            {/* Page header */}
            <div className="w-full max-w-7xl mx-auto px-4 pt-28 pb-4 relative z-10">
                <h1 className="text-3xl font-bold mb-2 tracking-tight text-white drop-shadow-md">Sri Lanka Disease Risk Map</h1>
                <p className="text-white/80 text-lg font-medium drop-shadow-sm max-w-2xl">
                    View real-time disease risk levels across all districts of Sri Lanka.
                </p>
            </div>

            {/* Map container */}
            <div className="w-full max-w-7xl mx-auto px-4 pb-8 flex-1 relative z-10">
                <div className="w-full rounded-2xl overflow-hidden glass-panel p-0 h-[70vh] min-h-[500px] border border-white/20 shadow-2xl">
                    <MapComponent />
                </div>
            </div>

            {/* ── Disease Prevention Guide ──────────────────── */}
            <div className="w-full max-w-7xl mx-auto px-4 pb-16 relative z-10">
                <div className="rounded-2xl border border-white/20 p-6 sm:p-8" style={{ background: 'rgba(255,255,255,0.06)', backdropFilter: 'blur(20px)' }}>
                    {/* Section header */}
                    <div className="flex flex-wrap items-start justify-between gap-4 mb-6">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{ background: 'rgba(255,255,255,0.15)' }}>
                                <ShieldCheck className="h-5 w-5 text-white" />
                            </div>
                            <div>
                                <h2 className="text-xl font-bold text-white">Disease Prevention Guide</h2>
                                <p className="text-sm text-white/60">Symptoms &amp; precautions — updated by health officers</p>
                            </div>
                        </div>
                    </div>

                    {/* Loading */}
                    {loadingGuide && (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                            {Array.from({ length: 4 }).map((_, i) => (
                                <div key={i} className="h-[380px] rounded-2xl border border-white/15 animate-pulse" style={{ background: 'rgba(255,255,255,0.08)', animationDelay: `${i * 50}ms` }} />
                            ))}
                        </div>
                    )}

                    {/* Disease cards */}
                    {!loadingGuide && merged.length > 0 && (
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                            {merged.map(d => <DiseaseGuideCard key={d.disease_id} disease={d} />)}
                        </div>
                    )}

                    {/* Empty state */}
                    {!loadingGuide && merged.length === 0 && (
                        <div className="flex flex-col items-center py-10 text-center text-white/50">
                            <Stethoscope className="h-8 w-8 mb-3 opacity-50" />
                            <p className="text-sm font-medium">No disease information available yet.</p>
                        </div>
                    )}
                </div>
            </div>
        </main>
    );
}

'use client';

import { useEffect, useState, useRef } from 'react';
import type { Feature, FeatureCollection, Geometry } from 'geojson';
import { format } from 'date-fns';
import {
    CheckCircle2,
    Activity,
    MapPin,
    CalendarDays,
    X,
    Loader2,
    Info,
    Bell,
    AlertCircle
} from 'lucide-react';
import { FaSyncAlt } from "react-icons/fa";
import api from '@/lib/api';
import { DatePicker } from '@/components/ui/datepicker';
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from '@/components/ui/tooltip';

type RiskLevel = 'safe' | 'low' | 'medium' | 'high';

interface DiseaseRisk {
    disease_id: number;
    disease_name: string;
    count: number;
    level: RiskLevel;
}

interface District {
    district_id: number;
    district_name: string;
    latitude: number;
    longitude: number;
    province_name: string;
    overall_risk: RiskLevel;
    week_number: number;
    year: number;
    risk_levels: Record<string, DiseaseRisk>;
}

interface Alert {
    disease_id: number;
    disease_name: string;
    level: RiskLevel;
    count: number;
    district_name: string;
    province_name: string;
    district_id: number;
}

interface MapData {
    districts: District[];
    current_alerts: Alert[];
    total_alerts: number;
    data_period: string;
    week_number: number;
    year: number;
    selected_date: string;
    high_risk_count: number;
    medium_risk_count: number;
    low_risk_count: number;
    safe_count: number;
}

type DistrictFeatureProperties = Record<string, unknown> & {
    shapeName?: string;
    district_name?: string;
    overall_risk?: RiskLevel;
    fill_color?: string;
};

type RawDistrictFeature = Feature<Geometry, Record<string, unknown>>;
type RawDistrictFeatureCollection = FeatureCollection<Geometry, Record<string, unknown>>;
type DistrictFeature = Feature<Geometry, DistrictFeatureProperties>;
type DistrictFeatureCollection = FeatureCollection<Geometry, DistrictFeatureProperties>;

const isDistrictFeatureCollection = (value: unknown): value is RawDistrictFeatureCollection => {
    if (!value || typeof value !== 'object') return false;
    const candidate = value as { type?: unknown; features?: unknown };
    return candidate.type === 'FeatureCollection' && Array.isArray(candidate.features);
};

type TomTomSdk = typeof import('@tomtom-international/web-sdk-maps');
type TomTomMap = import('@tomtom-international/web-sdk-maps').Map;
type MapVariant = 'default' | 'mono';

const getRiskColor = (risk: RiskLevel, variant: MapVariant = 'default') => {
    if (variant === 'mono') {
        switch (risk) {
            case 'high':
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-100 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-100',
                    marker: '#f5f5f5',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-100/10 text-zinc-100 border border-zinc-100/30 font-sans'
                };
            case 'medium':
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-300 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-300',
                    marker: '#d4d4d4',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-300/10 text-zinc-200 border border-zinc-300/30 font-sans'
                };
            case 'low':
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-400 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-400',
                    marker: '#a3a3a3',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-400/10 text-zinc-300 border border-zinc-400/30 font-sans'
                };
            case 'safe':
            default:
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-500 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-500',
                    marker: '#737373',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-500/10 text-zinc-400 border border-zinc-500/30 font-sans'
                };
        }
    }

    switch (risk) {
        case 'high':
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-rose-500 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-rose-400',
                marker: '#DC2626',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-rose-500/20 text-rose-300 border border-rose-500/30 font-sans'
            };
        case 'medium':
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-amber-500 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-amber-400',
                marker: '#F97316',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-amber-500/20 text-amber-300 border border-amber-500/30 font-sans'
            };
        case 'low':
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-blue-400 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-blue-300',
                marker: '#3b82f6',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-blue-500/20 text-blue-300 border border-blue-500/30 font-sans'
            };
        case 'safe':
        default:
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-emerald-500 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-emerald-400',
                marker: '#10B981',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-emerald-500/20 text-emerald-300 border border-emerald-500/30 font-sans'
            };
    }
};

interface MapComponentProps {
    variant?: MapVariant;
}

export default function MapComponent({ variant = 'default' }: MapComponentProps) {
    const mapContainer = useRef<HTMLDivElement>(null);
    const mapPanelRef = useRef<HTMLDivElement>(null);
    const map = useRef<TomTomMap | null>(null);
    const districtGeoJsonRef = useRef<RawDistrictFeatureCollection | null>(null);
    const districtHandlersBoundRef = useRef(false);
    const districtDataRef = useRef<District[]>([]);

    const [mapReady, setMapReady] = useState(false);
    const [mapError, setMapError] = useState<string | null>(null);
    const [dataLoading, setDataLoading] = useState(true);
    const [mapData, setMapData] = useState<MapData | null>(null);
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [tooltipDistrict, setTooltipDistrict] = useState<District | null>(null);
    const [tooltipPoint, setTooltipPoint] = useState<{ x: number; y: number } | null>(null);
    const [tooltipOpen, setTooltipOpen] = useState(false);
    const [tooltipPinned, setTooltipPinned] = useState(false);
    const tooltipPinnedRef = useRef(false);
    const tooltipRafRef = useRef<number | null>(null);
    const pendingTooltipRef = useRef<{ district: District; point: { x: number; y: number } } | null>(null);
    const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
    const [legendOpen, setLegendOpen] = useState(false);

    useEffect(() => {
        tooltipPinnedRef.current = tooltipPinned;
    }, [tooltipPinned]);

    useEffect(() => {
        return () => {
            if (tooltipRafRef.current !== null) {
                cancelAnimationFrame(tooltipRafRef.current);
                tooltipRafRef.current = null;
            }
        };
    }, []);

    const normalizeDistrictName = (name: string) =>
        name.toLowerCase().replace(/\bdistrict\b/g, '').replace(/[^a-z]/g, '');

    const isMono = variant === 'mono';
    const getRiskHexColor = (risk: RiskLevel) => getRiskColor(risk, variant).marker;

    // Initialize map — runs once AFTER the map container div is in the DOM.
    // We always render the map div (just hidden while data loads), so the ref
    // is available immediately on first render.
    useEffect(() => {
        let cancelled = false;

        const initMap = async () => {
            // Wait for the container element to exist in DOM
            if (!mapContainer.current) return;
            // Guard against double init
            if (map.current) return;

            try {
                // Inject TomTom CSS as a <link> tag (avoids TypeScript issues with CSS dynamic imports)
                if (!document.getElementById('tomtom-css')) {
                    const link = document.createElement('link');
                    link.id = 'tomtom-css';
                    link.rel = 'stylesheet';
                    link.href = 'https://api.tomtom.com/maps-sdk-for-web/cdn/6.x/6.25.0/maps/maps.css';
                    document.head.appendChild(link);
                }

                // Dynamically import TomTom SDK (client-side only)
                const tt = await import('@tomtom-international/web-sdk-maps');
                if (cancelled || !mapContainer.current) return;

                const apiKey = process.env.NEXT_PUBLIC_TOMTOM_API_KEY;
                if (!apiKey) {
                    setMapError('Map API key is missing.');
                    return;
                }

                // Initialize with no custom style URL — use TomTom default
                const mapInstance = tt.map({
                    key: apiKey,
                    container: mapContainer.current,
                    center: [80.7718, 7.8731],
                    zoom: 7.2,
                    language: 'en-GB',
                });

                map.current = mapInstance;

                mapInstance.on('load', () => {
                    if (!cancelled) {
                        setMapReady(true);
                    }
                });

                mapInstance.on('error', (errorEvent: unknown) => {
                    console.error('TomTom map error:', errorEvent);
                });

            } catch (error) {
                console.error('Failed to initialize map:', error);
                if (!cancelled) {
                    setMapError('Failed to load the map. Please refresh the page.');
                }
            }
        };

        // Small timeout to ensure DOM is fully painted before initializing
        const timer = setTimeout(initMap, 100);

        return () => {
            cancelled = true;
            clearTimeout(timer);
            if (map.current) {
                try { map.current.remove(); } catch { /* ignore */ }
                map.current = null;
            }
        };
    }, []);

    // Fetch map data
    useEffect(() => {
        const fetchMapData = async () => {
            try {
                setDataLoading(true);
                const response = await api.get('/map/alldistricts', {
                    params: { target_date: format(selectedDate, 'yyyy-MM-dd') },
                });
                setMapData(response.data);
                districtDataRef.current = response.data?.districts ?? [];
                setTooltipDistrict(null);
                setTooltipPoint(null);
                setTooltipOpen(false);
                setTooltipPinned(false);
                setExpandedAlert(null);
            } catch (error) {
                console.error('Failed to fetch map data:', error);
            } finally {
                setDataLoading(false);
            }
        };
        fetchMapData();
    }, [selectedDate]);

    // Add district polygon highlighting by risk level
    useEffect(() => {
        const mapInstance = map.current;
        if (!mapInstance || !mapReady || !mapData) return;

        const sourceId = 'district-risk-source';
        const fillLayerId = 'district-risk-fill';
        const lineLayerId = 'district-risk-line';

        const upsertDistrictPolygons = async () => {
            try {
                if (!districtGeoJsonRef.current) {
                    const response = await fetch('/geo/lka-districts.geojson');
                    if (!response.ok) {
                        throw new Error(`Failed to load district geometry: ${response.status}`);
                    }
                    const geoJsonPayload: unknown = await response.json();
                    if (!isDistrictFeatureCollection(geoJsonPayload)) {
                        throw new Error('Invalid district geometry format.');
                    }
                    districtGeoJsonRef.current = geoJsonPayload;
                }

                const riskByDistrict = new Map<string, District>();
                mapData.districts.forEach((district) => {
                    riskByDistrict.set(normalizeDistrictName(district.district_name), district);
                });
                districtDataRef.current = mapData.districts;

                const rawGeoJson = districtGeoJsonRef.current;

                const enrichedGeoJson: DistrictFeatureCollection = {
                    type: 'FeatureCollection',
                    features: rawGeoJson.features.map((feature): DistrictFeature => {
                        const shapeName = String(feature.properties?.shapeName ?? '');
                        const districtName = shapeName.replace(/\s+District\s*$/i, '').trim();
                        const matchedDistrict = riskByDistrict.get(normalizeDistrictName(districtName));
                        const overallRisk: RiskLevel = matchedDistrict?.overall_risk ?? 'safe';

                        return {
                            type: 'Feature',
                            geometry: feature.geometry,
                            properties: {
                                ...feature.properties,
                                district_name: districtName,
                                overall_risk: overallRisk,
                                fill_color: getRiskHexColor(overallRisk),
                            },
                        };
                    }),
                };

                if (!mapInstance.getSource(sourceId)) {
                    mapInstance.addSource(sourceId, {
                        type: 'geojson',
                        data: enrichedGeoJson,
                    });

                    mapInstance.addLayer({
                        id: fillLayerId,
                        type: 'fill',
                        source: sourceId,
                        paint: {
                            'fill-color': ['coalesce', ['get', 'fill_color'], isMono ? '#737373' : '#10b981'],
                            'fill-opacity': 0.38,
                        },
                    });

                    mapInstance.addLayer({
                        id: lineLayerId,
                        type: 'line',
                        source: sourceId,
                        paint: {
                            'line-color': isMono ? '#ffffff' : '#1E3A8A',
                            'line-width': 1.1,
                            'line-opacity': 0.45,
                        },
                    });
                } else {
                    const existingSource = mapInstance.getSource(sourceId) as {
                        setData: (data: DistrictFeatureCollection) => void;
                    };
                    existingSource.setData(enrichedGeoJson);
                }

                if (!districtHandlersBoundRef.current) {
                    const extractPoint = (event: unknown) => {
                        const mapEvent = event as { point?: { x?: number; y?: number } };
                        return {
                            x: Number(mapEvent.point?.x ?? 0),
                            y: Number(mapEvent.point?.y ?? 0),
                        };
                    };

                    const scheduleTooltipUpdate = (district: District, point: { x: number; y: number }) => {
                        pendingTooltipRef.current = { district, point };
                        if (tooltipRafRef.current !== null) return;

                        tooltipRafRef.current = requestAnimationFrame(() => {
                            tooltipRafRef.current = null;
                            const pending = pendingTooltipRef.current;
                            if (!pending) return;

                            setTooltipDistrict(pending.district);
                            setTooltipPoint(pending.point);
                            setTooltipOpen(true);
                        });
                    };

                    mapInstance.on('click', fillLayerId, (event: unknown) => {
                        const mapEvent = event as {
                            features?: Array<{ properties?: Record<string, unknown> }>;
                        };
                        const feature = mapEvent.features?.[0];
                        const districtName = String(feature?.properties?.district_name ?? '');
                        if (!districtName) return;

                        const match = districtDataRef.current.find(
                            (d) => normalizeDistrictName(d.district_name) === normalizeDistrictName(districtName)
                        );
                        if (match) {
                            scheduleTooltipUpdate(match, extractPoint(event));
                            setTooltipPinned(true);
                        }
                    });

                    mapInstance.on('mouseenter', fillLayerId, (event: unknown) => {
                        const mapEvent = event as {
                            features?: Array<{ properties?: Record<string, unknown> }>;
                        };
                        const feature = mapEvent.features?.[0];
                        const districtName = String(feature?.properties?.district_name ?? '');
                        if (!districtName) return;

                        const match = districtDataRef.current.find(
                            (d) => normalizeDistrictName(d.district_name) === normalizeDistrictName(districtName)
                        );
                        if (match) {
                            scheduleTooltipUpdate(match, extractPoint(event));
                            setTooltipPinned(false);
                        }
                    });

                    mapInstance.on('mousemove', fillLayerId, (event: unknown) => {
                        const mapEvent = event as {
                            features?: Array<{ properties?: Record<string, unknown> }>;
                        };
                        const feature = mapEvent.features?.[0];
                        const districtName = String(feature?.properties?.district_name ?? '');
                        if (!districtName) return;

                        const match = districtDataRef.current.find(
                            (d) => normalizeDistrictName(d.district_name) === normalizeDistrictName(districtName)
                        );
                        if (match) {
                            scheduleTooltipUpdate(match, extractPoint(event));
                        }
                    });

                    mapInstance.on('mouseenter', fillLayerId, () => {
                        mapInstance.getCanvas().style.cursor = 'pointer';
                    });

                    mapInstance.on('mouseleave', fillLayerId, () => {
                        mapInstance.getCanvas().style.cursor = '';
                        if (!tooltipPinnedRef.current) {
                            setTooltipOpen(false);
                            setTooltipDistrict(null);
                            setTooltipPoint(null);
                            pendingTooltipRef.current = null;
                        }
                    });

                    districtHandlersBoundRef.current = true;
                }
            } catch (error) {
                console.error('Failed to render district polygons:', error);
            }
        };

        upsertDistrictPolygons();
    }, [mapReady, mapData, isMono]);

    return (
        <div className={`w-full h-full flex flex-col md:flex-row backdrop-blur-md ${isMono ? 'bg-black/80 text-white' : 'bg-white/5'}`}>

            {/* ─── Left: Map area ─────────────────── */}
            <div ref={mapPanelRef} className="flex-1 relative overflow-hidden" style={{ minHeight: 400 }}>

                {/* The TomTom map mounts into this div via ref.  
                    It MUST always be in the DOM (never conditionally removed).
                    We overlay the loading state on top instead. */}
                <div
                    ref={mapContainer}
                    style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }}
                />

                {/* Loading overlay — sits on top of the map div, doesn't remove it */}
                {(!mapReady || dataLoading) && !mapError && (
                    <div
                        className={`absolute inset-0 z-20 flex items-center justify-center backdrop-blur-md ${isMono ? 'bg-black/60' : 'bg-[#1E3A8A]/30'}`}
                    >
                        <div className={`text-center p-6 rounded-2xl border shadow-xl backdrop-blur-lg ${isMono ? 'bg-black/70 border-white/25' : 'bg-white/10 border-white/20'}`}>
                            <Loader2 className="w-10 h-10 animate-spin mx-auto mb-3 text-white" />
                            <p className="font-medium text-sm text-white drop-shadow-md">
                                {dataLoading ? 'Loading map data...' : 'Initializing map...'}
                            </p>
                        </div>
                    </div>
                )}

                {/* Error overlay */}
                {mapError && (
                    <div className={`absolute inset-0 z-20 flex items-center justify-center backdrop-blur-md ${isMono ? 'bg-black/60' : 'bg-[#1E3A8A]/30'}`}>
                        <div className={`text-center p-8 rounded-2xl border backdrop-blur-lg ${isMono ? 'bg-black/80 border-white/30' : 'bg-rose-500/10 border-rose-500/30'}`}>
                            <AlertCircle className={`w-12 h-12 mx-auto mb-3 ${isMono ? 'text-zinc-200' : 'text-rose-400'}`} />
                            <p className="font-bold mb-1 text-white text-lg">Map Could Not Load</p>
                            <p className="text-sm text-white/80">{mapError}</p>
                        </div>
                    </div>
                )}

                {/* Risk legend — only shown once map is ready */}
                {mapReady && (
                    <div className="absolute top-4 left-4 z-10 flex flex-col items-start gap-2">
                        {!legendOpen ? (
                            <button
                                onClick={() => setLegendOpen(true)}
                                className={`backdrop-blur-xl border shadow-xl p-3 rounded-xl flex items-center justify-center transition-all animate-fade-in text-white group ${isMono ? 'bg-black/70 border-white/25 hover:bg-white/10' : 'bg-blue-900/10 border-white/20 hover:bg-white/25'}`}
                                aria-label="Show map options and details"
                            >
                                <Activity className="w-5 h-5 text-white mr-2 group-hover:scale-110 transition-transform" />
                                <span className="text-sm font-bold tracking-wide">Options & Details</span>
                            </button>
                        ) : (
                            <div className={`backdrop-blur-2xl border shadow-2xl p-5 rounded-2xl animate-fade-in-up text-white ${isMono ? 'bg-black/75 border-white/25' : 'bg-blue-900/10 border-white/20'}`} style={{ maxWidth: 280 }}>
                                <div className="flex items-center justify-between gap-3 mb-4">
                                    <div className="flex items-center gap-2">
                                        <div className={`p-2 rounded-lg border ${isMono ? 'bg-white/5 border-white/25' : 'bg-white/10 border-white/20'}`}>
                                            <Activity className="w-4 h-4 text-white" />
                                        </div>
                                        <div>
                                            <h2 className="font-bold text-sm tracking-wide">Sri Lanka Risk Map</h2>
                                            <p className="text-xs text-white/70 font-medium">{mapData?.data_period}</p>
                                        </div>
                                    </div>
                                    <button
                                        onClick={() => setLegendOpen(false)}
                                        className="text-white/60 hover:text-white hover:bg-white/10 p-1.5 rounded-md transition-colors"
                                    >
                                        <X className="w-4 h-4" />
                                    </button>
                                </div>
                                <div className={`mb-4 rounded-xl border p-3 ${isMono ? 'border-white/25 bg-white/5' : 'border-white/20 bg-white/5'}`}>
                                    <label htmlFor="risk-date" className="block text-xs font-semibold mb-1.5 text-white/90">
                                        Select Date
                                    </label>
                                    <div className="light-theme-forced-if-needed">
                                        <DatePicker date={selectedDate} onDateChange={setSelectedDate} className={`h-8 text-xs w-full text-white placeholder:text-white/50 ${isMono ? 'bg-black/60 border-white/25 hover:bg-white/10' : 'bg-white/10 border-white/30 hover:bg-white/20'}`} />
                                    </div>
                                </div>
                                <div className="grid grid-cols-2 gap-2">
                                    {[
                                        {
                                            count: mapData?.high_risk_count,
                                            label: 'High',
                                            color: isMono ? 'bg-zinc-100' : 'bg-rose-400',
                                            bg: isMono ? 'bg-zinc-100/10 border border-zinc-100/30' : 'bg-rose-500/20 border border-rose-500/30',
                                            text: isMono ? 'text-zinc-100' : 'text-rose-200',
                                        },
                                        {
                                            count: mapData?.medium_risk_count,
                                            label: 'Medium',
                                            color: isMono ? 'bg-zinc-300' : 'bg-amber-400',
                                            bg: isMono ? 'bg-zinc-300/10 border border-zinc-300/30' : 'bg-amber-500/20 border border-amber-500/30',
                                            text: isMono ? 'text-zinc-200' : 'text-amber-200',
                                        },
                                        {
                                            count: mapData?.low_risk_count,
                                            label: 'Low',
                                            color: isMono ? 'bg-zinc-400' : 'bg-blue-400',
                                            bg: isMono ? 'bg-zinc-400/10 border border-zinc-400/30' : 'bg-blue-500/20 border border-blue-500/30',
                                            text: isMono ? 'text-zinc-300' : 'text-blue-200',
                                        },
                                        {
                                            count: mapData?.safe_count,
                                            label: 'Safe',
                                            color: isMono ? 'bg-zinc-500' : 'bg-emerald-400',
                                            bg: isMono ? 'bg-zinc-500/10 border border-zinc-500/30' : 'bg-emerald-500/20 border border-emerald-500/30',
                                            text: isMono ? 'text-zinc-400' : 'text-emerald-200',
                                        },
                                    ].map(({ count, label, color, bg, text }) => (
                                        <div key={label} className={`flex items-center gap-2 p-2.5 rounded-xl ${bg}`}>
                                            <div className={`w-2 h-2 rounded-full ${color} shrink-0 shadow-[0_0_8px_${color}]`}></div>
                                            <div>
                                                <div className={`font-bold text-sm ${text}`}>{count ?? '–'}</div>
                                                <div className={`text-[10px] uppercase tracking-wider ${text} opacity-80 font-semibold`}>{label}</div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {/* District Tooltip */}
                <TooltipProvider delayDuration={0} skipDelayDuration={0}>
                    <Tooltip
                        open={tooltipOpen && Boolean(tooltipDistrict && tooltipPoint)}
                        onOpenChange={(open) => {
                            if (!open) {
                                tooltipPinnedRef.current = false;
                                setTooltipPinned(false);
                                setTooltipOpen(false);
                                setTooltipDistrict(null);
                                setTooltipPoint(null);
                                pendingTooltipRef.current = null;
                            }
                        }}
                    >
                        <TooltipTrigger asChild>
                            <div
                                className="absolute z-30 h-0 w-0"
                                style={{
                                    left: tooltipPoint?.x ?? 0,
                                    top: tooltipPoint?.y ?? 0,
                                    transform: 'translate(-50%, -50%)',
                                    pointerEvents: 'none',
                                }}
                            />
                        </TooltipTrigger>
                        <TooltipContent
                            container={mapPanelRef.current ?? undefined}
                            side="top"
                            sideOffset={10}
                            className="z-40 w-[min(calc(100vw-1.5rem),14rem)] rounded-md border border-white/30 bg-black px-2.5 py-2 text-white shadow-lg"
                        >
                            {tooltipDistrict && (() => {
                                const activeDiseases = Object.values(tooltipDistrict.risk_levels || {})
                                    .filter(d => d.count > 0)
                                    .sort((a, b) => b.count - a.count);

                                return (
                                    <div className="space-y-1">
                                        <div className="flex items-start justify-between gap-2">
                                            <p className="truncate text-xs font-bold tracking-wide">{tooltipDistrict.district_name}</p>
                                            {tooltipPinned && (
                                                <button
                                                    onClick={() => {
                                                        tooltipPinnedRef.current = false;
                                                        setTooltipPinned(false);
                                                        setTooltipOpen(false);
                                                        setTooltipDistrict(null);
                                                        setTooltipPoint(null);
                                                        pendingTooltipRef.current = null;
                                                    }}
                                                    className="rounded p-0.5 text-white/70 hover:text-white hover:bg-white/20 transition-colors"
                                                    aria-label="Close district tooltip"
                                                >
                                                    <X className="h-3.5 w-3.5" />
                                                </button>
                                            )}
                                        </div>
                                        <div className="flex justify-between items-center">
                                            <p className="text-[11px] text-white/80 font-medium tracking-wide">Overall Risk:</p>
                                            <p className={`text-[10px] font-bold uppercase ${getRiskColor(tooltipDistrict.overall_risk, variant).text}`}>
                                                {tooltipDistrict.overall_risk}
                                            </p>
                                        </div>
                                        <p className="text-[10px] text-white/60 mb-1 font-medium">As of Week {tooltipDistrict.week_number}, {tooltipDistrict.year}</p>

                                        {activeDiseases.length > 0 && (
                                            <div className="pt-1.5 mt-1.5 border-t border-white/20 space-y-0.5">
                                                <p className="text-[9px] text-white/50 uppercase font-bold tracking-wider mb-1">Active Conditions</p>
                                                {activeDiseases.map(d => {
                                                    const dColor = getRiskColor(d.level, variant);
                                                    return (
                                                        <div key={d.disease_id} className="flex justify-between items-center py-px">
                                                            <span className="text-[11px] text-white/90">{d.disease_name}</span>
                                                            <span className={`text-[9px] font-bold uppercase ${dColor.text}`}>{d.level}</span>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}
                                    </div>
                                );
                            })()}
                        </TooltipContent>
                    </Tooltip>
                </TooltipProvider>
            </div>

            {/* ─── Right: Alerts Sidebar ─────────── */}
            <div className={`w-full md:w-80 lg:w-96 flex flex-col border-t md:border-t-0 md:border-l backdrop-blur-xl ${isMono ? 'border-white/25 bg-black/70' : 'border-white/20 bg-white/5'}`} style={{ maxHeight: '100%' }}>
                {/* Header */}
                <div className={`p-4 border-b shrink-0 flex items-center gap-3 ${isMono ? 'border-white/25 bg-black/60' : 'border-white/20 bg-white/5'}`}>
                    <div className={`flex shrink-0 w-9 h-9 items-center justify-center rounded-xl ${isMono ? 'bg-zinc-800 shadow-lg shadow-black/40' : 'bg-blue-500 shadow-lg shadow-purple-500/30'}`}>
                        <Bell className="w-4 h-4 text-white" />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-sm font-bold text-white tracking-wide">Active Alerts</h3>
                        <p className="text-xs text-white/70 font-medium mt-0.5">
                            {mapData?.current_alerts.length || 0} alert{(mapData?.current_alerts.length || 0) !== 1 ? 's' : ''} across the nation
                        </p>
                    </div>
                </div>

                {/* Alerts List */}
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                    {dataLoading ? (
                        <div className="flex items-center justify-center h-32">
                            <Loader2 className="w-6 h-6 animate-spin text-white" />
                        </div>
                    ) : mapData?.current_alerts && mapData.current_alerts.length > 0 ? (
                        <div className="space-y-3">
                            {mapData.current_alerts.map((alert, idx) => {
                                const rc = getRiskColor(alert.level, variant);
                                const isExpanded = expandedAlert === idx;

                                // Find other diseases in the same district
                                const districtData = mapData.districts.find(d => d.district_id === alert.district_id);
                                const otherDiseases = Object.values(districtData?.risk_levels || {})
                                    .filter(d => d.disease_id !== alert.disease_id && d.count > 0)
                                    .sort((a, b) => b.count - a.count);

                                return (
                                    <div key={idx} className={`${rc.cardName} p-0 overflow-hidden shadow-lg`}>
                                        <button
                                            onClick={() => setExpandedAlert(isExpanded ? null : idx)}
                                            className="w-full text-left p-3.5 focus:outline-none"
                                        >
                                            <div className="flex items-start justify-between gap-2">
                                                <div className="flex-1 min-w-0">
                                                    <div className="flex items-center gap-2 mb-2 flex-wrap">
                                                        <span className={rc.badgeClass}>
                                                            {alert.level.toUpperCase()}
                                                        </span>
                                                        <p className="font-bold text-sm text-white truncate drop-shadow-sm">
                                                            {alert.disease_name}
                                                        </p>
                                                    </div>
                                                    <p className={`text-xs ${rc.text} truncate font-semibold`}>
                                                        {alert.district_name}, {alert.province_name}
                                                    </p>
                                                    <p className="text-xs mt-1 text-white/60 font-medium">
                                                        {alert.count} case{alert.count !== 1 ? 's' : ''} reported
                                                    </p>
                                                </div>
                                                <Info className={`w-4 h-4 shrink-0 mt-0.5 ${rc.text}`} />
                                            </div>
                                            {isExpanded && (
                                                <div className="mt-3 pt-3 space-y-2 text-xs text-left border-t border-white/10">
                                                    <p className="text-white/80">
                                                        <span className="font-bold text-white">Location: </span>
                                                        {alert.district_name}, {alert.province_name}
                                                    </p>
                                                    <p className="text-white/80 pb-1">
                                                        <span className="font-bold text-white">Risk Profile: </span>
                                                        {alert.level === 'high'
                                                            ? 'Critical — immediate action required'
                                                            : alert.level === 'medium'
                                                                ? 'Significant outbreak — close monitoring needed'
                                                                : 'Watch for further developments'}
                                                    </p>

                                                    {otherDiseases.length > 0 && (
                                                        <div className="pt-2 border-t border-white/10">
                                                            <p className="font-bold text-white mb-2 tracking-wide">Other Active Conditions</p>
                                                            <div className="space-y-1.5">
                                                                {otherDiseases.map(od => {
                                                                    const odColor = getRiskColor(od.level, variant);
                                                                    return (
                                                                        <div key={od.disease_id} className={`flex items-center justify-between px-2 py-1.5 rounded-lg ${isMono ? 'bg-white/10 border border-white/10' : 'bg-white/5 border border-white/5'}`}>
                                                                            <span className="text-white/90 font-medium">
                                                                                {od.disease_name} <span className="text-white/50">({od.count})</span>
                                                                            </span>
                                                                            <span className={`text-[10px] font-bold tracking-wider ${odColor.text}`}>
                                                                                {od.level.toUpperCase()}
                                                                            </span>
                                                                        </div>
                                                                    );
                                                                })}
                                                            </div>
                                                        </div>
                                                    )}
                                                </div>
                                            )}
                                        </button>
                                    </div>
                                );
                            })}
                        </div>
                    ) : (
                        <div className="text-center flex flex-col items-center justify-center h-full">
                            <div className={`w-12 h-12 rounded-2xl border flex items-center justify-center mb-3 shadow-xl backdrop-blur-md ${isMono ? 'border-white/30 bg-white/10' : 'border-white/20 bg-white/10'}`}>
                                <CheckCircle2 className={`h-6 w-6 ${isMono ? 'text-zinc-200' : 'text-emerald-400'}`} />
                            </div>
                            <p className="font-bold text-sm text-white drop-shadow-sm">No Active Alerts</p>
                            <p className="text-xs mt-1 text-white/70 font-medium">All districts currently safe</p>
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className={`border-t p-3 flex items-center justify-between shrink-0 backdrop-blur-md ${isMono ? 'border-white/25 bg-black/60' : 'border-white/20 bg-white/5'}`}>
                    <span className="text-[11px] font-medium text-white/60">Real-time surveillance active</span>
                    <button
                        onClick={() => window.location.reload()}
                        className={`text-white font-semibold text-xs py-1.5 px-4 rounded-xl transition-all shadow-md ${isMono ? 'bg-white/10 hover:bg-white/20 border border-white/25' : 'bg-white/15 hover:bg-white/25 border border-white/30'}`}
                    >
                        <FaSyncAlt size={20} />
                    </button>
                </div>
            </div>

        </div>
    );
}

'use client';

import { useEffect, useState, useRef, useCallback } from 'react';
import type { Feature, FeatureCollection, Geometry } from 'geojson';
import { format } from 'date-fns';
import {
    CheckCircle2,
    Activity,
    X,
    Loader2,
    Info,
    Bell,
    AlertCircle
} from 'lucide-react';
import { FaSyncAlt } from "react-icons/fa";
import api from '@/lib/api';
import { DatePicker } from '@/components/ui/datepicker';
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from '@/components/ui/tooltip';

type RiskLevel = 'safe' | 'low' | 'medium' | 'high';

interface DiseaseRisk {
    disease_id: number;
    disease_name: string;
    count: number;
    level: RiskLevel;
}

interface District {
    district_id: number;
    district_name: string;
    latitude: number;
    longitude: number;
    province_name: string;
    overall_risk: RiskLevel;
    week_number: number;
    year: number;
    risk_levels: Record<string, DiseaseRisk>;
}

interface Alert {
    disease_id: number;
    disease_name: string;
    level: RiskLevel;
    count: number;
    district_name: string;
    province_name: string;
    district_id: number;
}

interface MapData {
    districts: District[];
    current_alerts: Alert[];
    total_alerts: number;
    data_period: string;
    week_number: number;
    year: number;
    selected_date: string;
    high_risk_count: number;
    medium_risk_count: number;
    low_risk_count: number;
    safe_count: number;
}

type DistrictFeatureProperties = Record<string, unknown> & {
    shapeName?: string;
    district_name?: string;
    overall_risk?: RiskLevel;
    fill_color?: string;
};

type RawDistrictFeatureCollection = FeatureCollection<Geometry, Record<string, unknown>>;
type DistrictFeature = Feature<Geometry, DistrictFeatureProperties>;
type DistrictFeatureCollection = FeatureCollection<Geometry, DistrictFeatureProperties>;

const isDistrictFeatureCollection = (value: unknown): value is RawDistrictFeatureCollection => {
    if (!value || typeof value !== 'object') return false;
    const candidate = value as { type?: unknown; features?: unknown };
    return candidate.type === 'FeatureCollection' && Array.isArray(candidate.features);
};

type TomTomMap = import('@tomtom-international/web-sdk-maps').Map;
type MapVariant = 'default' | 'mono';

const getRiskColor = (risk: RiskLevel, variant: MapVariant = 'default') => {
    if (variant === 'mono') {
        switch (risk) {
            case 'high':
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-100 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-100',
                    marker: '#f5f5f5',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-100/10 text-zinc-100 border border-zinc-100/30 font-sans'
                };
            case 'medium':
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-300 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-300',
                    marker: '#d4d4d4',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-300/10 text-zinc-200 border border-zinc-300/30 font-sans'
                };
            case 'low':
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-400 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-400',
                    marker: '#a3a3a3',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-400/10 text-zinc-300 border border-zinc-400/30 font-sans'
                };
            case 'safe':
            default:
                return {
                    cardName: 'bg-white/6 rounded-xl border-l-[4px] border-l-zinc-500 border-y border-r border-white/15 hover:bg-white/10 transition-colors',
                    text: 'text-zinc-500',
                    marker: '#737373',
                    badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-zinc-500/10 text-zinc-400 border border-zinc-500/30 font-sans'
                };
        }
    }

    switch (risk) {
        case 'high':
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-rose-500 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-rose-400',
                marker: '#DC2626',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-rose-500/20 text-rose-300 border border-rose-500/30 font-sans'
            };
        case 'medium':
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-amber-500 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-amber-400',
                marker: '#F97316',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-amber-500/20 text-amber-300 border border-amber-500/30 font-sans'
            };
        case 'low':
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-blue-400 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-blue-300',
                marker: '#3b82f6',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-blue-500/20 text-blue-300 border border-blue-500/30 font-sans'
            };
        case 'safe':
        default:
            return {
                cardName: 'bg-white/10 rounded-xl border-l-[4px] border-l-emerald-500 border-y border-r border-white/10 hover:bg-white/20 transition-colors',
                text: 'text-emerald-400',
                marker: '#10B981',
                badgeClass: 'px-2 py-0.5 rounded-md text-[10px] font-bold tracking-wider bg-emerald-500/20 text-emerald-300 border border-emerald-500/30 font-sans'
            };
    }
};

interface MapComponentProps {
    variant?: MapVariant;
}

export default function MapComponent({ variant = 'default' }: MapComponentProps) {
    const mapContainer = useRef<HTMLDivElement>(null);
    const mapPanelRef = useRef<HTMLDivElement>(null);
    const map = useRef<TomTomMap | null>(null);
    const districtGeoJsonRef = useRef<RawDistrictFeatureCollection | null>(null);
    const districtHandlersBoundRef = useRef(false);
    const districtDataRef = useRef<District[]>([]);

    const [mapReady, setMapReady] = useState(false);
    const [mapError, setMapError] = useState<string | null>(null);
    const [dataLoading, setDataLoading] = useState(true);
    const [mapData, setMapData] = useState<MapData | null>(null);
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [tooltipDistrict, setTooltipDistrict] = useState<District | null>(null);
    const [tooltipPoint, setTooltipPoint] = useState<{ x: number; y: number } | null>(null);
    const [tooltipOpen, setTooltipOpen] = useState(false);
    const [tooltipPinned, setTooltipPinned] = useState(false);
    const tooltipPinnedRef = useRef(false);
    const tooltipRafRef = useRef<number | null>(null);
    const pendingTooltipRef = useRef<{ district: District; point: { x: number; y: number } } | null>(null);
    const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
    const [legendOpen, setLegendOpen] = useState(false);

    useEffect(() => {
        tooltipPinnedRef.current = tooltipPinned;
    }, [tooltipPinned]);

    useEffect(() => {
        return () => {
            if (tooltipRafRef.current !== null) {
                cancelAnimationFrame(tooltipRafRef.current);
                tooltipRafRef.current = null;
            }
        };
    }, []);

    const normalizeDistrictName = (name: string) =>
        name.toLowerCase().replace(/\bdistrict\b/g, '').replace(/[^a-z]/g, '');

    const isMono = variant === 'mono';
    const getRiskHexColor = useCallback((risk: RiskLevel) => getRiskColor(risk, variant).marker, [variant]);

    // Initialize map — runs once AFTER the map container div is in the DOM.
    // We always render the map div (just hidden while data loads), so the ref
    // is available immediately on first render.
    useEffect(() => {
        let cancelled = false;

        const initMap = async () => {
            // Wait for the container element to exist in DOM
            if (!mapContainer.current) return;
            // Guard against double init
            if (map.current) return;

            try {
                // Inject TomTom CSS as a <link> tag (avoids TypeScript issues with CSS dynamic imports)
                if (!document.getElementById('tomtom-css')) {
                    const link = document.createElement('link');
                    link.id = 'tomtom-css';
                    link.rel = 'stylesheet';
                    link.href = 'https://api.tomtom.com/maps-sdk-for-web/cdn/6.x/6.25.0/maps/maps.css';
                    document.head.appendChild(link);
                }

                // Dynamically import TomTom SDK (client-side only)
                const tt = await import('@tomtom-international/web-sdk-maps');
                if (cancelled || !mapContainer.current) return;

                const apiKey = process.env.NEXT_PUBLIC_TOMTOM_API_KEY;
                if (!apiKey) {
                    setMapError('Map API key is missing.');
                    return;
                }

                // Initialize with no custom style URL — use TomTom default
                const mapInstance = tt.map({
                    key: apiKey,
                    container: mapContainer.current,
                    center: [80.7718, 7.8731],
                    zoom: 7.2,
                    language: 'en-GB',
                });

                map.current = mapInstance;

                mapInstance.on('load', () => {
                    if (!cancelled) {
                        setMapReady(true);
                    }
                });

                mapInstance.on('error', (errorEvent: unknown) => {
                    console.error('TomTom map error:', errorEvent);
                });

            } catch (error) {
                console.error('Failed to initialize map:', error);
                if (!cancelled) {
                    setMapError('Failed to load the map. Please refresh the page.');
                }
            }
        };

        // Small timeout to ensure DOM is fully painted before initializing
        const timer = setTimeout(initMap, 100);

        return () => {
            cancelled = true;
            clearTimeout(timer);
            if (map.current) {
                try { map.current.remove(); } catch { /* ignore */ }
                map.current = null;
            }
        };
    }, []);

    // Fetch map data
    useEffect(() => {
        const fetchMapData = async () => {
            try {
                setDataLoading(true);
                const response = await api.get('/map/alldistricts', {
                    params: { target_date: format(selectedDate, 'yyyy-MM-dd') },
                });
                setMapData(response.data);
                districtDataRef.current = response.data?.districts ?? [];
                setTooltipDistrict(null);
                setTooltipPoint(null);
                setTooltipOpen(false);
                setTooltipPinned(false);
                setExpandedAlert(null);
            } catch (error) {
                console.error('Failed to fetch map data:', error);
            } finally {
                setDataLoading(false);
            }
        };
        fetchMapData();
    }, [selectedDate]);

    // Add district polygon highlighting by risk level
    useEffect(() => {
        const mapInstance = map.current;
        if (!mapInstance || !mapReady || !mapData) return;

        const sourceId = 'district-risk-source';
        const fillLayerId = 'district-risk-fill';
        const lineLayerId = 'district-risk-line';

        const upsertDistrictPolygons = async () => {
            try {
                if (!districtGeoJsonRef.current) {
                    const response = await fetch('/geo/lka-districts.geojson');
                    if (!response.ok) {
                        throw new Error(`Failed to load district geometry: ${response.status}`);
                    }
                    const geoJsonPayload: unknown = await response.json();
                    if (!isDistrictFeatureCollection(geoJsonPayload)) {
                        throw new Error('Invalid district geometry format.');
                    }
                    districtGeoJsonRef.current = geoJsonPayload;
                }

                const riskByDistrict = new Map<string, District>();
                mapData.districts.forEach((district) => {
                    riskByDistrict.set(normalizeDistrictName(district.district_name), district);
                });
                districtDataRef.current = mapData.districts;

                const rawGeoJson = districtGeoJsonRef.current;

                const enrichedGeoJson: DistrictFeatureCollection = {
                    type: 'FeatureCollection',
                    features: rawGeoJson.features.map((feature): DistrictFeature => {
                        const shapeName = String(feature.properties?.shapeName ?? '');
                        const districtName = shapeName.replace(/\s+District\s*$/i, '').trim();
                        const matchedDistrict = riskByDistrict.get(normalizeDistrictName(districtName));
                        const overallRisk: RiskLevel = matchedDistrict?.overall_risk ?? 'safe';

                        return {
                            type: 'Feature',
                            geometry: feature.geometry,
                            properties: {
                                ...feature.properties,
                                district_name: districtName,
                                overall_risk: overallRisk,
                                fill_color: getRiskHexColor(overallRisk),
                            },
                        };
                    }),
                };

                if (!mapInstance.getSource(sourceId)) {
                    mapInstance.addSource(sourceId, {
                        type: 'geojson',
                        data: enrichedGeoJson,
                    });

                    mapInstance.addLayer({
                        id: fillLayerId,
                        type: 'fill',
                        source: sourceId,
                        paint: {
                            'fill-color': ['coalesce', ['get', 'fill_color'], isMono ? '#737373' : '#10b981'],
                            'fill-opacity': 0.38,
                        },
                    });

                    mapInstance.addLayer({
                        id: lineLayerId,
                        type: 'line',
                        source: sourceId,
                        paint: {
                            'line-color': isMono ? '#ffffff' : '#1E3A8A',
                            'line-width': 1.1,
                            'line-opacity': 0.45,
                        },
                    });
                } else {
                    const existingSource = mapInstance.getSource(sourceId) as {
                        setData: (data: DistrictFeatureCollection) => void;
                    };
                    existingSource.setData(enrichedGeoJson);
                }

                if (!districtHandlersBoundRef.current) {
                    const extractPoint = (event: unknown) => {
                        const mapEvent = event as { point?: { x?: number; y?: number } };
                        return {
                            x: Number(mapEvent.point?.x ?? 0),
                            y: Number(mapEvent.point?.y ?? 0),
                        };
                    };

                    const scheduleTooltipUpdate = (district: District, point: { x: number; y: number }) => {
                        pendingTooltipRef.current = { district, point };
                        if (tooltipRafRef.current !== null) return;

                        tooltipRafRef.current = requestAnimationFrame(() => {
                            tooltipRafRef.current = null;
                            const pending = pendingTooltipRef.current;
                            if (!pending) return;

                            setTooltipDistrict(pending.district);
                            setTooltipPoint(pending.point);
                            setTooltipOpen(true);
                        });
                    };

                    mapInstance.on('click', fillLayerId, (event: unknown) => {
                        const mapEvent = event as {
                            features?: Array<{ properties?: Record<string, unknown> }>;
                        };
                        const feature = mapEvent.features?.[0];
                        const districtName = String(feature?.properties?.district_name ?? '');
                        if (!districtName) return;

                        const match = districtDataRef.current.find(
                            (d) => normalizeDistrictName(d.district_name) === normalizeDistrictName(districtName)
                        );
                        if (match) {
                            scheduleTooltipUpdate(match, extractPoint(event));
                            setTooltipPinned(true);
                        }
                    });

                    mapInstance.on('mouseenter', fillLayerId, (event: unknown) => {
                        const mapEvent = event as {
                            features?: Array<{ properties?: Record<string, unknown> }>;
                        };
                        const feature = mapEvent.features?.[0];
                        const districtName = String(feature?.properties?.district_name ?? '');
                        if (!districtName) return;

                        const match = districtDataRef.current.find(
                            (d) => normalizeDistrictName(d.district_name) === normalizeDistrictName(districtName)
                        );
                        if (match) {
                            scheduleTooltipUpdate(match, extractPoint(event));
                            setTooltipPinned(false);
                        }
                    });

                    mapInstance.on('mousemove', fillLayerId, (event: unknown) => {
                        const mapEvent = event as {
                            features?: Array<{ properties?: Record<string, unknown> }>;
                        };
                        const feature = mapEvent.features?.[0];
                        const districtName = String(feature?.properties?.district_name ?? '');
                        if (!districtName) return;

                        const match = districtDataRef.current.find(
                            (d) => normalizeDistrictName(d.district_name) === normalizeDistrictName(districtName)
                        );
                        if (match) {
                            scheduleTooltipUpdate(match, extractPoint(event));
                        }
                    });

                    mapInstance.on('mouseenter', fillLayerId, () => {
                        mapInstance.getCanvas().style.cursor = 'pointer';
                    });

                    mapInstance.on('mouseleave', fillLayerId, () => {
                        mapInstance.getCanvas().style.cursor = '';
                        if (!tooltipPinnedRef.current) {
                            setTooltipOpen(false);
                            setTooltipDistrict(null);
                            setTooltipPoint(null);
                            pendingTooltipRef.current = null;
                        }
                    });

                    districtHandlersBoundRef.current = true;
                }
            } catch (error) {
                console.error('Failed to render district polygons:', error);
            }
        };

        upsertDistrictPolygons();
    }, [mapReady, mapData, isMono, getRiskHexColor]);

    return (
        <div className={`w-full h-full flex flex-col md:flex-row backdrop-blur-md ${isMono ? 'bg-black/80 text-white' : 'bg-white/5'}`}>

            {/* ─── Left: Map area ─────────────────── */}
            <div ref={mapPanelRef} className="flex-1 relative overflow-hidden" style={{ minHeight: 400 }}>

                {/* The TomTom map mounts into this div via ref.  
                    It MUST always be in the DOM (never conditionally removed).
                    We overlay the loading state on top instead. */}
                <div
                    ref={mapContainer}
                    style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }}
                />

                {/* Loading overlay — sits on top of the map div, doesn't remove it */}
                {(!mapReady || dataLoading) && !mapError && (
                    <div
                        className={`absolute inset-0 z-20 flex items-center justify-center backdrop-blur-md ${isMono ? 'bg-black/60' : 'bg-[#1E3A8A]/30'}`}
                    >
                        <div className={`text-center p-6 rounded-2xl border shadow-xl backdrop-blur-lg ${isMono ? 'bg-black/70 border-white/25' : 'bg-white/10 border-white/20'}`}>
                            <Loader2 className="w-10 h-10 animate-spin mx-auto mb-3 text-white" />
                            <p className="font-medium text-sm text-white drop-shadow-md">
                                {dataLoading ? 'Loading map data...' : 'Initializing map...'}
                            </p>
                        </div>
                    </div>
                )}

                {/* Error overlay */}
                {mapError && (
                    <div className={`absolute inset-0 z-20 flex items-center justify-center backdrop-blur-md ${isMono ? 'bg-black/60' : 'bg-[#1E3A8A]/30'}`}>
                        <div className={`text-center p-8 rounded-2xl border backdrop-blur-lg ${isMono ? 'bg-black/80 border-white/30' : 'bg-rose-500/10 border-rose-500/30'}`}>
                            <AlertCircle className={`w-12 h-12 mx-auto mb-3 ${isMono ? 'text-zinc-200' : 'text-rose-400'}`} />
                            <p className="font-bold mb-1 text-white text-lg">Map Could Not Load</p>
                            <p className="text-sm text-white/80">{mapError}</p>
                        </div>
                    </div>
                )}

                {/* Risk legend — only shown once map is ready */}
                {mapReady && (
                    <div className="absolute top-4 left-4 z-10 flex flex-col items-start gap-2">
                        {!legendOpen ? (
                            <button
                                onClick={() => setLegendOpen(true)}
                                className={`backdrop-blur-xl border shadow-xl p-3 rounded-xl flex items-center justify-center transition-all animate-fade-in text-white group ${isMono ? 'bg-black/70 border-white/25 hover:bg-white/10' : 'bg-blue-900/10 border-white/20 hover:bg-white/25'}`}
                                aria-label="Show map options and details"
                            >
                                <Activity className="w-5 h-5 text-white mr-2 group-hover:scale-110 transition-transform" />
                                <span className="text-sm font-bold tracking-wide">Options & Details</span>
                            </button>
                        ) : (
                            <div className={`backdrop-blur-2xl border shadow-2xl p-5 rounded-2xl animate-fade-in-up text-white ${isMono ? 'bg-black/75 border-white/25' : 'bg-blue-900/10 border-white/20'}`} style={{ maxWidth: 280 }}>
                                <div className="flex items-center justify-between gap-3 mb-4">
                                    <div className="flex items-center gap-2">
                                        <div className={`p-2 rounded-lg border ${isMono ? 'bg-white/5 border-white/25' : 'bg-white/10 border-white/20'}`}>
                                            <Activity className="w-4 h-4 text-white" />
                                        </div>
                                        <div>
                                            <h2 className="font-bold text-sm tracking-wide">Sri Lanka Risk Map</h2>
                                            <p className="text-xs text-white/70 font-medium">{mapData?.data_period}</p>
                                        </div>
                                    </div>
                                    <button
                                        onClick={() => setLegendOpen(false)}
                                        className="text-white/60 hover:text-white hover:bg-white/10 p-1.5 rounded-md transition-colors"
                                    >
                                        <X className="w-4 h-4" />
                                    </button>
                                </div>
                                <div className={`mb-4 rounded-xl border p-3 ${isMono ? 'border-white/25 bg-white/5' : 'border-white/20 bg-white/5'}`}>
                                    <label htmlFor="risk-date" className="block text-xs font-semibold mb-1.5 text-white/90">
                                        Select Date
                                    </label>
                                    <div className="light-theme-forced-if-needed">
                                        <DatePicker date={selectedDate} onDateChange={setSelectedDate} className={`h-8 text-xs w-full text-white placeholder:text-white/50 ${isMono ? 'bg-black/60 border-white/25 hover:bg-white/10' : 'bg-white/10 border-white/30 hover:bg-white/20'}`} />
                                    </div>
                                </div>
                                <div className="grid grid-cols-2 gap-2">
                                    {[
                                        {
                                            count: mapData?.high_risk_count,
                                            label: 'High',
                                            color: isMono ? 'bg-zinc-100' : 'bg-rose-400',
                                            bg: isMono ? 'bg-zinc-100/10 border border-zinc-100/30' : 'bg-rose-500/20 border border-rose-500/30',
                                            text: isMono ? 'text-zinc-100' : 'text-rose-200',
                                        },
                                        {
                                            count: mapData?.medium_risk_count,
                                            label: 'Medium',
                                            color: isMono ? 'bg-zinc-300' : 'bg-amber-400',
                                            bg: isMono ? 'bg-zinc-300/10 border border-zinc-300/30' : 'bg-amber-500/20 border border-amber-500/30',
                                            text: isMono ? 'text-zinc-200' : 'text-amber-200',
                                        },
                                        {
                                            count: mapData?.low_risk_count,
                                            label: 'Low',
                                            color: isMono ? 'bg-zinc-400' : 'bg-blue-400',
                                            bg: isMono ? 'bg-zinc-400/10 border border-zinc-400/30' : 'bg-blue-500/20 border border-blue-500/30',
                                            text: isMono ? 'text-zinc-300' : 'text-blue-200',
                                        },
                                        {
                                            count: mapData?.safe_count,
                                            label: 'Safe',
                                            color: isMono ? 'bg-zinc-500' : 'bg-emerald-400',
                                            bg: isMono ? 'bg-zinc-500/10 border border-zinc-500/30' : 'bg-emerald-500/20 border border-emerald-500/30',
                                            text: isMono ? 'text-zinc-400' : 'text-emerald-200',
                                        },
                                    ].map(({ count, label, color, bg, text }) => (
                                        <div key={label} className={`flex items-center gap-2 p-2.5 rounded-xl ${bg}`}>
                                            <div className={`w-2 h-2 rounded-full ${color} shrink-0 shadow-[0_0_8px_${color}]`}></div>
                                            <div>
                                                <div className={`font-bold text-sm ${text}`}>{count ?? '–'}</div>
                                                <div className={`text-[10px] uppercase tracking-wider ${text} opacity-80 font-semibold`}>{label}</div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {/* District Tooltip */}
                <TooltipProvider delayDuration={0} skipDelayDuration={0}>
                    <Tooltip
                        open={tooltipOpen && Boolean(tooltipDistrict && tooltipPoint)}
                        onOpenChange={(open) => {
                            if (!open) {
                                tooltipPinnedRef.current = false;
                                setTooltipPinned(false);
                                setTooltipOpen(false);
                                setTooltipDistrict(null);
                                setTooltipPoint(null);
                                pendingTooltipRef.current = null;
                            }
                        }}
                    >
                        <TooltipTrigger asChild>
                            <div
                                className="absolute z-30 h-0 w-0"
                                style={{
                                    left: tooltipPoint?.x ?? 0,
                                    top: tooltipPoint?.y ?? 0,
                                    transform: 'translate(-50%, -50%)',
                                    pointerEvents: 'none',
                                }}
                            />
                        </TooltipTrigger>
                        <TooltipContent
                            container={mapPanelRef.current ?? undefined}
                            side="top"
                            sideOffset={10}
                            className="z-40 w-[min(calc(100vw-1.5rem),14rem)] rounded-md border border-white/30 bg-black px-2.5 py-2 text-white shadow-lg"
                        >
                            {tooltipDistrict && (() => {
                                const activeDiseases = Object.values(tooltipDistrict.risk_levels || {})
                                    .filter(d => d.count > 0)
                                    .sort((a, b) => b.count - a.count);
                                
                                return (
                                    <div className="space-y-1">
                                        <div className="flex items-start justify-between gap-2">
                                            <p className="truncate text-xs font-bold tracking-wide">{tooltipDistrict.district_name}</p>
                                            {tooltipPinned && (
                                                <button
                                                    onClick={() => {
                                                        tooltipPinnedRef.current = false;
                                                        setTooltipPinned(false);
                                                        setTooltipOpen(false);
                                                        setTooltipDistrict(null);
                                                        setTooltipPoint(null);
                                                        pendingTooltipRef.current = null;
                                                    }}
                                                    className="rounded p-0.5 text-white/70 hover:text-white hover:bg-white/20 transition-colors"
                                                    aria-label="Close district tooltip"
                                                >
                                                    <X className="h-3.5 w-3.5" />
                                                </button>
                                            )}
                                        </div>
                                        <div className="flex justify-between items-center">
                                            <p className="text-[11px] text-white/80 font-medium tracking-wide">Overall Risk:</p>
                                            <p className={`text-[10px] font-bold uppercase ${getRiskColor(tooltipDistrict.overall_risk, variant).text}`}>
                                                {tooltipDistrict.overall_risk}
                                            </p>
                                        </div>
                                        <p className="text-[10px] text-white/60 mb-1 font-medium">As of Week {tooltipDistrict.week_number}, {tooltipDistrict.year}</p>

                                        {activeDiseases.length > 0 && (
                                            <div className="pt-1.5 mt-1.5 border-t border-white/20 space-y-0.5">
                                                <p className="text-[9px] text-white/50 uppercase font-bold tracking-wider mb-1">Active Conditions</p>
                                                {activeDiseases.map(d => {
                                                    const dColor = getRiskColor(d.level, variant);
                                                    return (
                                                        <div key={d.disease_id} className="flex justify-between items-center py-px">
                                                            <span className="text-[11px] text-white/90">{d.disease_name}</span>
                                                            <span className={`text-[9px] font-bold uppercase ${dColor.text}`}>{d.level}</span>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}
                                    </div>
                                );
                            })()}
                        </TooltipContent>
                    </Tooltip>
                </TooltipProvider>
            </div>

            {/* ─── Right: Alerts Sidebar ─────────── */}
            <div className={`w-full md:w-80 lg:w-96 flex flex-col border-t md:border-t-0 md:border-l backdrop-blur-xl ${isMono ? 'border-white/25 bg-black/70' : 'border-white/20 bg-white/5'}`} style={{ maxHeight: '100%' }}>
                {/* Header */}
                <div className={`p-4 border-b shrink-0 flex items-center gap-3 ${isMono ? 'border-white/25 bg-black/60' : 'border-white/20 bg-white/5'}`}>
                    <div className={`flex shrink-0 w-9 h-9 items-center justify-center rounded-xl ${isMono ? 'bg-zinc-800 shadow-lg shadow-black/40' : 'bg-blue-500 shadow-lg shadow-purple-500/30'}`}>
                        <Bell className="w-4 h-4 text-white" />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-sm font-bold text-white tracking-wide">Active Alerts</h3>
                        <p className="text-xs text-white/70 font-medium mt-0.5">
                            {mapData?.current_alerts.length || 0} alert{(mapData?.current_alerts.length || 0) !== 1 ? 's' : ''} across the nation
                        </p>
                    </div>
                </div>

                {/* Alerts List */}
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                    {dataLoading ? (
                        <div className="flex items-center justify-center h-32">
                            <Loader2 className="w-6 h-6 animate-spin text-white" />
                        </div>
                    ) : mapData?.current_alerts && mapData.current_alerts.length > 0 ? (
                        <div className="space-y-3">
                            {mapData.current_alerts.map((alert, idx) => {
                                const rc = getRiskColor(alert.level, variant);
                                const isExpanded = expandedAlert === idx;
                                
                                // Find other diseases in the same district
                                const districtData = mapData.districts.find(d => d.district_id === alert.district_id);
                                const otherDiseases = Object.values(districtData?.risk_levels || {})
                                    .filter(d => d.disease_id !== alert.disease_id && d.count > 0)
                                    .sort((a, b) => b.count - a.count);

                                return (
                                    <div key={idx} className={`${rc.cardName} p-0 overflow-hidden shadow-lg`}>
                                        <button
                                            onClick={() => setExpandedAlert(isExpanded ? null : idx)}
                                            className="w-full text-left p-3.5 focus:outline-none"
                                        >
                                            <div className="flex items-start justify-between gap-2">
                                                <div className="flex-1 min-w-0">
                                                    <div className="flex items-center gap-2 mb-2 flex-wrap">
                                                        <span className={rc.badgeClass}>
                                                            {alert.level.toUpperCase()}
                                                        </span>
                                                        <p className="font-bold text-sm text-white truncate drop-shadow-sm">
                                                            {alert.disease_name}
                                                        </p>
                                                    </div>
                                                    <p className={`text-xs ${rc.text} truncate font-semibold`}>
                                                        {alert.district_name}, {alert.province_name}
                                                    </p>
                                                    <p className="text-xs mt-1 text-white/60 font-medium">
                                                        {alert.count} case{alert.count !== 1 ? 's' : ''} reported
                                                    </p>
                                                </div>
                                                <Info className={`w-4 h-4 shrink-0 mt-0.5 ${rc.text}`} />
                                            </div>
                                            {isExpanded && (
                                                <div className="mt-3 pt-3 space-y-2 text-xs text-left border-t border-white/10">
                                                    <p className="text-white/80">
                                                        <span className="font-bold text-white">Location: </span>
                                                        {alert.district_name}, {alert.province_name}
                                                    </p>
                                                    <p className="text-white/80 pb-1">
                                                        <span className="font-bold text-white">Risk Profile: </span>
                                                        {alert.level === 'high'
                                                            ? 'Critical — immediate action required'
                                                            : alert.level === 'medium'
                                                                ? 'Significant outbreak — close monitoring needed'
                                                                : 'Watch for further developments'}
                                                    </p>
                                                    
                                                    {otherDiseases.length > 0 && (
                                                        <div className="pt-2 border-t border-white/10">
                                                            <p className="font-bold text-white mb-2 tracking-wide">Other Active Conditions</p>
                                                            <div className="space-y-1.5">
                                                                {otherDiseases.map(od => {
                                                                    const odColor = getRiskColor(od.level, variant);
                                                                    return (
                                                                        <div key={od.disease_id} className={`flex items-center justify-between px-2 py-1.5 rounded-lg ${isMono ? 'bg-white/10 border border-white/10' : 'bg-white/5 border border-white/5'}`}>
                                                                            <span className="text-white/90 font-medium">
                                                                                {od.disease_name} <span className="text-white/50">({od.count})</span>
                                                                            </span>
                                                                            <span className={`text-[10px] font-bold tracking-wider ${odColor.text}`}>
                                                                                {od.level.toUpperCase()}
                                                                            </span>
                                                                        </div>
                                                                    );
                                                                })}
                                                            </div>
                                                        </div>
                                                    )}
                                                </div>
                                            )}
                                        </button>
                                    </div>
                                );
                            })}
                        </div>
                    ) : (
                        <div className="text-center flex flex-col items-center justify-center h-full">
                            <div className={`w-12 h-12 rounded-2xl border flex items-center justify-center mb-3 shadow-xl backdrop-blur-md ${isMono ? 'border-white/30 bg-white/10' : 'border-white/20 bg-white/10'}`}>
                                <CheckCircle2 className={`h-6 w-6 ${isMono ? 'text-zinc-200' : 'text-emerald-400'}`} />
                            </div>
                            <p className="font-bold text-sm text-white drop-shadow-sm">No Active Alerts</p>
                            <p className="text-xs mt-1 text-white/70 font-medium">All districts currently safe</p>
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className={`border-t p-3 flex items-center justify-between shrink-0 backdrop-blur-md ${isMono ? 'border-white/25 bg-black/60' : 'border-white/20 bg-white/5'}`}>
                    <span className="text-[11px] font-medium text-white/60">Real-time surveillance active</span>
                    <button
                        onClick={() => window.location.reload()}
                        className={`text-white font-semibold text-xs py-1.5 px-4 rounded-xl transition-all shadow-md ${isMono ? 'bg-white/10 hover:bg-white/20 border border-white/25' : 'bg-white/15 hover:bg-white/25 border border-white/30'}`}
                    >
                        <FaSyncAlt size={20} />
                    </button>
                </div>
            </div>

        </div>
    );
}

'use client';

import { useEffect, useMemo, useRef, useState, useCallback } from "react";
import * as tt from "@tomtom-international/web-sdk-maps";
import "@tomtom-international/web-sdk-maps/dist/maps.css";
import { useLocation } from "@/contexts/LocationContext";
import { Loader2, AlertTriangle, CheckCircle2, Navigation, Activity, ChevronDown, ChevronUp, ShieldCheck, HeartPulse, Sparkles, Hospital, Info, TriangleAlert } from "lucide-react";

type DiseaseDetail = {
    disease_id: number;
    symptoms: string[];
    precautions: string[];
};

type RiskLevel = "safe" | "low" | "medium" | "high";

type SymptomCategory = { category: string; icon: string; items: string[] };
type PrecautionCategory = { category: string; icon: string; items: string[] };

type EnhancedInfo = {
    disease_name: string;
    severity_level: "low" | "moderate" | "high" | "critical";
    brief_summary: string;
    symptom_categories: SymptomCategory[];
    precaution_categories: PrecautionCategory[];
    when_to_seek_help: string;
};

async function enhanceDisease(name: string, details: DiseaseDetail): Promise<EnhancedInfo | null> {
    try {
        const res = await fetch("/api/groq/enhance-disease", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                disease_name: name,
                symptoms: details?.symptoms ?? [],
                precautions: details?.precautions ?? [],
            }),
        });
        if (!res.ok) return null;
        return await res.json() as EnhancedInfo;
    } catch {
        return null;
    }
}

interface DiseaseRisk {
    disease_id: number;
    disease_name: string;
    count: number;
    level: RiskLevel;
}

type SeverityConfig = {
    color: string;
    bg: string;
    border: string;
    textColor: string;
    stripColor: string;
};

const getSeverityConfig = (severity: RiskLevel): SeverityConfig => {
    switch (severity) {
        case "high":
            return { color: "#e11d48", bg: "rgba(225,29,72,0.09)", border: "rgba(225,29,72,0.28)", textColor: "#be123c", stripColor: "#f43f5e" };
        case "medium":
            return { color: "#d97706", bg: "rgba(217,119,6,0.09)", border: "rgba(217,119,6,0.28)", textColor: "#b45309", stripColor: "#f59e0b" };
        case "low":
            return { color: "#2563eb", bg: "rgba(37,99,235,0.09)", border: "rgba(37,99,235,0.22)", textColor: "var(--color-primary)", stripColor: "#3b82f6" };
        case "safe":
            return { color: "#059669", bg: "rgba(5,150,105,0.09)", border: "rgba(5,150,105,0.25)", textColor: "#047857", stripColor: "#10b981" };
        default:
            return { color: "#64748b", bg: "var(--dash-card-header-bg)", border: "var(--dash-card-border)", textColor: "var(--dash-text-secondary)", stripColor: "var(--dash-card-border)" };
    }
};

const getMaxRiskLevel = (riskLevels: Record<string, DiseaseRisk>): RiskLevel => {
    const priority: Record<RiskLevel, number> = { safe: 0, low: 1, medium: 2, high: 3 };
    return Object.values(riskLevels).reduce<RiskLevel>(
        (max, d) => (priority[d.level] > priority[max] ? d.level : max),
        "safe"
    );
};

/* ── Pathogen Row Component ─────────────────────────────────────────────── */

function ActivePathogenRow({ risk, detail, isExpanded, onToggle }: { risk: DiseaseRisk, detail?: DiseaseDetail, isExpanded: boolean, onToggle: () => void }) {
    const c = getSeverityConfig(risk.level);
    const hasDetail = detail && (detail.symptoms.length > 0 || detail.precautions.length > 0);

    const [enhanced, setEnhanced] = useState<EnhancedInfo | null>(null);
    const [enhancing, setEnhancing] = useState(false);
    const [enhanceFailed, setEnhanceFailed] = useState(false);

    useEffect(() => {
        if (isExpanded && hasDetail && !enhanced && !enhancing && !enhanceFailed) {
            setEnhancing(true);
            enhanceDisease(risk.disease_name, detail).then((res) => {
                if (res) setEnhanced(res);
                else setEnhanceFailed(true);
            }).catch(() => setEnhanceFailed(true))
              .finally(() => setEnhancing(false));
        }
    }, [isExpanded, hasDetail, enhanced, enhancing, enhanceFailed, risk.disease_name, detail]);

    return (
        <div>
            <button
                type="button"
                onClick={onToggle}
                className="relative w-full flex items-center justify-between p-2.5 rounded-lg border overflow-hidden transition-all duration-200 text-left"
                style={{ background: c.bg, borderColor: c.border }}
            >
                <div className="absolute left-0 top-0 bottom-0 w-1 rounded-l-lg" style={{ background: c.stripColor }} />
                <div className="pl-2.5 flex flex-col min-w-0 pr-2">
                    <span className="text-sm font-semibold truncate" style={{ color: c.textColor }}>{risk.disease_name}</span>
                    <span className="text-[10px] mt-0.5" style={{ color: c.textColor, opacity: 0.8 }}>
                        {risk.count} projected {risk.count === 1 ? 'case' : 'cases'}
                    </span>
                </div>
                <div className="flex items-center gap-1.5 shrink-0">
                    <span className="text-[10px] font-bold uppercase rounded-full px-2.5 py-0.5 border" style={{ color: c.textColor, background: "rgba(255,255,255,0.35)", borderColor: c.border }}>
                        {risk.level}
                    </span>
                    {hasDetail && (
                        isExpanded ? <ChevronUp className="h-3.5 w-3.5" style={{ color: c.textColor }} /> : <ChevronDown className="h-3.5 w-3.5" style={{ color: c.textColor }} />
                    )}
                </div>
            </button>

            {/* Expandable Panel */}
            {isExpanded && hasDetail && (
                <div className="mt-1 rounded-lg border px-3 py-3 space-y-3" style={{ background: "var(--dash-card-bg)", borderColor: "var(--dash-card-border)" }}>
                    {enhancing ? (
                        <div className="flex flex-col items-center py-4 gap-2 text-center" style={{ color: "var(--dash-text-secondary)" }}>
                            <Loader2 className="h-4 w-4 animate-spin mb-1" style={{ color: "var(--color-primary)" }} />
                            <span className="text-xs font-medium">Analyzing with AI...</span>
                        </div>
                    ) : enhanced ? (
                        <div className="space-y-4">
                            <div className="flex items-center gap-1.5 text-[9px] font-semibold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                                <Sparkles className="h-3 w-3 text-violet-500" />
                                AI-organized by Groq
                            </div>

                            {enhanced.brief_summary && (
                                <p className="text-xs leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>{enhanced.brief_summary}</p>
                            )}

                            {enhanced.symptom_categories.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                        <HeartPulse className="h-3 w-3 text-red-500 shrink-0" />
                                        <p className="text-[9px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Symptoms</p>
                                    </div>
                                    <div className="space-y-2">
                                        {enhanced.symptom_categories.map((cat) => (
                                            <div key={cat.category}>
                                                <p className="text-[11px] font-bold mb-1 flex items-center gap-1" style={{ color: "#dc2626" }}>
                                                    <span>{cat.icon}</span> {cat.category}
                                                </p>
                                                <div className="flex flex-wrap gap-1">
                                                    {cat.items.map((item) => (
                                                        <span key={item} className="inline-flex items-center rounded-full border px-2 py-0.5 text-[10px] font-medium" style={{ background: "rgba(239,68,68,0.08)", borderColor: "rgba(239,68,68,0.20)", color: "#dc2626" }}>
                                                            {item}
                                                        </span>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {enhanced.precaution_categories.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5 border-t pt-2" style={{ borderColor: "var(--dash-card-border)" }}>
                                        <ShieldCheck className="h-3 w-3 text-emerald-500 shrink-0" />
                                        <p className="text-[9px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Precautions</p>
                                    </div>
                                    <div className="space-y-2">
                                        {enhanced.precaution_categories.map((cat) => (
                                            <div key={cat.category}>
                                                <p className="text-[11px] font-bold mb-1 flex items-center gap-1" style={{ color: "#059669" }}>
                                                    <span>{cat.icon}</span> {cat.category}
                                                </p>
                                                <ol className="space-y-1">
                                                    {cat.items.map((item, ii) => (
                                                        <li key={item} className="flex items-start gap-1.5 text-[11px]" style={{ color: "var(--dash-text-secondary)" }}>
                                                            <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold" style={{ background: "rgba(16,185,129,0.12)", color: "#059669", border: "1px solid rgba(16,185,129,0.25)" }}>
                                                                {ii + 1}
                                                            </span>
                                                            {item}
                                                        </li>
                                                    ))}
                                                </ol>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {enhanced.when_to_seek_help && (
                                <div className="mt-3 rounded-lg border p-2 flex items-start gap-2" style={{ background: "rgba(239,68,68,0.05)", borderColor: "rgba(239,68,68,0.15)" }}>
                                    <Hospital className="h-3.5 w-3.5 mt-0.5 text-red-500 shrink-0" />
                                    <p className="text-[10px] leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>
                                        <span className="font-bold text-red-500 block mb-0.5">When to seek help</span>
                                        {enhanced.when_to_seek_help}
                                    </p>
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {enhanceFailed && (
                                <div className="flex items-center gap-2 text-[10px] rounded p-2" style={{ background: "rgba(245,158,11,0.1)", color: "#d97706" }}>
                                    <TriangleAlert className="h-3 w-3 shrink-0" />
                                    AI enhancement unavailable — showing raw data
                                </div>
                            )}
                            {detail?.symptoms.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                        <HeartPulse className="h-3 w-3 text-red-500" />
                                        <p className="text-[10px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Symptoms</p>
                                    </div>
                                    <div className="flex flex-wrap gap-1">
                                        {detail.symptoms.map((s) => (
                                            <span key={s} className="inline-flex items-center rounded-full border px-2 py-0.5 text-[10px] font-medium" style={{ background: "rgba(239,68,68,0.08)", borderColor: "rgba(239,68,68,0.20)", color: "#dc2626" }}>
                                                {s}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {detail?.precautions.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                        <ShieldCheck className="h-3 w-3 text-emerald-500" />
                                        <p className="text-[10px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Precautions</p>
                                    </div>
                                    <ol className="space-y-1">
                                        {detail.precautions.map((p, i) => (
                                            <li key={p} className="flex items-start gap-1.5 text-[11px]" style={{ color: "var(--dash-text-secondary)" }}>
                                                <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold" style={{ background: "rgba(16,185,129,0.12)", color: "#059669", border: "1px solid rgba(16,185,129,0.25)" }}>
                                                    {i + 1}
                                                </span>
                                                {p}
                                            </li>
                                        ))}
                                    </ol>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

export default function MapComponent() {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapRef = useRef<tt.Map | null>(null);
    const nearbyMarkerRef = useRef<tt.Marker | null>(null);
    const userMarkerRef = useRef<tt.Marker | null>(null);

    const { locationData, isLoading: contextLoading, error: contextError } = useLocation();
    const [mapReady, setMapReady] = useState(false);
    const [diseaseDetails, setDiseaseDetails] = useState<DiseaseDetail[]>([]);
    const [expandedDiseaseId, setExpandedDiseaseId] = useState<number | null>(null);

    // Fetch disease details from MongoDB via public Next.js route
    useEffect(() => {
        fetch("/api/public/disease-details", { cache: "no-store" })
            .then((r) => r.json())
            .then((data: unknown) => {
                if (Array.isArray(data)) setDiseaseDetails(data as DiseaseDetail[]);
            })
            .catch(() => { /* non-critical */ });
    }, []);

    const isLoading = contextLoading || !mapReady;

    const area = locationData?.nearest_area;
    const riskList = useMemo(() => {
        if (!area) return [];
        return Object.values(area.risk_levels).sort((a, b) => {
            const p: Record<RiskLevel, number> = { high: 3, medium: 2, low: 1, safe: 0 };
            return p[b.level] - p[a.level];
        });
    }, [area]);

    const overallRisk = useMemo(() => {
        if (!area) return "safe" as RiskLevel;
        return getMaxRiskLevel(area.risk_levels);
    }, [area]);

    const circleGeoJson = (center: [number, number], radiusMeters: number) => {
        const points = 64;
        const coords: number[][] = [];
        const [lng, lat] = center;
        const radiusKm = radiusMeters / 1000;
        const latRad = (lat * Math.PI) / 180;
        for (let i = 0; i < points; i++) {
            const angle = (i / points) * 2 * Math.PI;
            const dLat = (radiusKm / 111) * Math.cos(angle);
            const dLng = (radiusKm / (111 * Math.cos(latRad))) * Math.sin(angle);
            coords.push([lng + dLng, lat + dLat]);
        }
        coords.push(coords[0]);
        return {
            type: "Feature" as const,
            geometry: { type: "Polygon" as const, coordinates: [coords] },
            properties: {},
        };
    };

    const upsertCircle = useCallback((map: tt.Map, center: [number, number], radiusMeters: number, color: string) => {
        const sourceId = "radius-source";
        const fillId = "radius-layer";
        const outlineId = "radius-layer-outline";
        const data = {
            type: "FeatureCollection" as const,
            features: [circleGeoJson(center, radiusMeters)],
        };
        if (!map.getSource(sourceId)) {
            map.addSource(sourceId, { type: "geojson", data });
            map.addLayer({ id: fillId, type: "fill", source: sourceId, paint: { "fill-color": color, "fill-opacity": 0.15 } });
            map.addLayer({ id: outlineId, type: "line", source: sourceId, paint: { "line-color": color, "line-width": 2, "line-opacity": 0.8 } });
        } else {
            const src = map.getSource(sourceId) as tt.GeoJSONSource;
            src.setData(data);
            map.setPaintProperty(fillId, "fill-color", color);
            map.setPaintProperty(outlineId, "line-color", color);
        }
    }, []);

    useEffect(() => {
        if (!mapElement.current) return;
        if (mapRef.current) return;
        const map = tt.map({
            key: process.env.NEXT_PUBLIC_TOMTOM_API_KEY!,
            container: mapElement.current,
            center: [80.7718, 7.8731],
            zoom: 7.5,
            language: "en-GB",
        });
        mapRef.current = map;
        map.on("load", () => setMapReady(true));
        return () => {
            userMarkerRef.current?.remove();
            nearbyMarkerRef.current?.remove();
            map.remove();
            mapRef.current = null;
        };
    }, []);

    useEffect(() => {
        const map = mapRef.current;
        if (!map || !mapReady || !locationData) return;
        const { latitude, longitude } = locationData.user_location;
        const userCoords: [number, number] = [longitude, latitude];

        userMarkerRef.current?.remove();
        nearbyMarkerRef.current?.remove();

        const userPopupHtml = `
            <div style="font-family: inherit; margin: -4px;">
                <div style="font-weight:700; font-size: 13px; margin-bottom: 2px; color: #1e293b;">Your Location</div>
                <div style="font-size:11px; color: #64748b;">${latitude.toFixed(4)}, ${longitude.toFixed(4)}</div>
            </div>`;

        userMarkerRef.current = new tt.Marker({ color: "#2563eb" })
            .setLngLat(userCoords)
            .setPopup(new tt.Popup({ offset: 26, className: "custom-map-popup" }).setHTML(userPopupHtml))
            .addTo(map);

        if (locationData.nearest_area) {
            const a = locationData.nearest_area;
            const areaCoords: [number, number] = [a.longitude, a.latitude];
            const maxRisk = getMaxRiskLevel(a.risk_levels);
            const markerColor = getSeverityConfig(maxRisk).color;
            const riskListHtml = Object.values(a.risk_levels).map(r => `<div style="font-size:11px; margin-bottom:2px;">• ${r.disease_name}: <b>${r.level}</b></div>`).join('');
            const areaPopupHtml = `
                <div style="font-family: inherit; margin: -4px; width: 160px;">
                    <div style="font-weight:700; font-size: 14px; margin-bottom: 2px; color: #0f172a;">${a.district_name}</div>
                    <div style="font-size:11px; color: #64748b; margin-bottom: 8px;">${a.province_name} · ${a.distance.toFixed(1)} km</div>
                    <div style="border-top: 1px solid #e2e8f0; padding-top: 6px;">
                        ${riskListHtml}
                    </div>
                </div>`;

            nearbyMarkerRef.current = new tt.Marker({ color: markerColor })
                .setLngLat(areaCoords)
                .setPopup(new tt.Popup({ offset: 26, className: "custom-map-popup" }).setHTML(areaPopupHtml))
                .addTo(map);

            upsertCircle(map, areaCoords, 5000, markerColor);

            const bounds = new tt.LngLatBounds();
            bounds.extend(userCoords);
            bounds.extend(areaCoords);
            setTimeout(() => {
                if (mapRef.current) mapRef.current.fitBounds(bounds, { padding: 80, maxZoom: 12 });
            }, 100);
        } else {
            map.setCenter(userCoords);
            map.setZoom(12);
        }
    }, [locationData, mapReady, upsertCircle]);

    const overallCfg = getSeverityConfig(overallRisk);

    return (
        <div className="space-y-5">

            {/* ── Page header ─────────────────────────────────────────────── */}
            <div className="flex items-center gap-3">
                <div
                    className="w-10 h-10 rounded-xl flex items-center justify-center shadow-md flex-shrink-0"
                    style={{ background: "var(--color-primary)" }}
                >
                    <Navigation className="w-5 h-5 text-white" />
                </div>
                <div>
                    <h1 className="text-xl font-bold tracking-tight" style={{ color: "var(--dash-text-primary)" }}>
                        Disease Risk Map
                    </h1>
                    <p className="text-xs" style={{ color: "var(--dash-text-muted)" }}>
                        Real-time health risk visualization for your area
                    </p>
                </div>
            </div>

            {/* ── Error state ───────────────────────────────────────────── */}
            {contextError && (
                <div
                    className="flex items-center gap-2.5 rounded-xl border px-4 py-3 text-sm animate-fade-in-scale"
                    style={{
                        background: "rgba(220,38,38,0.08)",
                        borderColor: "rgba(220,38,38,0.28)",
                        color: "var(--color-danger)",
                    }}
                >
                    <AlertTriangle className="h-4 w-4 shrink-0" />
                    <span>{contextError}</span>
                </div>
            )}

            {/* ── Main layout ───────────────────────────────────────────── */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 items-start">

                {/* ── Interactive Map ───────────────────────────────────── */}
                <div
                    className="lg:col-span-2 card-panel relative p-0 overflow-hidden h-[450px] sm:h-[550px] lg:h-[650px] flex flex-col"
                >
                    <div ref={mapElement} className="flex-1 w-full" />

                    {/* Loading overlay */}
                    {isLoading && (
                        <div
                            className="absolute inset-0 z-10 flex items-center justify-center transition-all duration-300"
                            style={{ backdropFilter: "blur(4px)", background: "rgba(var(--dash-bg), 0.4)" }}
                        >
                            <div
                                className="px-5 py-3.5 rounded-2xl shadow-xl flex items-center gap-3 border"
                                style={{
                                    background: "var(--dash-card-bg)",
                                    borderColor: "var(--dash-card-border)",
                                }}
                            >
                                <Loader2 className="w-5 h-5 animate-spin" style={{ color: "var(--color-primary)" }} />
                                <span className="font-semibold text-sm" style={{ color: "var(--dash-text-primary)" }}>
                                    {contextLoading ? "Locating you..." : "Initializing map..."}
                                </span>
                            </div>
                        </div>
                    )}

                    {/* Risk legend overlay */}
                    <div className="absolute left-3 top-3 z-10 pointer-events-none">
                        <div
                            className="rounded-xl border p-2.5 pointer-events-auto"
                            style={{
                                background: "var(--dash-card-bg)",
                                borderColor: "var(--dash-card-border)",
                                backdropFilter: "blur(12px)",
                                boxShadow: "var(--shadow-md)",
                            }}
                        >
                            <p
                                className="text-[10px] font-bold uppercase tracking-widest mb-1.5 px-1"
                                style={{ color: "var(--dash-text-muted)" }}
                            >
                                Risk Legend
                            </p>
                            <div className="flex flex-col gap-1.5">
                                {(["high", "medium", "low", "safe"] as RiskLevel[]).map((lvl) => {
                                    const c = getSeverityConfig(lvl);
                                    return (
                                        <div key={lvl} className="flex items-center gap-2 px-1">
                                            <span
                                                className="w-2.5 h-2.5 rounded-full shadow-sm flex-shrink-0"
                                                style={{ backgroundColor: c.color }}
                                            />
                                            <span
                                                className="text-xs font-semibold capitalize"
                                                style={{ color: "var(--dash-text-secondary)" }}
                                            >
                                                {lvl}
                                            </span>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    </div>
                </div>

                {/* ── Information panel ─────────────────────────────────── */}
                <div className="lg:col-span-1 space-y-4">
                    {area ? (
                        <div className="card-panel animate-fade-in-scale">
                            {/* Panel header */}
                            <div className="card-panel-header flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <div
                                        className="w-7 h-7 rounded-lg flex items-center justify-center shadow-sm"
                                        style={{ background: "var(--color-primary)" }}
                                    >
                                        <Navigation className="h-3.5 w-3.5 text-white" />
                                    </div>
                                    <span
                                        className="text-sm font-semibold"
                                        style={{ color: "var(--dash-text-primary)" }}
                                    >
                                        Area Insights
                                    </span>
                                </div>
                                {/* Overall risk badge */}
                                <span
                                    className="text-[10px] font-bold rounded-full px-2.5 py-1 border capitalize"
                                    style={{
                                        color: overallCfg.textColor,
                                        background: overallCfg.bg,
                                        borderColor: overallCfg.border,
                                    }}
                                >
                                    {overallRisk} risk
                                </span>
                            </div>

                            <div className="p-4 sm:p-5 space-y-4">
                                {/* District info */}
                                <div>
                                    <h2
                                        className="text-lg font-bold"
                                        style={{ color: "var(--dash-text-primary)" }}
                                    >
                                        {area.district_name}
                                    </h2>
                                    <p className="text-xs" style={{ color: "var(--dash-text-muted)" }}>
                                        {area.province_name} • {area.distance.toFixed(1)} km away
                                    </p>
                                </div>

                                {/* Warning / safe banner */}
                                {locationData?.warning && locationData.warning !== "Area is safe" ? (
                                    <div
                                        className="rounded-xl border p-3 flex gap-2.5 items-start"
                                        style={{
                                            background: "rgba(217,119,6,0.09)",
                                            borderColor: "rgba(217,119,6,0.28)",
                                        }}
                                    >
                                        <AlertTriangle
                                            className="h-4 w-4 shrink-0 mt-0.5"
                                            style={{ color: "#b45309" }}
                                        />
                                        <p
                                            className="text-xs font-semibold leading-relaxed"
                                            style={{ color: "#92400e" }}
                                        >
                                            {locationData.warning}
                                        </p>
                                    </div>
                                ) : (
                                    <div
                                        className="rounded-xl border p-3 flex gap-2.5 items-start"
                                        style={{
                                            background: "rgba(5,150,105,0.09)",
                                            borderColor: "rgba(5,150,105,0.25)",
                                        }}
                                    >
                                        <CheckCircle2
                                            className="h-4 w-4 shrink-0 mt-0.5"
                                            style={{ color: "#059669" }}
                                        />
                                        <p
                                            className="text-xs font-semibold leading-relaxed"
                                            style={{ color: "#047857" }}
                                        >
                                            Area is currently safe with normal health activity.
                                        </p>
                                    </div>
                                )}

                                {/* Active pathogens list */}
                                <div>
                                    <p
                                        className="text-[10px] font-bold uppercase tracking-widest mb-2 border-b pb-1.5"
                                        style={{
                                            color: "var(--dash-text-muted)",
                                            borderColor: "var(--dash-card-border)",
                                        }}
                                    >
                                        Active Pathogens
                                    </p>
                                    {riskList.length > 0 ? (
                                        <div className="space-y-2">
                                            {riskList.map(risk => {
                                                const c = getSeverityConfig(risk.level);
                                                const detail = diseaseDetails.find(d => d.disease_id === risk.disease_id);
                                                const isExpanded = expandedDiseaseId === risk.disease_id;
                                                const hasDetail = detail && (detail.symptoms.length > 0 || detail.precautions.length > 0);
                                                return (
                                                    <ActivePathogenRow
                                                        key={risk.disease_id}
                                                        risk={risk}
                                                        detail={detail}
                                                        isExpanded={isExpanded}
                                                        onToggle={() => setExpandedDiseaseId(isExpanded ? null : risk.disease_id)}
                                                    />
                                                );
                                            })}
                                        </div>
                                    ) : (
                                        <div
                                            className="py-4 text-center text-xs rounded-xl border border-dashed"
                                            style={{
                                                color: "var(--dash-text-muted)",
                                                background: "var(--dash-card-header-bg)",
                                                borderColor: "var(--dash-card-border)",
                                            }}
                                        >
                                            No recent reports in this area.
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    ) : (
                        /* Awaiting location state */
                        <div className="card-panel py-10 px-6 text-center animate-fade-in-scale">
                            <div
                                className="w-12 h-12 rounded-2xl border flex items-center justify-center mx-auto mb-3"
                                style={{
                                    background: "var(--dash-card-header-bg)",
                                    borderColor: "var(--dash-card-border)",
                                }}
                            >
                                <Activity className="h-5 w-5" style={{ color: "var(--dash-text-muted)" }} />
                            </div>
                            <h3 className="text-sm font-semibold" style={{ color: "var(--dash-text-primary)" }}>
                                Awaiting Location
                            </h3>
                            <p
                                className="text-xs mt-1 max-w-[200px] mx-auto"
                                style={{ color: "var(--dash-text-muted)" }}
                            >
                                Stand by while we fetch your coordinates to display health insights.
                            </p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useMemo, useRef, useState, useCallback } from "react";
import * as tt from "@tomtom-international/web-sdk-maps";
import "@tomtom-international/web-sdk-maps/dist/maps.css";
import { useLocation } from "@/contexts/LocationContext";
import { Loader2, AlertTriangle, CheckCircle2, Navigation, Activity, ChevronDown, ChevronUp, ShieldCheck, HeartPulse, Sparkles, Hospital, TriangleAlert } from "lucide-react";

type DiseaseDetail = {
    disease_id: number;
    symptoms: string[];
    precautions: string[];
};

type RiskLevel = "safe" | "low" | "medium" | "high";

type SymptomCategory = { category: string; icon: string; items: string[] };
type PrecautionCategory = { category: string; icon: string; items: string[] };

type EnhancedInfo = {
    disease_name: string;
    severity_level: "low" | "moderate" | "high" | "critical";
    brief_summary: string;
    symptom_categories: SymptomCategory[];
    precaution_categories: PrecautionCategory[];
    when_to_seek_help: string;
};

async function enhanceDisease(name: string, details: DiseaseDetail): Promise<EnhancedInfo | null> {
    try {
        const res = await fetch("/api/groq/enhance-disease", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                disease_name: name,
                symptoms: details?.symptoms ?? [],
                precautions: details?.precautions ?? [],
            }),
        });
        if (!res.ok) return null;
        return await res.json() as EnhancedInfo;
    } catch {
        return null;
    }
}

interface DiseaseRisk {
    disease_id: number;
    disease_name: string;
    count: number;
    level: RiskLevel;
}

type SeverityConfig = {
    color: string;
    bg: string;
    border: string;
    textColor: string;
    stripColor: string;
};

const getSeverityConfig = (severity: RiskLevel): SeverityConfig => {
    switch (severity) {
        case "high":
            return { color: "#e11d48", bg: "rgba(225,29,72,0.09)", border: "rgba(225,29,72,0.28)", textColor: "#be123c", stripColor: "#f43f5e" };
        case "medium":
            return { color: "#d97706", bg: "rgba(217,119,6,0.09)", border: "rgba(217,119,6,0.28)", textColor: "#b45309", stripColor: "#f59e0b" };
        case "low":
            return { color: "#2563eb", bg: "rgba(37,99,235,0.09)", border: "rgba(37,99,235,0.22)", textColor: "var(--color-primary)", stripColor: "#3b82f6" };
        case "safe":
            return { color: "#059669", bg: "rgba(5,150,105,0.09)", border: "rgba(5,150,105,0.25)", textColor: "#047857", stripColor: "#10b981" };
        default:
            return { color: "#64748b", bg: "var(--dash-card-header-bg)", border: "var(--dash-card-border)", textColor: "var(--dash-text-secondary)", stripColor: "var(--dash-card-border)" };
    }
};

const getMaxRiskLevel = (riskLevels: Record<string, DiseaseRisk>): RiskLevel => {
    const priority: Record<RiskLevel, number> = { safe: 0, low: 1, medium: 2, high: 3 };
    return Object.values(riskLevels).reduce<RiskLevel>(
        (max, d) => (priority[d.level] > priority[max] ? d.level : max),
        "safe"
    );
};

/* ── Pathogen Row Component ─────────────────────────────────────────────── */

function ActivePathogenRow({ risk, detail, isExpanded, onToggle }: { risk: DiseaseRisk, detail?: DiseaseDetail, isExpanded: boolean, onToggle: () => void }) {
    const c = getSeverityConfig(risk.level);
    const hasDetail = detail && (detail.symptoms.length > 0 || detail.precautions.length > 0);

    const [enhanced, setEnhanced] = useState<EnhancedInfo | null>(null);
    const [enhancing, setEnhancing] = useState(false);
    const [enhanceFailed, setEnhanceFailed] = useState(false);

    const handleToggle = async () => {
        onToggle();

        const shouldLoadEnhancement = !isExpanded && hasDetail && !enhanced && !enhancing && !enhanceFailed;
        if (!shouldLoadEnhancement || !detail) return;

        setEnhancing(true);
        try {
            const res = await enhanceDisease(risk.disease_name, detail);
            if (res) setEnhanced(res);
            else setEnhanceFailed(true);
        } catch {
            setEnhanceFailed(true);
        } finally {
            setEnhancing(false);
        }
    };

    return (
        <div>
            <button
                type="button"
                onClick={() => void handleToggle()}
                className="relative w-full flex items-center justify-between p-2.5 rounded-lg border overflow-hidden transition-all duration-200 text-left"
                style={{ background: c.bg, borderColor: c.border }}
            >
                <div className="absolute left-0 top-0 bottom-0 w-1 rounded-l-lg" style={{ background: c.stripColor }} />
                <div className="pl-2.5 flex flex-col min-w-0 pr-2">
                    <span className="text-sm font-semibold truncate" style={{ color: c.textColor }}>{risk.disease_name}</span>
                    <span className="text-[10px] mt-0.5" style={{ color: c.textColor, opacity: 0.8 }}>
                        {risk.count} projected {risk.count === 1 ? 'case' : 'cases'}
                    </span>
                </div>
                <div className="flex items-center gap-1.5 shrink-0">
                    <span className="text-[10px] font-bold uppercase rounded-full px-2.5 py-0.5 border" style={{ color: c.textColor, background: "rgba(255,255,255,0.35)", borderColor: c.border }}>
                        {risk.level}
                    </span>
                    {hasDetail && (
                        isExpanded ? <ChevronUp className="h-3.5 w-3.5" style={{ color: c.textColor }} /> : <ChevronDown className="h-3.5 w-3.5" style={{ color: c.textColor }} />
                    )}
                </div>
            </button>

            {/* Expandable Panel */}
            {isExpanded && hasDetail && (
                <div className="mt-1 rounded-lg border px-3 py-3 space-y-3" style={{ background: "var(--dash-card-bg)", borderColor: "var(--dash-card-border)" }}>
                    {enhancing ? (
                        <div className="flex flex-col items-center py-4 gap-2 text-center" style={{ color: "var(--dash-text-secondary)" }}>
                            <Loader2 className="h-4 w-4 animate-spin mb-1" style={{ color: "var(--color-primary)" }} />
                            <span className="text-xs font-medium">Analyzing with AI...</span>
                        </div>
                    ) : enhanced ? (
                        <div className="space-y-4">
                            <div className="flex items-center gap-1.5 text-[9px] font-semibold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                                <Sparkles className="h-3 w-3 text-violet-500" />
                                AI-organized by Groq
                            </div>

                            {enhanced.brief_summary && (
                                <p className="text-xs leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>{enhanced.brief_summary}</p>
                            )}

                            {enhanced.symptom_categories.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                        <HeartPulse className="h-3 w-3 text-red-500 shrink-0" />
                                        <p className="text-[9px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Symptoms</p>
                                    </div>
                                    <div className="space-y-2">
                                        {enhanced.symptom_categories.map((cat) => (
                                            <div key={cat.category}>
                                                <p className="text-[11px] font-bold mb-1 flex items-center gap-1" style={{ color: "#dc2626" }}>
                                                    <span>{cat.icon}</span> {cat.category}
                                                </p>
                                                <div className="flex flex-wrap gap-1">
                                                    {cat.items.map((item) => (
                                                        <span key={item} className="inline-flex items-center rounded-full border px-2 py-0.5 text-[10px] font-medium" style={{ background: "rgba(239,68,68,0.08)", borderColor: "rgba(239,68,68,0.20)", color: "#dc2626" }}>
                                                            {item}
                                                        </span>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {enhanced.precaution_categories.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5 border-t pt-2" style={{ borderColor: "var(--dash-card-border)" }}>
                                        <ShieldCheck className="h-3 w-3 text-emerald-500 shrink-0" />
                                        <p className="text-[9px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Precautions</p>
                                    </div>
                                    <div className="space-y-2">
                                        {enhanced.precaution_categories.map((cat) => (
                                            <div key={cat.category}>
                                                <p className="text-[11px] font-bold mb-1 flex items-center gap-1" style={{ color: "#059669" }}>
                                                    <span>{cat.icon}</span> {cat.category}
                                                </p>
                                                <ol className="space-y-1">
                                                    {cat.items.map((item, ii) => (
                                                        <li key={item} className="flex items-start gap-1.5 text-[11px]" style={{ color: "var(--dash-text-secondary)" }}>
                                                            <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold" style={{ background: "rgba(16,185,129,0.12)", color: "#059669", border: "1px solid rgba(16,185,129,0.25)" }}>
                                                                {ii + 1}
                                                            </span>
                                                            {item}
                                                        </li>
                                                    ))}
                                                </ol>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {enhanced.when_to_seek_help && (
                                <div className="mt-3 rounded-lg border p-2 flex items-start gap-2" style={{ background: "rgba(239,68,68,0.05)", borderColor: "rgba(239,68,68,0.15)" }}>
                                    <Hospital className="h-3.5 w-3.5 mt-0.5 text-red-500 shrink-0" />
                                    <p className="text-[10px] leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>
                                        <span className="font-bold text-red-500 block mb-0.5">When to seek help</span>
                                        {enhanced.when_to_seek_help}
                                    </p>
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {enhanceFailed && (
                                <div className="flex items-center gap-2 text-[10px] rounded p-2" style={{ background: "rgba(245,158,11,0.1)", color: "#d97706" }}>
                                    <TriangleAlert className="h-3 w-3 shrink-0" />
                                    AI enhancement unavailable — showing raw data
                                </div>
                            )}
                            {detail?.symptoms.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                        <HeartPulse className="h-3 w-3 text-red-500" />
                                        <p className="text-[10px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Symptoms</p>
                                    </div>
                                    <div className="flex flex-wrap gap-1">
                                        {detail.symptoms.map((s) => (
                                            <span key={s} className="inline-flex items-center rounded-full border px-2 py-0.5 text-[10px] font-medium" style={{ background: "rgba(239,68,68,0.08)", borderColor: "rgba(239,68,68,0.20)", color: "#dc2626" }}>
                                                {s}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {detail?.precautions.length > 0 && (
                                <div>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                        <ShieldCheck className="h-3 w-3 text-emerald-500" />
                                        <p className="text-[10px] font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Precautions</p>
                                    </div>
                                    <ol className="space-y-1">
                                        {detail.precautions.map((p, i) => (
                                            <li key={p} className="flex items-start gap-1.5 text-[11px]" style={{ color: "var(--dash-text-secondary)" }}>
                                                <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold" style={{ background: "rgba(16,185,129,0.12)", color: "#059669", border: "1px solid rgba(16,185,129,0.25)" }}>
                                                    {i + 1}
                                                </span>
                                                {p}
                                            </li>
                                        ))}
                                    </ol>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

export default function MapComponent() {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapRef = useRef<tt.Map | null>(null);
    const nearbyMarkerRef = useRef<tt.Marker | null>(null);
    const userMarkerRef = useRef<tt.Marker | null>(null);

    const { locationData, isLoading: contextLoading, error: contextError } = useLocation();
    const [mapReady, setMapReady] = useState(false);
    const [diseaseDetails, setDiseaseDetails] = useState<DiseaseDetail[]>([]);
    const [expandedDiseaseId, setExpandedDiseaseId] = useState<number | null>(null);

    // Fetch disease details from MongoDB via public Next.js route
    useEffect(() => {
        fetch("/api/public/disease-details", { cache: "no-store" })
            .then((r) => r.json())
            .then((data: unknown) => {
                if (Array.isArray(data)) setDiseaseDetails(data as DiseaseDetail[]);
            })
            .catch(() => { /* non-critical */ });
    }, []);

    const isLoading = contextLoading || !mapReady;

    const area = locationData?.nearest_area;
    const riskList = useMemo(() => {
        if (!area) return [];
        return Object.values(area.risk_levels).sort((a, b) => {
            const p: Record<RiskLevel, number> = { high: 3, medium: 2, low: 1, safe: 0 };
            return p[b.level] - p[a.level];
        });
    }, [area]);

    const overallRisk = useMemo(() => {
        if (!area) return "safe" as RiskLevel;
        return getMaxRiskLevel(area.risk_levels);
    }, [area]);

    const circleGeoJson = (center: [number, number], radiusMeters: number) => {
        const points = 64;
        const coords: number[][] = [];
        const [lng, lat] = center;
        const radiusKm = radiusMeters / 1000;
        const latRad = (lat * Math.PI) / 180;
        for (let i = 0; i < points; i++) {
            const angle = (i / points) * 2 * Math.PI;
            const dLat = (radiusKm / 111) * Math.cos(angle);
            const dLng = (radiusKm / (111 * Math.cos(latRad))) * Math.sin(angle);
            coords.push([lng + dLng, lat + dLat]);
        }
        coords.push(coords[0]);
        return {
            type: "Feature" as const,
            geometry: { type: "Polygon" as const, coordinates: [coords] },
            properties: {},
        };
    };

    const upsertCircle = useCallback((map: tt.Map, center: [number, number], radiusMeters: number, color: string) => {
        const sourceId = "radius-source";
        const fillId = "radius-layer";
        const outlineId = "radius-layer-outline";
        const data = {
            type: "FeatureCollection" as const,
            features: [circleGeoJson(center, radiusMeters)],
        };
        if (!map.getSource(sourceId)) {
            map.addSource(sourceId, { type: "geojson", data });
            map.addLayer({ id: fillId, type: "fill", source: sourceId, paint: { "fill-color": color, "fill-opacity": 0.15 } });
            map.addLayer({ id: outlineId, type: "line", source: sourceId, paint: { "line-color": color, "line-width": 2, "line-opacity": 0.8 } });
        } else {
            const src = map.getSource(sourceId) as tt.GeoJSONSource;
            src.setData(data);
            map.setPaintProperty(fillId, "fill-color", color);
            map.setPaintProperty(outlineId, "line-color", color);
        }
    }, []);

    useEffect(() => {
        if (!mapElement.current) return;
        if (mapRef.current) return;
        const map = tt.map({
            key: process.env.NEXT_PUBLIC_TOMTOM_API_KEY!,
            container: mapElement.current,
            center: [80.7718, 7.8731],
            zoom: 7.5,
            language: "en-GB",
        });
        mapRef.current = map;
        map.on("load", () => setMapReady(true));
        return () => {
            userMarkerRef.current?.remove();
            nearbyMarkerRef.current?.remove();
            map.remove();
            mapRef.current = null;
        };
    }, []);

    useEffect(() => {
        const map = mapRef.current;
        if (!map || !mapReady || !locationData) return;
        const { latitude, longitude } = locationData.user_location;
        const userCoords: [number, number] = [longitude, latitude];

        userMarkerRef.current?.remove();
        nearbyMarkerRef.current?.remove();

        const userPopupHtml = `
            <div style="font-family: inherit; margin: -4px;">
                <div style="font-weight:700; font-size: 13px; margin-bottom: 2px; color: #1e293b;">Your Location</div>
                <div style="font-size:11px; color: #64748b;">${latitude.toFixed(4)}, ${longitude.toFixed(4)}</div>
            </div>`;

        userMarkerRef.current = new tt.Marker({ color: "#2563eb" })
            .setLngLat(userCoords)
            .setPopup(new tt.Popup({ offset: 26, className: "custom-map-popup" }).setHTML(userPopupHtml))
            .addTo(map);

        if (locationData.nearest_area) {
            const a = locationData.nearest_area;
            const areaCoords: [number, number] = [a.longitude, a.latitude];
            const maxRisk = getMaxRiskLevel(a.risk_levels);
            const markerColor = getSeverityConfig(maxRisk).color;
            const riskListHtml = Object.values(a.risk_levels).map(r => `<div style="font-size:11px; margin-bottom:2px;">• ${r.disease_name}: <b>${r.level}</b></div>`).join('');
            const areaPopupHtml = `
                <div style="font-family: inherit; margin: -4px; width: 160px;">
                    <div style="font-weight:700; font-size: 14px; margin-bottom: 2px; color: #0f172a;">${a.district_name}</div>
                    <div style="font-size:11px; color: #64748b; margin-bottom: 8px;">${a.province_name} · ${a.distance.toFixed(1)} km</div>
                    <div style="border-top: 1px solid #e2e8f0; padding-top: 6px;">
                        ${riskListHtml}
                    </div>
                </div>`;

            nearbyMarkerRef.current = new tt.Marker({ color: markerColor })
                .setLngLat(areaCoords)
                .setPopup(new tt.Popup({ offset: 26, className: "custom-map-popup" }).setHTML(areaPopupHtml))
                .addTo(map);

            upsertCircle(map, areaCoords, 5000, markerColor);

            const bounds = new tt.LngLatBounds();
            bounds.extend(userCoords);
            bounds.extend(areaCoords);
            setTimeout(() => {
                if (mapRef.current) mapRef.current.fitBounds(bounds, { padding: 80, maxZoom: 12 });
            }, 100);
        } else {
            map.setCenter(userCoords);
            map.setZoom(12);
        }
    }, [locationData, mapReady, upsertCircle]);

    const overallCfg = getSeverityConfig(overallRisk);

    return (
        <div className="space-y-5">

            {/* ── Page header ─────────────────────────────────────────────── */}
            <div className="flex items-center gap-3">
                <div
                    className="w-10 h-10 rounded-xl flex items-center justify-center shadow-md flex-shrink-0"
                    style={{ background: "var(--color-primary)" }}
                >
                    <Navigation className="w-5 h-5 text-white" />
                </div>
                <div>
                    <h1 className="text-xl font-bold tracking-tight" style={{ color: "var(--dash-text-primary)" }}>
                        Disease Risk Map
                    </h1>
                    <p className="text-xs" style={{ color: "var(--dash-text-muted)" }}>
                        Real-time health risk visualization for your area
                    </p>
                </div>
            </div>

            {/* ── Error state ───────────────────────────────────────────── */}
            {contextError && (
                <div
                    className="flex items-center gap-2.5 rounded-xl border px-4 py-3 text-sm animate-fade-in-scale"
                    style={{
                        background: "rgba(220,38,38,0.08)",
                        borderColor: "rgba(220,38,38,0.28)",
                        color: "var(--color-danger)",
                    }}
                >
                    <AlertTriangle className="h-4 w-4 shrink-0" />
                    <span>{contextError}</span>
                </div>
            )}

            {/* ── Main layout ───────────────────────────────────────────── */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 items-start">

                {/* ── Interactive Map ───────────────────────────────────── */}
                <div
                    className="lg:col-span-2 card-panel relative p-0 overflow-hidden h-[450px] sm:h-[550px] lg:h-[650px] flex flex-col"
                >
                    <div ref={mapElement} className="flex-1 w-full" />

                    {/* Loading overlay */}
                    {isLoading && (
                        <div
                            className="absolute inset-0 z-10 flex items-center justify-center transition-all duration-300"
                            style={{ backdropFilter: "blur(4px)", background: "rgba(var(--dash-bg), 0.4)" }}
                        >
                            <div
                                className="px-5 py-3.5 rounded-2xl shadow-xl flex items-center gap-3 border"
                                style={{
                                    background: "var(--dash-card-bg)",
                                    borderColor: "var(--dash-card-border)",
                                }}
                            >
                                <Loader2 className="w-5 h-5 animate-spin" style={{ color: "var(--color-primary)" }} />
                                <span className="font-semibold text-sm" style={{ color: "var(--dash-text-primary)" }}>
                                    {contextLoading ? "Locating you..." : "Initializing map..."}
                                </span>
                            </div>
                        </div>
                    )}

                    {/* Risk legend overlay */}
                    <div className="absolute left-3 top-3 z-10 pointer-events-none">
                        <div
                            className="rounded-xl border p-2.5 pointer-events-auto"
                            style={{
                                background: "var(--dash-card-bg)",
                                borderColor: "var(--dash-card-border)",
                                backdropFilter: "blur(12px)",
                                boxShadow: "var(--shadow-md)",
                            }}
                        >
                            <p
                                className="text-[10px] font-bold uppercase tracking-widest mb-1.5 px-1"
                                style={{ color: "var(--dash-text-muted)" }}
                            >
                                Risk Legend
                            </p>
                            <div className="flex flex-col gap-1.5">
                                {(["high", "medium", "low", "safe"] as RiskLevel[]).map((lvl) => {
                                    const c = getSeverityConfig(lvl);
                                    return (
                                        <div key={lvl} className="flex items-center gap-2 px-1">
                                            <span
                                                className="w-2.5 h-2.5 rounded-full shadow-sm flex-shrink-0"
                                                style={{ backgroundColor: c.color }}
                                            />
                                            <span
                                                className="text-xs font-semibold capitalize"
                                                style={{ color: "var(--dash-text-secondary)" }}
                                            >
                                                {lvl}
                                            </span>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    </div>
                </div>

                {/* ── Information panel ─────────────────────────────────── */}
                <div className="lg:col-span-1 space-y-4">
                    {area ? (
                        <div className="card-panel animate-fade-in-scale">
                            {/* Panel header */}
                            <div className="card-panel-header flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                    <div
                                        className="w-7 h-7 rounded-lg flex items-center justify-center shadow-sm"
                                        style={{ background: "var(--color-primary)" }}
                                    >
                                        <Navigation className="h-3.5 w-3.5 text-white" />
                                    </div>
                                    <span
                                        className="text-sm font-semibold"
                                        style={{ color: "var(--dash-text-primary)" }}
                                    >
                                        Area Insights
                                    </span>
                                </div>
                                {/* Overall risk badge */}
                                <span
                                    className="text-[10px] font-bold rounded-full px-2.5 py-1 border capitalize"
                                    style={{
                                        color: overallCfg.textColor,
                                        background: overallCfg.bg,
                                        borderColor: overallCfg.border,
                                    }}
                                >
                                    {overallRisk} risk
                                </span>
                            </div>

                            <div className="p-4 sm:p-5 space-y-4">
                                {/* District info */}
                                <div>
                                    <h2
                                        className="text-lg font-bold"
                                        style={{ color: "var(--dash-text-primary)" }}
                                    >
                                        {area.district_name}
                                    </h2>
                                    <p className="text-xs" style={{ color: "var(--dash-text-muted)" }}>
                                        {area.province_name} • {area.distance.toFixed(1)} km away
                                    </p>
                                </div>

                                {/* Warning / safe banner */}
                                {locationData?.warning && locationData.warning !== "Area is safe" ? (
                                    <div
                                        className="rounded-xl border p-3 flex gap-2.5 items-start"
                                        style={{
                                            background: "rgba(217,119,6,0.09)",
                                            borderColor: "rgba(217,119,6,0.28)",
                                        }}
                                    >
                                        <AlertTriangle
                                            className="h-4 w-4 shrink-0 mt-0.5"
                                            style={{ color: "#b45309" }}
                                        />
                                        <p
                                            className="text-xs font-semibold leading-relaxed"
                                            style={{ color: "#92400e" }}
                                        >
                                            {locationData.warning}
                                        </p>
                                    </div>
                                ) : (
                                    <div
                                        className="rounded-xl border p-3 flex gap-2.5 items-start"
                                        style={{
                                            background: "rgba(5,150,105,0.09)",
                                            borderColor: "rgba(5,150,105,0.25)",
                                        }}
                                    >
                                        <CheckCircle2
                                            className="h-4 w-4 shrink-0 mt-0.5"
                                            style={{ color: "#059669" }}
                                        />
                                        <p
                                            className="text-xs font-semibold leading-relaxed"
                                            style={{ color: "#047857" }}
                                        >
                                            Area is currently safe with normal health activity.
                                        </p>
                                    </div>
                                )}

                                {/* Active pathogens list */}
                                <div>
                                    <p
                                        className="text-[10px] font-bold uppercase tracking-widest mb-2 border-b pb-1.5"
                                        style={{
                                            color: "var(--dash-text-muted)",
                                            borderColor: "var(--dash-card-border)",
                                        }}
                                    >
                                        Active Pathogens
                                    </p>
                                    {riskList.length > 0 ? (
                                        <div className="space-y-2">
                                            {riskList.map(risk => {
                                                const detail = diseaseDetails.find(d => d.disease_id === risk.disease_id);
                                                const isExpanded = expandedDiseaseId === risk.disease_id;
                                                return (
                                                    <ActivePathogenRow
                                                        key={risk.disease_id}
                                                        risk={risk}
                                                        detail={detail}
                                                        isExpanded={isExpanded}
                                                        onToggle={() => setExpandedDiseaseId(isExpanded ? null : risk.disease_id)}
                                                    />
                                                );
                                            })}
                                        </div>
                                    ) : (
                                        <div
                                            className="py-4 text-center text-xs rounded-xl border border-dashed"
                                            style={{
                                                color: "var(--dash-text-muted)",
                                                background: "var(--dash-card-header-bg)",
                                                borderColor: "var(--dash-card-border)",
                                            }}
                                        >
                                            No recent reports in this area.
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    ) : (
                        /* Awaiting location state */
                        <div className="card-panel py-10 px-6 text-center animate-fade-in-scale">
                            <div
                                className="w-12 h-12 rounded-2xl border flex items-center justify-center mx-auto mb-3"
                                style={{
                                    background: "var(--dash-card-header-bg)",
                                    borderColor: "var(--dash-card-border)",
                                }}
                            >
                                <Activity className="h-5 w-5" style={{ color: "var(--dash-text-muted)" }} />
                            </div>
                            <h3 className="text-sm font-semibold" style={{ color: "var(--dash-text-primary)" }}>
                                Awaiting Location
                            </h3>
                            <p
                                className="text-xs mt-1 max-w-[200px] mx-auto"
                                style={{ color: "var(--dash-text-muted)" }}
                            >
                                Stand by while we fetch your coordinates to display health insights.
                            </p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, useMemo, useCallback } from "react";
import {
    HeartPulse,
    ShieldCheck,
    AlertCircle,
    Search,
    ChevronDown,
    ChevronUp,
    RefreshCw,
    Stethoscope,
    CheckCircle2,
    Sparkles,
    Loader2,
    TriangleAlert,
    Hospital,
    Info,
} from "lucide-react";

/* ── Types ─────────────────────────────────────────────────────────────────── */

type Disease = {
    disease_id: number;
    disease_name: string;
    description: string | null;
};

type DiseaseDetail = {
    disease_id: number;
    symptoms: string[];
    precautions: string[];
    createdAt: string;
    updatedAt: string;
};

type MergedDisease = Disease & { details: DiseaseDetail | null };

type SymptomCategory = { category: string; icon: string; items: string[] };
type PrecautionCategory = { category: string; icon: string; items: string[] };

type EnhancedInfo = {
    disease_name: string;
    severity_level: "low" | "moderate" | "high" | "critical";
    brief_summary: string;
    symptom_categories: SymptomCategory[];
    precaution_categories: PrecautionCategory[];
    when_to_seek_help: string;
};

/* ── Fetch helpers ─────────────────────────────────────────────────────────── */

async function fetchDiseases(): Promise<Disease[]> {
    try {
        const res = await fetch("/api/public/diseases", { cache: "no-store" });
        if (!res.ok) return [];
        const data = await res.json();
        return Array.isArray(data) ? data : (data?.diseases ?? []);
    } catch {
        return [];
    }
}

async function fetchDiseaseDetails(): Promise<DiseaseDetail[]> {
    const res = await fetch("/api/public/disease-details", { cache: "no-store" });
    const data = await res.json();
    if (!res.ok) throw new Error(data?.error || "Failed to fetch disease details");
    return Array.isArray(data) ? data : [];
}

async function enhanceDisease(disease: MergedDisease): Promise<EnhancedInfo | null> {
    try {
        const res = await fetch("/api/groq/enhance-disease", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                disease_name: disease.disease_name,
                symptoms: disease.details?.symptoms ?? [],
                precautions: disease.details?.precautions ?? [],
            }),
        });
        if (!res.ok) return null;
        return await res.json() as EnhancedInfo;
    } catch {
        return null;
    }
}

/* ── Severity config ────────────────────────────────────────────────────────── */

type SeverityLevel = "low" | "moderate" | "high" | "critical";

const severityConfig: Record<SeverityLevel, {
    label: string; bg: string; border: string; text: string; badgeBg: string;
}> = {
    low: {
        label: "Low Risk", bg: "rgba(16,185,129,0.07)", border: "rgba(16,185,129,0.25)",
        text: "#059669", badgeBg: "rgba(16,185,129,0.12)",
    },
    moderate: {
        label: "Moderate Risk", bg: "rgba(245,158,11,0.07)", border: "rgba(245,158,11,0.28)",
        text: "#d97706", badgeBg: "rgba(245,158,11,0.12)",
    },
    high: {
        label: "High Risk", bg: "rgba(239,68,68,0.07)", border: "rgba(239,68,68,0.25)",
        text: "#dc2626", badgeBg: "rgba(239,68,68,0.12)",
    },
    critical: {
        label: "Critical", bg: "rgba(139,0,0,0.07)", border: "rgba(139,0,0,0.30)",
        text: "#991b1b", badgeBg: "rgba(139,0,0,0.12)",
    },
};

/* ── Sub-components ─────────────────────────────────────────────────────────── */

function SeverityBadge({ level }: { level: SeverityLevel }) {
    const cfg = severityConfig[level] ?? severityConfig.low;
    return (
        <span
            className="inline-flex items-center gap-1.5 rounded-full border px-2.5 py-0.5 text-[11px] font-bold capitalize"
            style={{ background: cfg.badgeBg, borderColor: cfg.border, color: cfg.text }}
        >
            <span className="h-1.5 w-1.5 rounded-full shrink-0" style={{ background: cfg.text }} />
            {cfg.label}
        </span>
    );
}

function EnhancedDiseasePanel({ enhanced }: { enhanced: EnhancedInfo }) {
    const sev = severityConfig[enhanced.severity_level] ?? severityConfig.low;

    return (
        <div className="space-y-5">
            {/* Summary banner */}
            {enhanced.brief_summary && (
                <div
                    className="flex items-start gap-3 rounded-xl border px-4 py-3"
                    style={{ background: sev.bg, borderColor: sev.border }}
                >
                    <Info className="h-4 w-4 shrink-0 mt-0.5" style={{ color: sev.text }} />
                    <p className="text-sm leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>
                        {enhanced.brief_summary}
                    </p>
                </div>
            )}

            {/* Symptoms */}
            {enhanced.symptom_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <AlertCircle className="h-4 w-4 text-red-500 shrink-0" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            Symptoms
                        </p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.symptom_categories.map((cat) => (
                            <div
                                key={cat.category}
                                className="rounded-xl border p-3.5"
                                style={{
                                    background: "rgba(239,68,68,0.04)",
                                    borderColor: "rgba(239,68,68,0.18)",
                                }}
                            >
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5" style={{ color: "#dc2626" }}>
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ul className="space-y-1.5">
                                    {cat.items.map((item) => (
                                        <li key={item} className="flex items-start gap-2 text-xs" style={{ color: "var(--dash-text-secondary)" }}>
                                            <span className="mt-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0" />
                                            {item}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Divider */}
            {enhanced.symptom_categories.length > 0 && enhanced.precaution_categories.length > 0 && (
                <div className="border-t" style={{ borderColor: "var(--dash-card-border)" }} />
            )}

            {/* Precautions */}
            {enhanced.precaution_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <ShieldCheck className="h-4 w-4 text-emerald-500 shrink-0" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            Precautions
                        </p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.precaution_categories.map((cat, ci) => (
                            <div
                                key={cat.category}
                                className="rounded-xl border p-3.5"
                                style={{
                                    background: "rgba(16,185,129,0.04)",
                                    borderColor: "rgba(16,185,129,0.18)",
                                }}
                            >
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5" style={{ color: "#059669" }}>
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ol className="space-y-1.5">
                                    {cat.items.map((item, ii) => (
                                        <li key={item} className="flex items-start gap-2 text-xs" style={{ color: "var(--dash-text-secondary)" }}>
                                            <span
                                                className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold"
                                                style={{
                                                    background: "rgba(16,185,129,0.15)",
                                                    color: "#059669",
                                                    border: "1px solid rgba(16,185,129,0.30)",
                                                }}
                                            >
                                                {ii + 1}
                                            </span>
                                            {item}
                                        </li>
                                    ))}
                                </ol>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* When to seek help */}
            {enhanced.when_to_seek_help && (
                <div
                    className="flex items-start gap-3 rounded-xl border px-4 py-3.5"
                    style={{
                        background: "rgba(239,68,68,0.05)",
                        borderColor: "rgba(239,68,68,0.20)",
                    }}
                >
                    <Hospital className="h-4 w-4 shrink-0 mt-0.5 text-red-500" />
                    <div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-red-500 mb-1">
                            When to seek medical help
                        </p>
                        <p className="text-sm leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>
                            {enhanced.when_to_seek_help}
                        </p>
                    </div>
                </div>
            )}
        </div>
    );
}

/* ── Fallback plain display (if Groq fails) ─────────────────────────────────── */

function PlainDiseasePanel({ details }: { details: DiseaseDetail }) {
    return (
        <div className="space-y-4">
            {details.symptoms.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <AlertCircle className="h-4 w-4 text-red-500" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Symptoms</p>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {details.symptoms.map((s) => (
                            <span key={s} className="inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-medium"
                                style={{ background: "rgba(239,68,68,0.08)", borderColor: "rgba(239,68,68,0.22)", color: "#dc2626" }}>
                                <span className="mr-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0" />{s}
                            </span>
                        ))}
                    </div>
                </div>
            )}
            {details.precautions.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <ShieldCheck className="h-4 w-4 text-emerald-500" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Precautions</p>
                    </div>
                    <ol className="space-y-2">
                        {details.precautions.map((p, i) => (
                            <li key={p} className="flex items-start gap-2.5 text-sm" style={{ color: "var(--dash-text-secondary)" }}>
                                <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-5 w-5 rounded-full text-[10px] font-bold"
                                    style={{ background: "rgba(16,185,129,0.12)", color: "#059669", border: "1px solid rgba(16,185,129,0.25)" }}>
                                    {i + 1}
                                </span>
                                {p}
                            </li>
                        ))}
                    </ol>
                </div>
            )}
        </div>
    );
}

/* ── Disease card with Groq enhancement ─────────────────────────────────────── */

function DiseaseCard({ disease, defaultOpen }: { disease: MergedDisease; defaultOpen?: boolean }) {
    const [open, setOpen] = useState(defaultOpen ?? false);
    const [enhanced, setEnhanced] = useState<EnhancedInfo | null>(null);
    const [enhancing, setEnhancing] = useState(false);
    const [enhanceFailed, setEnhanceFailed] = useState(false);

    const hasDetails = disease.details !== null &&
        (disease.details.symptoms.length > 0 || disease.details.precautions.length > 0);

    const handleToggle = useCallback(async () => {
        const nextOpen = !open;
        setOpen(nextOpen);

        // Load enhanced info when first opened and details exist
        if (nextOpen && hasDetails && !enhanced && !enhancing && !enhanceFailed) {
            setEnhancing(true);
            try {
                const result = await enhanceDisease(disease);
                if (result) {
                    setEnhanced(result);
                } else {
                    setEnhanceFailed(true);
                }
            } catch {
                setEnhanceFailed(true);
            } finally {
                setEnhancing(false);
            }
        }
    }, [open, hasDetails, enhanced, enhancing, enhanceFailed, disease]);

    const sev = enhanced?.severity_level
        ? (severityConfig[enhanced.severity_level] ?? severityConfig.low)
        : null;

    return (
        <div className="card-panel animate-fade-in-scale overflow-hidden" style={{ animationDelay: "0ms" }}>
            {/* Header */}
            <button
                type="button"
                onClick={() => void handleToggle()}
                className="w-full card-panel-header flex items-center justify-between gap-3 cursor-pointer"
                aria-expanded={open}
            >
                <div className="flex items-center gap-3 min-w-0">
                    <div
                        className="shrink-0 w-9 h-9 rounded-xl flex items-center justify-center shadow-sm"
                        style={{ background: sev ? sev.bg === severityConfig.critical.bg ? "#991b1b" : sev.text : "var(--color-primary)" }}
                    >
                        <HeartPulse className="h-4 w-4 text-white" />
                    </div>
                    <div className="min-w-0 text-left">
                        <p className="text-sm font-bold truncate" style={{ color: "var(--dash-text-primary)" }}>
                            {disease.disease_name}
                        </p>
                        {disease.description && (
                            <p className="text-xs truncate" style={{ color: "var(--dash-text-muted)" }}>
                                {disease.description}
                            </p>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-2 shrink-0">
                    {enhanced?.severity_level && <SeverityBadge level={enhanced.severity_level} />}
                    {!hasDetails && (
                        <span className="hidden sm:inline text-[10px] font-semibold rounded-full border px-2.5 py-0.5"
                            style={{ background: "var(--dash-card-header-bg)", borderColor: "var(--dash-card-border)", color: "var(--dash-text-muted)" }}>
                            No details yet
                        </span>
                    )}
                    {open
                        ? <ChevronUp className="h-4 w-4" style={{ color: "var(--dash-text-muted)" }} />
                        : <ChevronDown className="h-4 w-4" style={{ color: "var(--dash-text-muted)" }} />}
                </div>
            </button>

            {/* Expanded content */}
            {open && (
                <div className="px-5 pb-5 pt-4">
                    {!hasDetails ? (
                        <div className="flex flex-col items-center py-8 rounded-xl border border-dashed text-center"
                            style={{ background: "var(--dash-card-header-bg)", borderColor: "var(--dash-card-border)", color: "var(--dash-text-muted)" }}>
                            <Stethoscope className="h-6 w-6 mb-2 opacity-50" />
                            <p className="text-sm font-medium">No details added yet</p>
                        </div>
                    ) : enhancing ? (
                        /* Groq loading state */
                        <div className="flex flex-col items-center py-10 gap-3">
                            <div className="flex items-center gap-2.5 rounded-xl border px-5 py-3"
                                style={{ background: "var(--dash-card-bg)", borderColor: "var(--dash-card-border)" }}>
                                <Loader2 className="h-4 w-4 animate-spin" style={{ color: "var(--color-primary)" }} />
                                <span className="text-sm font-medium" style={{ color: "var(--dash-text-secondary)" }}>
                                    Analyzing with AI…
                                </span>
                                <Sparkles className="h-4 w-4 text-violet-500" />
                            </div>
                        </div>
                    ) : enhanced ? (
                        /* Groq-enhanced display */
                        <div>
                            <div className="flex items-center gap-1.5 mb-4 text-[10px] font-semibold uppercase tracking-widest"
                                style={{ color: "var(--dash-text-muted)" }}>
                                <Sparkles className="h-3 w-3 text-violet-500" />
                                AI-organized by Groq · LLaMA 3.3
                            </div>
                            <EnhancedDiseasePanel enhanced={enhanced} />
                        </div>
                    ) : (
                        /* Fallback if Groq failed */
                        <div>
                            {enhanceFailed && (
                                <div className="flex items-center gap-2 mb-3 text-xs rounded-lg border px-3 py-2"
                                    style={{ background: "rgba(245,158,11,0.07)", borderColor: "rgba(245,158,11,0.22)", color: "#d97706" }}>
                                    <TriangleAlert className="h-3.5 w-3.5 shrink-0" />
                                    AI enhancement unavailable — showing raw data
                                </div>
                            )}
                            <PlainDiseasePanel details={disease.details!} />
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

/* ── Main Component ─────────────────────────────────────────────────────────── */

export default function TakeCare() {
    const [diseases, setDiseases] = useState<Disease[]>([]);
    const [details, setDetails] = useState<DiseaseDetail[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [search, setSearch] = useState("");
    const [refreshing, setRefreshing] = useState(false);

    const load = async (isRefresh = false) => {
        if (isRefresh) setRefreshing(true);
        else setLoading(true);
        setError(null);
        try {
            const [diseaseList, detailList] = await Promise.all([
                fetchDiseases(),
                fetchDiseaseDetails(),
            ]);
            setDiseases(diseaseList);
            setDetails(detailList);
        } catch (err) {
            setError(err instanceof Error ? err.message : "Failed to load data");
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    };

    useEffect(() => { void load(); }, []);

    // Build from union of all known IDs — details-driven
    const merged = useMemo<MergedDisease[]>(() => {
        const detailMap = new Map(details.map((d) => [d.disease_id, d]));
        const diseaseMap = new Map(diseases.map((d) => [d.disease_id, d]));
        const allIds = new Set([...details.map((d) => d.disease_id), ...diseases.map((d) => d.disease_id)]);
        return Array.from(allIds).map((id) => {
            const disease = diseaseMap.get(id);
            const detail = detailMap.get(id) ?? null;
            return {
                disease_id: id,
                disease_name: disease?.disease_name ?? `Disease #${id}`,
                description: disease?.description ?? null,
                details: detail,
            };
        }).sort((a, b) => {
            if (a.details && !b.details) return -1;
            if (!a.details && b.details) return 1;
            return a.disease_name.localeCompare(b.disease_name);
        });
    }, [diseases, details]);

    const filtered = useMemo(() => {
        if (!search.trim()) return merged;
        const q = search.toLowerCase();
        return merged.filter((d) =>
            d.disease_name.toLowerCase().includes(q) ||
            (d.description ?? "").toLowerCase().includes(q)
        );
    }, [merged, search]);

    const withDetails = filtered.filter((d) => d.details !== null);
    const withoutDetails = filtered.filter((d) => d.details === null);

    return (
        <section className="space-y-6">
            {/* ── Page heading ────────────────────────────────── */}
            <div className="flex flex-wrap items-start justify-between gap-3 pt-1">
                <div>
                    <div className="flex items-center gap-2.5 mb-1">
                        <div className="w-8 h-8 rounded-xl bg-linear-to-br from-rose-500 to-pink-600 flex items-center justify-center shadow-md shadow-rose-500/25">
                            <HeartPulse className="h-4 w-4 text-white" />
                        </div>
                        <h1 className="text-xl font-bold tracking-tight" style={{ color: "var(--dash-text-primary)" }}>
                            Take Care
                        </h1>
                    </div>
                    <p className="text-sm ml-[2.6rem]" style={{ color: "var(--dash-text-secondary)" }}>
                        AI-organized disease symptoms &amp; precautions — powered by Groq &amp; LLaMA 3.3
                    </p>
                </div>

                <button
                    onClick={() => void load(true)}
                    disabled={refreshing || loading}
                    className="btn-secondary text-xs px-3.5 py-2 rounded-xl flex items-center gap-1.5 disabled:opacity-60"
                >
                    <RefreshCw className={`h-3.5 w-3.5 ${refreshing ? "animate-spin" : ""}`} />
                    {refreshing ? "Refreshing…" : "Refresh"}
                </button>
            </div>

            {/* ── AI badge ───────────────────────────────────── */}
            <div className="flex items-center gap-2 rounded-xl border px-4 py-3"
                style={{ background: "rgba(139,92,246,0.06)", borderColor: "rgba(139,92,246,0.20)" }}>
                <Sparkles className="h-4 w-4 text-violet-500 shrink-0" />
                <p className="text-xs font-medium" style={{ color: "var(--dash-text-secondary)" }}>
                    <span className="font-bold text-violet-600 dark:text-violet-400">AI-powered</span> — Click any disease to let Groq AI organize symptoms and precautions into clear, structured categories.
                </p>
            </div>

            {/* ── Error banner ──────────────────────────────── */}
            {error && (
                <div className="flex items-center gap-2.5 rounded-xl border px-4 py-3 text-sm animate-fade-in-scale"
                    style={{ background: "rgba(220,38,38,0.08)", borderColor: "rgba(220,38,38,0.28)", color: "#dc2626" }}>
                    <AlertCircle className="h-4 w-4 shrink-0" />
                    <span>{error}</span>
                </div>
            )}

            {/* ── Search bar ─────────────────────────────────── */}
            {!loading && merged.length > 0 && (
                <div className="relative">
                    <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 pointer-events-none"
                        style={{ color: "var(--dash-text-muted)" }} />
                    <input
                        type="text"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        placeholder="Search diseases…"
                        className="input-primary pl-10"
                    />
                </div>
            )}

            {/* ── Loading skeletons ──────────────────────────── */}
            {loading && (
                <div className="space-y-3">
                    {Array.from({ length: 4 }).map((_, i) => (
                        <div key={i} className="rounded-[1.125rem] border h-16 animate-pulse"
                            style={{ background: "var(--dash-skeleton-bg)", borderColor: "var(--dash-card-border)", animationDelay: `${i * 60}ms` }} />
                    ))}
                </div>
            )}

            {/* ── Empty state ────────────────────────────────── */}
            {!loading && filtered.length === 0 && !error && (
                <div className="card-panel py-14 px-6 flex flex-col items-center justify-center text-center">
                    <div className="w-14 h-14 rounded-2xl border flex items-center justify-center mb-4"
                        style={{ background: "var(--dash-card-header-bg)", borderColor: "var(--dash-card-border)" }}>
                        <HeartPulse className="h-6 w-6" style={{ color: "var(--dash-text-muted)" }} />
                    </div>
                    <p className="text-sm font-semibold" style={{ color: "var(--dash-text-primary)" }}>
                        {search ? "No diseases match your search" : "No diseases found"}
                    </p>
                    <p className="text-xs mt-1" style={{ color: "var(--dash-text-muted)" }}>
                        {search ? "Try a different keyword." : "Health officers haven't added any diseases yet."}
                    </p>
                </div>
            )}

            {/* ── Diseases with details ─────────────────────── */}
            {!loading && withDetails.length > 0 && (
                <div className="space-y-3">
                    <div className="flex items-center gap-2">
                        <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            With Symptoms &amp; Precautions ({withDetails.length})
                        </p>
                    </div>
                    {withDetails.map((d) => (
                        <DiseaseCard key={d.disease_id} disease={d} defaultOpen={withDetails.length === 1} />
                    ))}
                </div>
            )}

            {/* ── Diseases without details ─────────────────── */}
            {!loading && withoutDetails.length > 0 && (
                <div className="space-y-3">
                    <div className="flex items-center gap-2">
                        <Stethoscope className="h-4 w-4" style={{ color: "var(--dash-text-muted)" }} />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            Pending Details ({withoutDetails.length})
                        </p>
                    </div>
                    {withoutDetails.map((d) => (
                        <DiseaseCard key={d.disease_id} disease={d} />
                    ))}
                </div>
            )}
        </section>
    );
}

"use client";

import { useEffect, useState, useMemo, useCallback } from "react";
import {
    HeartPulse,
    ShieldCheck,
    AlertCircle,
    Search,
    ChevronDown,
    ChevronUp,
    RefreshCw,
    Stethoscope,
    CheckCircle2,
    Sparkles,
    Loader2,
    TriangleAlert,
    Hospital,
    Info,
} from "lucide-react";

/* ── Types ─────────────────────────────────────────────────────────────────── */

type Disease = {
    disease_id: number;
    disease_name: string;
    description: string | null;
};

type DiseaseDetail = {
    disease_id: number;
    symptoms: string[];
    precautions: string[];
    createdAt: string;
    updatedAt: string;
};

type MergedDisease = Disease & { details: DiseaseDetail | null };

type SymptomCategory = { category: string; icon: string; items: string[] };
type PrecautionCategory = { category: string; icon: string; items: string[] };

type EnhancedInfo = {
    disease_name: string;
    severity_level: "low" | "moderate" | "high" | "critical";
    brief_summary: string;
    symptom_categories: SymptomCategory[];
    precaution_categories: PrecautionCategory[];
    when_to_seek_help: string;
};

/* ── Fetch helpers ─────────────────────────────────────────────────────────── */

async function fetchDiseases(): Promise<Disease[]> {
    try {
        const res = await fetch("/api/public/diseases", { cache: "no-store" });
        if (!res.ok) return [];
        const data = await res.json();
        return Array.isArray(data) ? data : (data?.diseases ?? []);
    } catch {
        return [];
    }
}

async function fetchDiseaseDetails(): Promise<DiseaseDetail[]> {
    const res = await fetch("/api/public/disease-details", { cache: "no-store" });
    const data = await res.json();
    if (!res.ok) throw new Error(data?.error || "Failed to fetch disease details");
    return Array.isArray(data) ? data : [];
}

async function enhanceDisease(disease: MergedDisease): Promise<EnhancedInfo | null> {
    try {
        const res = await fetch("/api/groq/enhance-disease", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                disease_name: disease.disease_name,
                symptoms: disease.details?.symptoms ?? [],
                precautions: disease.details?.precautions ?? [],
            }),
        });
        if (!res.ok) return null;
        return await res.json() as EnhancedInfo;
    } catch {
        return null;
    }
}

/* ── Severity config ────────────────────────────────────────────────────────── */

type SeverityLevel = "low" | "moderate" | "high" | "critical";

const severityConfig: Record<SeverityLevel, {
    label: string; bg: string; border: string; text: string; badgeBg: string;
}> = {
    low: {
        label: "Low Risk", bg: "rgba(16,185,129,0.07)", border: "rgba(16,185,129,0.25)",
        text: "#059669", badgeBg: "rgba(16,185,129,0.12)",
    },
    moderate: {
        label: "Moderate Risk", bg: "rgba(245,158,11,0.07)", border: "rgba(245,158,11,0.28)",
        text: "#d97706", badgeBg: "rgba(245,158,11,0.12)",
    },
    high: {
        label: "High Risk", bg: "rgba(239,68,68,0.07)", border: "rgba(239,68,68,0.25)",
        text: "#dc2626", badgeBg: "rgba(239,68,68,0.12)",
    },
    critical: {
        label: "Critical", bg: "rgba(139,0,0,0.07)", border: "rgba(139,0,0,0.30)",
        text: "#991b1b", badgeBg: "rgba(139,0,0,0.12)",
    },
};

/* ── Sub-components ─────────────────────────────────────────────────────────── */

function SeverityBadge({ level }: { level: SeverityLevel }) {
    const cfg = severityConfig[level] ?? severityConfig.low;
    return (
        <span
            className="inline-flex items-center gap-1.5 rounded-full border px-2.5 py-0.5 text-[11px] font-bold capitalize"
            style={{ background: cfg.badgeBg, borderColor: cfg.border, color: cfg.text }}
        >
            <span className="h-1.5 w-1.5 rounded-full shrink-0" style={{ background: cfg.text }} />
            {cfg.label}
        </span>
    );
}

function EnhancedDiseasePanel({ enhanced }: { enhanced: EnhancedInfo }) {
    const sev = severityConfig[enhanced.severity_level] ?? severityConfig.low;

    return (
        <div className="space-y-5">
            {/* Summary banner */}
            {enhanced.brief_summary && (
                <div
                    className="flex items-start gap-3 rounded-xl border px-4 py-3"
                    style={{ background: sev.bg, borderColor: sev.border }}
                >
                    <Info className="h-4 w-4 shrink-0 mt-0.5" style={{ color: sev.text }} />
                    <p className="text-sm leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>
                        {enhanced.brief_summary}
                    </p>
                </div>
            )}

            {/* Symptoms */}
            {enhanced.symptom_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <AlertCircle className="h-4 w-4 text-red-500 shrink-0" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            Symptoms
                        </p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.symptom_categories.map((cat) => (
                            <div
                                key={cat.category}
                                className="rounded-xl border p-3.5"
                                style={{
                                    background: "rgba(239,68,68,0.04)",
                                    borderColor: "rgba(239,68,68,0.18)",
                                }}
                            >
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5" style={{ color: "#dc2626" }}>
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ul className="space-y-1.5">
                                    {cat.items.map((item) => (
                                        <li key={item} className="flex items-start gap-2 text-xs" style={{ color: "var(--dash-text-secondary)" }}>
                                            <span className="mt-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0" />
                                            {item}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Divider */}
            {enhanced.symptom_categories.length > 0 && enhanced.precaution_categories.length > 0 && (
                <div className="border-t" style={{ borderColor: "var(--dash-card-border)" }} />
            )}

            {/* Precautions */}
            {enhanced.precaution_categories.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <ShieldCheck className="h-4 w-4 text-emerald-500 shrink-0" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            Precautions
                        </p>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        {enhanced.precaution_categories.map((cat) => (
                            <div
                                key={cat.category}
                                className="rounded-xl border p-3.5"
                                style={{
                                    background: "rgba(16,185,129,0.04)",
                                    borderColor: "rgba(16,185,129,0.18)",
                                }}
                            >
                                <p className="text-xs font-bold mb-2.5 flex items-center gap-1.5" style={{ color: "#059669" }}>
                                    <span className="text-base leading-none">{cat.icon}</span>
                                    {cat.category}
                                </p>
                                <ol className="space-y-1.5">
                                    {cat.items.map((item, ii) => (
                                        <li key={item} className="flex items-start gap-2 text-xs" style={{ color: "var(--dash-text-secondary)" }}>
                                            <span
                                                className="shrink-0 mt-0.5 inline-flex items-center justify-center h-4 w-4 rounded-full text-[9px] font-bold"
                                                style={{
                                                    background: "rgba(16,185,129,0.15)",
                                                    color: "#059669",
                                                    border: "1px solid rgba(16,185,129,0.30)",
                                                }}
                                            >
                                                {ii + 1}
                                            </span>
                                            {item}
                                        </li>
                                    ))}
                                </ol>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* When to seek help */}
            {enhanced.when_to_seek_help && (
                <div
                    className="flex items-start gap-3 rounded-xl border px-4 py-3.5"
                    style={{
                        background: "rgba(239,68,68,0.05)",
                        borderColor: "rgba(239,68,68,0.20)",
                    }}
                >
                    <Hospital className="h-4 w-4 shrink-0 mt-0.5 text-red-500" />
                    <div>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-red-500 mb-1">
                            When to seek medical help
                        </p>
                        <p className="text-sm leading-relaxed" style={{ color: "var(--dash-text-secondary)" }}>
                            {enhanced.when_to_seek_help}
                        </p>
                    </div>
                </div>
            )}
        </div>
    );
}

/* ── Fallback plain display (if Groq fails) ─────────────────────────────────── */

function PlainDiseasePanel({ details }: { details: DiseaseDetail }) {
    return (
        <div className="space-y-4">
            {details.symptoms.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <AlertCircle className="h-4 w-4 text-red-500" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Symptoms</p>
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {details.symptoms.map((s) => (
                            <span key={s} className="inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-medium"
                                style={{ background: "rgba(239,68,68,0.08)", borderColor: "rgba(239,68,68,0.22)", color: "#dc2626" }}>
                                <span className="mr-1 h-1.5 w-1.5 rounded-full bg-red-400 shrink-0" />{s}
                            </span>
                        ))}
                    </div>
                </div>
            )}
            {details.precautions.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <ShieldCheck className="h-4 w-4 text-emerald-500" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>Precautions</p>
                    </div>
                    <ol className="space-y-2">
                        {details.precautions.map((p, i) => (
                            <li key={p} className="flex items-start gap-2.5 text-sm" style={{ color: "var(--dash-text-secondary)" }}>
                                <span className="shrink-0 mt-0.5 inline-flex items-center justify-center h-5 w-5 rounded-full text-[10px] font-bold"
                                    style={{ background: "rgba(16,185,129,0.12)", color: "#059669", border: "1px solid rgba(16,185,129,0.25)" }}>
                                    {i + 1}
                                </span>
                                {p}
                            </li>
                        ))}
                    </ol>
                </div>
            )}
        </div>
    );
}

/* ── Disease card with Groq enhancement ─────────────────────────────────────── */

function DiseaseCard({ disease, defaultOpen }: { disease: MergedDisease; defaultOpen?: boolean }) {
    const [open, setOpen] = useState(defaultOpen ?? false);
    const [enhanced, setEnhanced] = useState<EnhancedInfo | null>(null);
    const [enhancing, setEnhancing] = useState(false);
    const [enhanceFailed, setEnhanceFailed] = useState(false);

    const hasDetails = disease.details !== null &&
        (disease.details.symptoms.length > 0 || disease.details.precautions.length > 0);

    const handleToggle = useCallback(async () => {
        const nextOpen = !open;
        setOpen(nextOpen);

        // Load enhanced info when first opened and details exist
        if (nextOpen && hasDetails && !enhanced && !enhancing && !enhanceFailed) {
            setEnhancing(true);
            try {
                const result = await enhanceDisease(disease);
                if (result) {
                    setEnhanced(result);
                } else {
                    setEnhanceFailed(true);
                }
            } catch {
                setEnhanceFailed(true);
            } finally {
                setEnhancing(false);
            }
        }
    }, [open, hasDetails, enhanced, enhancing, enhanceFailed, disease]);

    const sev = enhanced?.severity_level
        ? (severityConfig[enhanced.severity_level] ?? severityConfig.low)
        : null;

    return (
        <div className="card-panel animate-fade-in-scale overflow-hidden" style={{ animationDelay: "0ms" }}>
            {/* Header */}
            <button
                type="button"
                onClick={() => void handleToggle()}
                className="w-full card-panel-header flex items-center justify-between gap-3 cursor-pointer"
                aria-expanded={open}
            >
                <div className="flex items-center gap-3 min-w-0">
                    <div
                        className="shrink-0 w-9 h-9 rounded-xl flex items-center justify-center shadow-sm"
                        style={{ background: sev ? sev.bg === severityConfig.critical.bg ? "#991b1b" : sev.text : "var(--color-primary)" }}
                    >
                        <HeartPulse className="h-4 w-4 text-white" />
                    </div>
                    <div className="min-w-0 text-left">
                        <p className="text-sm font-bold truncate" style={{ color: "var(--dash-text-primary)" }}>
                            {disease.disease_name}
                        </p>
                        {disease.description && (
                            <p className="text-xs truncate" style={{ color: "var(--dash-text-muted)" }}>
                                {disease.description}
                            </p>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-2 shrink-0">
                    {enhanced?.severity_level && <SeverityBadge level={enhanced.severity_level} />}
                    {!hasDetails && (
                        <span className="hidden sm:inline text-[10px] font-semibold rounded-full border px-2.5 py-0.5"
                            style={{ background: "var(--dash-card-header-bg)", borderColor: "var(--dash-card-border)", color: "var(--dash-text-muted)" }}>
                            No details yet
                        </span>
                    )}
                    {open
                        ? <ChevronUp className="h-4 w-4" style={{ color: "var(--dash-text-muted)" }} />
                        : <ChevronDown className="h-4 w-4" style={{ color: "var(--dash-text-muted)" }} />}
                </div>
            </button>

            {/* Expanded content */}
            {open && (
                <div className="px-5 pb-5 pt-4">
                    {!hasDetails ? (
                        <div className="flex flex-col items-center py-8 rounded-xl border border-dashed text-center"
                            style={{ background: "var(--dash-card-header-bg)", borderColor: "var(--dash-card-border)", color: "var(--dash-text-muted)" }}>
                            <Stethoscope className="h-6 w-6 mb-2 opacity-50" />
                            <p className="text-sm font-medium">No details added yet</p>
                        </div>
                    ) : enhancing ? (
                        /* Groq loading state */
                        <div className="flex flex-col items-center py-10 gap-3">
                            <div className="flex items-center gap-2.5 rounded-xl border px-5 py-3"
                                style={{ background: "var(--dash-card-bg)", borderColor: "var(--dash-card-border)" }}>
                                <Loader2 className="h-4 w-4 animate-spin" style={{ color: "var(--color-primary)" }} />
                                <span className="text-sm font-medium" style={{ color: "var(--dash-text-secondary)" }}>
                                    Analyzing with AI…
                                </span>
                                <Sparkles className="h-4 w-4 text-violet-500" />
                            </div>
                        </div>
                    ) : enhanced ? (
                        /* Groq-enhanced display */
                        <div>
                            <div className="flex items-center gap-1.5 mb-4 text-[10px] font-semibold uppercase tracking-widest"
                                style={{ color: "var(--dash-text-muted)" }}>
                                <Sparkles className="h-3 w-3 text-violet-500" />
                                AI-organized by Groq · LLaMA 3.3
                            </div>
                            <EnhancedDiseasePanel enhanced={enhanced} />
                        </div>
                    ) : (
                        /* Fallback if Groq failed */
                        <div>
                            {enhanceFailed && (
                                <div className="flex items-center gap-2 mb-3 text-xs rounded-lg border px-3 py-2"
                                    style={{ background: "rgba(245,158,11,0.07)", borderColor: "rgba(245,158,11,0.22)", color: "#d97706" }}>
                                    <TriangleAlert className="h-3.5 w-3.5 shrink-0" />
                                    AI enhancement unavailable — showing raw data
                                </div>
                            )}
                            <PlainDiseasePanel details={disease.details!} />
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

/* ── Main Component ─────────────────────────────────────────────────────────── */

export default function TakeCare() {
    const [diseases, setDiseases] = useState<Disease[]>([]);
    const [details, setDetails] = useState<DiseaseDetail[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [search, setSearch] = useState("");
    const [refreshing, setRefreshing] = useState(false);

    const load = async (isRefresh = false) => {
        if (isRefresh) setRefreshing(true);
        else setLoading(true);
        setError(null);
        try {
            const [diseaseList, detailList] = await Promise.all([
                fetchDiseases(),
                fetchDiseaseDetails(),
            ]);
            setDiseases(diseaseList);
            setDetails(detailList);
        } catch (err) {
            setError(err instanceof Error ? err.message : "Failed to load data");
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    };

    useEffect(() => { void load(); }, []);

    // Build from union of all known IDs — details-driven
    const merged = useMemo<MergedDisease[]>(() => {
        const detailMap = new Map(details.map((d) => [d.disease_id, d]));
        const diseaseMap = new Map(diseases.map((d) => [d.disease_id, d]));
        const allIds = new Set([...details.map((d) => d.disease_id), ...diseases.map((d) => d.disease_id)]);
        return Array.from(allIds).map((id) => {
            const disease = diseaseMap.get(id);
            const detail = detailMap.get(id) ?? null;
            return {
                disease_id: id,
                disease_name: disease?.disease_name ?? `Disease #${id}`,
                description: disease?.description ?? null,
                details: detail,
            };
        }).sort((a, b) => {
            if (a.details && !b.details) return -1;
            if (!a.details && b.details) return 1;
            return a.disease_name.localeCompare(b.disease_name);
        });
    }, [diseases, details]);

    const filtered = useMemo(() => {
        if (!search.trim()) return merged;
        const q = search.toLowerCase();
        return merged.filter((d) =>
            d.disease_name.toLowerCase().includes(q) ||
            (d.description ?? "").toLowerCase().includes(q)
        );
    }, [merged, search]);

    const withDetails = filtered.filter((d) => d.details !== null);
    const withoutDetails = filtered.filter((d) => d.details === null);

    return (
        <section className="space-y-6">
            {/* ── Page heading ────────────────────────────────── */}
            <div className="flex flex-wrap items-start justify-between gap-3 pt-1">
                <div>
                    <div className="flex items-center gap-2.5 mb-1">
                        <div className="w-8 h-8 rounded-xl bg-linear-to-br from-rose-500 to-pink-600 flex items-center justify-center shadow-md shadow-rose-500/25">
                            <HeartPulse className="h-4 w-4 text-white" />
                        </div>
                        <h1 className="text-xl font-bold tracking-tight" style={{ color: "var(--dash-text-primary)" }}>
                            Take Care
                        </h1>
                    </div>
                    <p className="text-sm ml-[2.6rem]" style={{ color: "var(--dash-text-secondary)" }}>
                        AI-organized disease symptoms &amp; precautions — powered by Groq &amp; LLaMA 3.3
                    </p>
                </div>

                <button
                    onClick={() => void load(true)}
                    disabled={refreshing || loading}
                    className="btn-secondary text-xs px-3.5 py-2 rounded-xl flex items-center gap-1.5 disabled:opacity-60"
                >
                    <RefreshCw className={`h-3.5 w-3.5 ${refreshing ? "animate-spin" : ""}`} />
                    {refreshing ? "Refreshing…" : "Refresh"}
                </button>
            </div>

            {/* ── AI badge ───────────────────────────────────── */}
            <div className="flex items-center gap-2 rounded-xl border px-4 py-3"
                style={{ background: "rgba(139,92,246,0.06)", borderColor: "rgba(139,92,246,0.20)" }}>
                <Sparkles className="h-4 w-4 text-violet-500 shrink-0" />
                <p className="text-xs font-medium" style={{ color: "var(--dash-text-secondary)" }}>
                    <span className="font-bold text-violet-600 dark:text-violet-400">AI-powered</span> — Click any disease to let Groq AI organize symptoms and precautions into clear, structured categories.
                </p>
            </div>

            {/* ── Error banner ──────────────────────────────── */}
            {error && (
                <div className="flex items-center gap-2.5 rounded-xl border px-4 py-3 text-sm animate-fade-in-scale"
                    style={{ background: "rgba(220,38,38,0.08)", borderColor: "rgba(220,38,38,0.28)", color: "#dc2626" }}>
                    <AlertCircle className="h-4 w-4 shrink-0" />
                    <span>{error}</span>
                </div>
            )}

            {/* ── Search bar ─────────────────────────────────── */}
            {!loading && merged.length > 0 && (
                <div className="relative">
                    <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 pointer-events-none"
                        style={{ color: "var(--dash-text-muted)" }} />
                    <input
                        type="text"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        placeholder="Search diseases…"
                        className="input-primary pl-10"
                    />
                </div>
            )}

            {/* ── Loading skeletons ──────────────────────────── */}
            {loading && (
                <div className="space-y-3">
                    {Array.from({ length: 4 }).map((_, i) => (
                        <div key={i} className="rounded-[1.125rem] border h-16 animate-pulse"
                            style={{ background: "var(--dash-skeleton-bg)", borderColor: "var(--dash-card-border)", animationDelay: `${i * 60}ms` }} />
                    ))}
                </div>
            )}

            {/* ── Empty state ────────────────────────────────── */}
            {!loading && filtered.length === 0 && !error && (
                <div className="card-panel py-14 px-6 flex flex-col items-center justify-center text-center">
                    <div className="w-14 h-14 rounded-2xl border flex items-center justify-center mb-4"
                        style={{ background: "var(--dash-card-header-bg)", borderColor: "var(--dash-card-border)" }}>
                        <HeartPulse className="h-6 w-6" style={{ color: "var(--dash-text-muted)" }} />
                    </div>
                    <p className="text-sm font-semibold" style={{ color: "var(--dash-text-primary)" }}>
                        {search ? "No diseases match your search" : "No diseases found"}
                    </p>
                    <p className="text-xs mt-1" style={{ color: "var(--dash-text-muted)" }}>
                        {search ? "Try a different keyword." : "Health officers haven't added any diseases yet."}
                    </p>
                </div>
            )}

            {/* ── Diseases with details ─────────────────────── */}
            {!loading && withDetails.length > 0 && (
                <div className="space-y-3">
                    <div className="flex items-center gap-2">
                        <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            With Symptoms &amp; Precautions ({withDetails.length})
                        </p>
                    </div>
                    {withDetails.map((d) => (
                        <DiseaseCard key={d.disease_id} disease={d} defaultOpen={withDetails.length === 1} />
                    ))}
                </div>
            )}

            {/* ── Diseases without details ─────────────────── */}
            {!loading && withoutDetails.length > 0 && (
                <div className="space-y-3">
                    <div className="flex items-center gap-2">
                        <Stethoscope className="h-4 w-4" style={{ color: "var(--dash-text-muted)" }} />
                        <p className="text-xs font-bold uppercase tracking-widest" style={{ color: "var(--dash-text-muted)" }}>
                            Pending Details ({withoutDetails.length})
                        </p>
                    </div>
                    {withoutDetails.map((d) => (
                        <DiseaseCard key={d.disease_id} disease={d} />
                    ))}
                </div>
            )}
        </section>
    );
}

'use client';

import { useEffect, useState } from "react";
import { AlertTriangle, FileText, MapPin, Activity, ShieldAlert, Calendar, Search } from "lucide-react";
import { formatDistanceToNow } from "date-fns";

type Report = {
    report_id: string;
    description: string;
    district_info?: {
        district_name: string;
        province_name: string;
    };
    extracted_data?: {
        disease_name: string;
        cases_reported: number;
        severity: "low" | "medium" | "high" | "critical" | "unknown";
        symptoms: string[];
    };
    created_at: string;
    score: number;
};

export default function OfficerUserReports() {
    const [reports, setReports] = useState<Report[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [searchDistrict, setSearchDistrict] = useState("");
    const [appliedDistrict, setAppliedDistrict] = useState("");

    const fetchReports = async (districtFilter: string) => {
        setLoading(true);
        setError("");
        try {
            const query = new URLSearchParams({ limit: "50" });
            if (districtFilter.trim()) {
                query.append("district", districtFilter.trim());
            }
            const res = await fetch(`/api/user-reports?${query.toString()}`);
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || "Failed to fetch reports");
            setReports(data.reports || []);
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReports(appliedDistrict);
    }, [appliedDistrict]);

    const getSeverityBadge = (severity?: string) => {
        switch (severity?.toLowerCase()) {
            case "critical":
            case "high":
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold bg-zinc-950 text-zinc-50 dark:bg-zinc-50 dark:text-zinc-950">HIGH</span>;
            case "medium":
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold border border-zinc-200 dark:border-zinc-800 text-zinc-800 dark:text-zinc-200 bg-zinc-100 dark:bg-zinc-900">MID</span>;
            case "low":
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold border border-zinc-200 dark:border-zinc-800 text-zinc-500 dark:text-zinc-400 bg-white dark:bg-black">LOW</span>;
            default:
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold border border-dotted border-zinc-300 dark:border-zinc-700 text-zinc-400 dark:text-zinc-500">UNK</span>;
        }
    };

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setAppliedDistrict(searchDistrict);
    };

    return (
        <section className="space-y-6 max-w-7xl mx-auto pb-10">
            <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 pt-2">
                <div>
                    <div className="flex items-center gap-2 mb-1.5">
                        <FileText className="h-5 w-5 text-zinc-950 dark:text-zinc-50" />
                        <h1 className="text-2xl font-bold tracking-tight text-zinc-950 dark:text-zinc-50">
                            User Reports Dashboard
                        </h1>
                    </div>
                    <p className="text-sm text-zinc-500 dark:text-zinc-400">
                        View submitted disease reports from civilians across all regions.
                    </p>
                </div>

                <form onSubmit={handleSearch} className="flex items-center w-full sm:w-auto relative group">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-zinc-400" />
                    <input 
                        type="text" 
                        value={searchDistrict}
                        onChange={(e) => setSearchDistrict(e.target.value)}
                        placeholder="Filter by district..."
                        className="pl-9 pr-4 py-2 w-full sm:w-64 bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 rounded-md text-sm placeholder:text-zinc-400 focus:outline-none focus:ring-2 focus:ring-zinc-950 dark:focus:ring-zinc-300 transition-all"
                    />
                    <button type="submit" className="sr-only">Search</button>
                </form>
            </div>

            {error && (
                <div className="flex items-center gap-2 rounded-md border border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900 px-4 py-3 text-sm text-zinc-950 dark:text-zinc-50">
                    <AlertTriangle className="h-4 w-4 shrink-0" />
                    <span className="font-medium">{error}</span>
                </div>
            )}

            <div className="rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-black overflow-hidden shadow-sm">
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse min-w-[700px]">
                        <thead>
                            <tr className="border-b border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900/50">
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider">Report Details</th>
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider">Analysis</th>
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider">Location</th>
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider text-right">Age</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-zinc-200 dark:divide-zinc-800">
                            {loading ? (
                                Array.from({ length: 6 }).map((_, i) => (
                                    <tr key={i} className="animate-pulse">
                                        <td className="px-5 py-4"><div className="h-4 w-48 bg-zinc-200 dark:bg-zinc-800 rounded mb-2" /><div className="h-3 w-24 bg-zinc-100 dark:bg-zinc-900 rounded" /></td>
                                        <td className="px-5 py-4"><div className="h-5 w-24 bg-zinc-200 dark:bg-zinc-800 rounded-sm" /></td>
                                        <td className="px-5 py-4"><div className="h-4 w-28 bg-zinc-200 dark:bg-zinc-800 rounded" /></td>
                                        <td className="px-5 py-4 flex justify-end"><div className="h-4 w-16 bg-zinc-200 dark:bg-zinc-800 rounded" /></td>
                                    </tr>
                                ))
                            ) : reports.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-5 py-12 text-center text-zinc-500 dark:text-zinc-400">
                                        <ShieldAlert className="h-8 w-8 mx-auto mb-3 text-zinc-300 dark:text-zinc-700" />
                                        <p className="text-sm font-medium">No reports found.</p>
                                        {appliedDistrict && <p className="text-xs mt-1">Try clearing the district filter.</p>}
                                    </td>
                                </tr>
                            ) : (
                                reports.map((r) => (
                                    <tr key={r.report_id} className="group hover:bg-zinc-50 dark:hover:bg-zinc-900/50 transition-colors">
                                        <td className="px-5 py-4 align-top">
                                            <div className="flex flex-col min-w-0 pr-4">
                                                <p className="text-sm font-medium text-zinc-950 dark:text-zinc-50">
                                                    {r.description || "No description provided"}
                                                </p>
                                                <p className="text-xs text-zinc-500 dark:text-zinc-400 mt-1.5 font-mono">
                                                    ID: {r.report_id.slice(-8)} &bull; Score: {r.score}
                                                </p>
                                            </div>
                                        </td>
                                        <td className="px-5 py-4 align-top">
                                            <div className="flex flex-col items-start gap-1.5">
                                                {getSeverityBadge(r.extracted_data?.severity)}
                                                <span className="text-sm font-medium text-zinc-950 dark:text-zinc-50">
                                                    {r.extracted_data?.disease_name || "Unverified"}
                                                </span>
                                            </div>
                                        </td>
                                        <td className="px-5 py-4 align-top">
                                            {r.district_info ? (
                                                <div className="flex flex-col gap-0.5">
                                                    <span className="text-sm font-medium text-zinc-950 dark:text-zinc-50 flex items-center gap-1.5">
                                                        <MapPin className="h-3.5 w-3.5 text-zinc-400" />
                                                        {r.district_info.district_name}
                                                    </span>
                                                    <span className="text-xs text-zinc-500 dark:text-zinc-400 ml-5">
                                                        {r.district_info.province_name}
                                                    </span>
                                                </div>
                                            ) : (
                                                <span className="text-sm text-zinc-500 italic">Unknown Location</span>
                                            )}
                                        </td>
                                        <td className="px-5 py-4 align-top text-right">
                                            <div className="flex items-center justify-end gap-1.5 text-xs text-zinc-500 dark:text-zinc-400">
                                                <Calendar className="h-3.5 w-3.5" />
                                                {r.created_at ? formatDistanceToNow(new Date(r.created_at), { addSuffix: true }) : "Unknown"}
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </section>
    );
}

'use client';

import { useEffect, useState } from "react";
import { AlertTriangle, FileText, MapPin, ShieldAlert, Calendar, Search } from "lucide-react";
import { formatDistanceToNow } from "date-fns";

type Report = {
    report_id: string;
    description: string;
    district_info?: {
        district_name: string;
        province_name: string;
    };
    extracted_data?: {
        disease_name: string;
        cases_reported: number;
        severity: "low" | "medium" | "high" | "critical" | "unknown";
        symptoms: string[];
    };
    created_at: string;
    score: number;
};

export default function OfficerUserReports() {
    const [reports, setReports] = useState<Report[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [searchDistrict, setSearchDistrict] = useState("");
    const [appliedDistrict, setAppliedDistrict] = useState("");

    const fetchReports = async (districtFilter: string) => {
        setLoading(true);
        setError("");
        try {
            const query = new URLSearchParams({ limit: "50" });
            if (districtFilter.trim()) {
                query.append("district", districtFilter.trim());
            }
            const res = await fetch(`/api/user-reports?${query.toString()}`);
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || "Failed to fetch reports");
            setReports(data.reports || []);
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : "Failed to fetch reports");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReports(appliedDistrict);
    }, [appliedDistrict]);

    const getSeverityBadge = (severity?: string) => {
        switch (severity?.toLowerCase()) {
            case "critical":
            case "high":
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold bg-zinc-950 text-zinc-50 dark:bg-zinc-50 dark:text-zinc-950">HIGH</span>;
            case "medium":
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold border border-zinc-200 dark:border-zinc-800 text-zinc-800 dark:text-zinc-200 bg-zinc-100 dark:bg-zinc-900">MID</span>;
            case "low":
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold border border-zinc-200 dark:border-zinc-800 text-zinc-500 dark:text-zinc-400 bg-white dark:bg-black">LOW</span>;
            default:
                return <span className="inline-flex items-center gap-1 rounded-sm px-2 py-0.5 text-[10px] font-bold border border-dotted border-zinc-300 dark:border-zinc-700 text-zinc-400 dark:text-zinc-500">UNK</span>;
        }
    };

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setAppliedDistrict(searchDistrict);
    };

    return (
        <section className="space-y-6 max-w-7xl mx-auto pb-10">
            <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 pt-2">
                <div>
                    <div className="flex items-center gap-2 mb-1.5">
                        <FileText className="h-5 w-5 text-zinc-950 dark:text-zinc-50" />
                        <h1 className="text-2xl font-bold tracking-tight text-zinc-950 dark:text-zinc-50">
                            User Reports Dashboard
                        </h1>
                    </div>
                    <p className="text-sm text-zinc-500 dark:text-zinc-400">
                        View submitted disease reports from civilians across all regions.
                    </p>
                </div>

                <form onSubmit={handleSearch} className="flex items-center w-full sm:w-auto relative group">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-zinc-400" />
                    <input 
                        type="text" 
                        value={searchDistrict}
                        onChange={(e) => setSearchDistrict(e.target.value)}
                        placeholder="Filter by district..."
                        className="pl-9 pr-4 py-2 w-full sm:w-64 bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 rounded-md text-sm placeholder:text-zinc-400 focus:outline-none focus:ring-2 focus:ring-zinc-950 dark:focus:ring-zinc-300 transition-all"
                    />
                    <button type="submit" className="sr-only">Search</button>
                </form>
            </div>

            {error && (
                <div className="flex items-center gap-2 rounded-md border border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900 px-4 py-3 text-sm text-zinc-950 dark:text-zinc-50">
                    <AlertTriangle className="h-4 w-4 shrink-0" />
                    <span className="font-medium">{error}</span>
                </div>
            )}

            <div className="rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-black overflow-hidden shadow-sm">
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse min-w-[700px]">
                        <thead>
                            <tr className="border-b border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900/50">
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider">Report Details</th>
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider">Analysis</th>
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider">Location</th>
                                <th className="px-5 py-3 text-xs font-semibold text-zinc-500 dark:text-zinc-400 uppercase tracking-wider text-right">Age</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-zinc-200 dark:divide-zinc-800">
                            {loading ? (
                                Array.from({ length: 6 }).map((_, i) => (
                                    <tr key={i} className="animate-pulse">
                                        <td className="px-5 py-4"><div className="h-4 w-48 bg-zinc-200 dark:bg-zinc-800 rounded mb-2" /><div className="h-3 w-24 bg-zinc-100 dark:bg-zinc-900 rounded" /></td>
                                        <td className="px-5 py-4"><div className="h-5 w-24 bg-zinc-200 dark:bg-zinc-800 rounded-sm" /></td>
                                        <td className="px-5 py-4"><div className="h-4 w-28 bg-zinc-200 dark:bg-zinc-800 rounded" /></td>
                                        <td className="px-5 py-4 flex justify-end"><div className="h-4 w-16 bg-zinc-200 dark:bg-zinc-800 rounded" /></td>
                                    </tr>
                                ))
                            ) : reports.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-5 py-12 text-center text-zinc-500 dark:text-zinc-400">
                                        <ShieldAlert className="h-8 w-8 mx-auto mb-3 text-zinc-300 dark:text-zinc-700" />
                                        <p className="text-sm font-medium">No reports found.</p>
                                        {appliedDistrict && <p className="text-xs mt-1">Try clearing the district filter.</p>}
                                    </td>
                                </tr>
                            ) : (
                                reports.map((r) => (
                                    <tr key={r.report_id} className="group hover:bg-zinc-50 dark:hover:bg-zinc-900/50 transition-colors">
                                        <td className="px-5 py-4 align-top">
                                            <div className="flex flex-col min-w-0 pr-4">
                                                <p className="text-sm font-medium text-zinc-950 dark:text-zinc-50">
                                                    {r.description || "No description provided"}
                                                </p>
                                                <p className="text-xs text-zinc-500 dark:text-zinc-400 mt-1.5 font-mono">
                                                    ID: {r.report_id.slice(-8)} &bull; Score: {r.score}
                                                </p>
                                            </div>
                                        </td>
                                        <td className="px-5 py-4 align-top">
                                            <div className="flex flex-col items-start gap-1.5">
                                                {getSeverityBadge(r.extracted_data?.severity)}
                                                <span className="text-sm font-medium text-zinc-950 dark:text-zinc-50">
                                                    {r.extracted_data?.disease_name || "Unverified"}
                                                </span>
                                            </div>
                                        </td>
                                        <td className="px-5 py-4 align-top">
                                            {r.district_info ? (
                                                <div className="flex flex-col gap-0.5">
                                                    <span className="text-sm font-medium text-zinc-950 dark:text-zinc-50 flex items-center gap-1.5">
                                                        <MapPin className="h-3.5 w-3.5 text-zinc-400" />
                                                        {r.district_info.district_name}
                                                    </span>
                                                    <span className="text-xs text-zinc-500 dark:text-zinc-400 ml-5">
                                                        {r.district_info.province_name}
                                                    </span>
                                                </div>
                                            ) : (
                                                <span className="text-sm text-zinc-500 italic">Unknown Location</span>
                                            )}
                                        </td>
                                        <td className="px-5 py-4 align-top text-right">
                                            <div className="flex items-center justify-end gap-1.5 text-xs text-zinc-500 dark:text-zinc-400">
                                                <Calendar className="h-3.5 w-3.5" />
                                                {r.created_at ? formatDistanceToNow(new Date(r.created_at), { addSuffix: true }) : "Unknown"}
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </section>
    );
}

"use client";

import { useEffect, useRef } from "react";
import HeroSection from "@/components/homepage-components/HeroSection";
import StatSection from "@/components/homepage-components/StatSection";
import AboutSection from "@/components/homepage-components/AboutSection";
import FeaturesSection from "@/components/homepage-components/FeaturesSection";
import CtaSection from "@/components/homepage-components/CtaSection";
import Footer from "@/components/Footer";
import dynamic from "next/dynamic";
import { getGsap } from "@/lib/gsap";

// Dynamically import Three.js component with no SSR
const ThreeBackground = dynamic(
  () => import("@/components/homepage-components/ThreeBackground"),
  { ssr: false }
);


export default function HomePage() {
  const pageRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    const { gsap } = getGsap();
    const root = pageRef.current;

    if (!root) {
      return;
    }

    const ctx = gsap.context(() => {
      const sections = gsap.utils.toArray<HTMLElement>("[data-home-scroll-section]");

      sections.forEach((section) => {
        gsap.fromTo(
          section,
          { opacity: 0, y: 56, scale: 0.98 },
          {
            opacity: 1,
            y: 0,
            scale: 1,
            duration: 0.9,
            ease: "power3.out",
            scrollTrigger: {
              trigger: section,
              start: "top 82%",
              end: "top 40%",
              toggleActions: "play none none reverse",
            },
          }
        );
      });

      gsap.to("[data-home-glow='left']", {
        y: 48,
        x: 18,
        scale: 1.08,
        ease: "none",
        scrollTrigger: {
          trigger: root,
          start: "top top",
          end: "bottom bottom",
          scrub: true,
        },
      });

      gsap.to("[data-home-glow='right']", {
        y: -36,
        x: -16,
        scale: 1.06,
        ease: "none",
        scrollTrigger: {
          trigger: root,
          start: "top top",
          end: "bottom bottom",
          scrub: true,
        },
      });
    }, root);

    return () => ctx.revert();
  }, []);

  return (
    <main ref={pageRef} className="min-h-screen bg-white">
      {/* Fixed background with hero gradient */}
      <div className="fixed inset-0 bg-gradient-to-br from-[#1E3A8A] via-[#1e40af] to-[#0EA5A4] overflow-hidden">
        {/* Three.js animated background */}
        <ThreeBackground />

        {/* Decorative background elements */}
        <div className="absolute inset-0 opacity-10">
          <div data-home-glow="left" className="absolute top-10 left-10 w-72 h-72 bg-white rounded-full blur-3xl"></div>
          <div data-home-glow="right" className="absolute bottom-10 right-10 w-96 h-96 bg-white rounded-full blur-3xl"></div>
        </div>
      </div>

      {/* Scrollable content */}
      <div className="relative z-10">
        <HeroSection />

        {/* Floating sections container */}
        <div className="relative">
          <div data-home-scroll-section>
            <StatSection />
          </div>
          <div data-home-scroll-section>
            <AboutSection />
          </div>
          <div data-home-scroll-section>
            <FeaturesSection />
          </div>
          <div data-home-scroll-section>
            <CtaSection />
          </div>
        </div>
      </div>
    </main>
  );
}

